export enum TargetLanguage {
  ENGLISH = 'English',
  DUTCH = 'Dutch',
  ARABIC = 'Arabic',
  RUSSIAN = 'Russian'
}

export interface ChatMessage {
  id: string;
  role: 'user' | 'model';
  text: string;
  timestamp: Date;
  isFinal: boolean;
}

export interface AudioConfig {
  inputSampleRate: number;
