export enum TargetLanguage {
  ENGLISH = 'English',
  DUTCH = 'Dutch',
  ARABIC = 'Arabic',
  RUSSIAN = 'Russian'
}

export interface ChatMessage {
  id: string;
  role: 'user' | 'model';
  text: string;
  timestamp: Date;
  isFinal: boolean;
}

export interface AudioConfig {
  inputSampleRate: number;
  outputSampleRate: number;
}

export interface OfflinePack {
  id: string;
  pair: string; // e.g., "TR-EN"
  name: string;
  size: string;
  downloaded: boolean;
  progress: number; // 0-100
}

const CACHE_NAME = 'linguaflow-v1';
const ASSETS_TO_CACHE = [
  '/',
  '/index.html',
  // Note: specific JS bundles generated by the build system would technically go here.
  // For this dev environment, we cache the root.
];

self.addEventListener('install', (event) => {
  event.waitUntil(
    caches.open(CACHE_NAME).then((cache) => {
      return cache.addAll(ASSETS_TO_CACHE);
    })
  );
});

self.addEventListener('fetch', (event) => {
  event.respondWith(
    caches.match(event.request).then((response) => {
      // Cache hit - return response
      if (response) {
        return response;
      }
      return fetch(event.request).catch(() => {
        // Fallback for offline if not cached (optional handling)
        return new Response("Offline"); 
      });
    })
  );
});

self.addEventListener('activate', (event) => {
  event.waitUntil(
    caches.keys().then((cacheNames) => {
      return Promise.all(
        cacheNames.map((cacheName) => {
          if (cacheName !== CACHE_NAME) {
            return caches.delete(cacheName);
          }
        })
      );
    })
  );
});

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';
import { TargetLanguage, ChatMessage, OfflinePack } from './types';
import { float32To16BitPCM, arrayBufferToBase64, base64ToArrayBuffer, pcm16ToFloat32 } from './utils/audioUtils';
import AudioVisualizer from './components/AudioVisualizer';
import { Mic, MicOff, Globe, Settings, Volume2, RotateCcw, Wifi, WifiOff, Download, Check, Trash2, X } from 'lucide-react';

// Live API Configuration
const MODEL_NAME = 'gemini-2.5-flash-native-audio-preview-09-2025';
const INPUT_SAMPLE_RATE = 16000;
const OUTPUT_SAMPLE_RATE = 24000;

// Mock Offline Packs
const INITIAL_PACKS: OfflinePack[] = [
  { id: 'tr-en', pair: 'TR ↔ EN', name: 'English Pack', size: '45 MB', downloaded: false, progress: 0 },
  { id: 'tr-nl', pair: 'TR ↔ NL', name: 'Dutch Pack', size: '42 MB', downloaded: false, progress: 0 },
  { id: 'tr-ar', pair: 'TR ↔ AR', name: 'Arabic Pack', size: '50 MB', downloaded: false, progress: 0 },
  { id: 'tr-ru', pair: 'TR ↔ RU', name: 'Russian Pack', size: '48 MB', downloaded: false, progress: 0 },
];

const App: React.FC = () => {
  const [targetLang, setTargetLang] = useState<TargetLanguage>(TargetLanguage.ENGLISH);
  const [isConnected, setIsConnected] = useState(false);
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [error, setError] = useState<string | null>(null);

  // Offline / Network State
  const [isOnline, setIsOnline] = useState(navigator.onLine);
  const [forceOfflineMode, setForceOfflineMode] = useState(false);
  const [showSettings, setShowSettings] = useState(false);
  const [offlinePacks, setOfflinePacks] = useState<OfflinePack[]>(INITIAL_PACKS);

  // Audio Context Refs
  const inputAudioContextRef = useRef<AudioContext | null>(null);
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const inputAnalyserRef = useRef<AnalyserNode | null>(null);
  const outputAnalyserRef = useRef<AnalyserNode | null>(null);
  const mediaStreamRef = useRef<MediaStream | null>(null);

  // Logic Refs
  const aiClientRef = useRef<GoogleGenAI | null>(null);
  const sessionPromiseRef = useRef<Promise<any> | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());

  // Transcription Buffers
  const currentInputTranscription = useRef('');
  const currentOutputTranscription = useRef('');

  // Offline Recognition Ref
  const recognitionRef = useRef<any>(null);

  // 1. Initialize Gemini Client & Network Listeners
  useEffect(() => {
    if (process.env.API_KEY) {
      aiClientRef.current = new GoogleGenAI({ apiKey: process.env.API_KEY });
    } else {
      setError("API Key not found in environment variables.");
    }

    // Network Listeners
    const handleOnline = () => setIsOnline(true);
    const handleOffline = () => {
      setIsOnline(false);
      stopConnection(); // Stop Gemini if network drops
    };

    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);

    // Load packs from localStorage (Simulation)
    const savedPacks = localStorage.getItem('offlinePacks');
    if (savedPacks) {
      setOfflinePacks(JSON.parse(savedPacks));
    }

    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
    };
  }, []);

  const isOfflineActive = !isOnline || forceOfflineMode;

  // 2. Audio Processing Helper: Resample and Send (Online Only)
  const processAudioInput = useCallback((inputData: Float32Array) => {
    if (!sessionPromiseRef.current) return;
    const pcmData = float32To16BitPCM(inputData);
    const base64Data = arrayBufferToBase64(pcmData);

    sessionPromiseRef.current.then((session) => {
      session.sendRealtimeInput({
        media: {
          mimeType: `audio/pcm;rate=${INPUT_SAMPLE_RATE}`,
          data: base64Data,
        },
      });
    });
  }, []);

  // 3. Connect to Live API (Online)
  const connectToLiveAPI = async () => {
    if (isOfflineActive) {
      startOfflineRecognition();
      return;
    }

    if (!aiClientRef.current) return;
    setError(null);

    try {
      // Setup Audio Input
      const stream = await navigator.mediaDevices.getUserMedia({ audio: {
        sampleRate: INPUT_SAMPLE_RATE,
        channelCount: 1,
        echoCancellation: true,
        noiseSuppression: true,
        autoGainControl: true
      }});
      mediaStreamRef.current = stream;

      const audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ 
        sampleRate: INPUT_SAMPLE_RATE 
      });
      inputAudioContextRef.current = audioCtx;

      const source = audioCtx.createMediaStreamSource(stream);
      const analyser = audioCtx.createAnalyser();
      analyser.fftSize = 256;
      inputAnalyserRef.current = analyser;

      const scriptProcessor = audioCtx.createScriptProcessor(4096, 1, 1);

      scriptProcessor.onaudioprocess = (e) => {
        const inputData = e.inputBuffer.getChannelData(0);
        processAudioInput(inputData);
      };

      source.connect(analyser);
      analyser.connect(scriptProcessor);
      scriptProcessor.connect(audioCtx.destination);

      // Setup Audio Output
      const outCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ 
        sampleRate: OUTPUT_SAMPLE_RATE 
      });
      outputAudioContextRef.current = outCtx;
      const outAnalyser = outCtx.createAnalyser();
      outAnalyser.fftSize = 256;
      outputAnalyserRef.current = outAnalyser;
      outAnalyser.connect(outCtx.destination);

      const systemPrompt = `You are a world-class simultaneous interpreter. 
      Your task is to translate spoken Turkish into ${targetLang} immediately.
      Simply output the translated audio in ${targetLang}.
      Also provide the text transcriptions for both input and output.`;

      sessionPromiseRef.current = aiClientRef.current.live.connect({
        model: MODEL_NAME,
        config: {
          systemInstruction: systemPrompt,
          responseModalities: [Modality.AUDIO],
          inputAudioTranscription: { model: "gemini-2.5-flash" },
          outputAudioTranscription: { model: "gemini-2.5-flash" },
        },
        callbacks: {
          onopen: () => {
            console.log("Gemini Live Session Opened");
            setIsConnected(true);
            nextStartTimeRef.current = 0;
          },
          onmessage: async (msg: LiveServerMessage) => {
            if (msg.serverContent?.inputTranscription) {
               currentInputTranscription.current += msg.serverContent.inputTranscription.text;
            }
            if (msg.serverContent?.outputTranscription) {
               currentOutputTranscription.current += msg.serverContent.outputTranscription.text;
            }
            if (msg.serverContent?.turnComplete) {
               const inputTx = currentInputTranscription.current.trim();
               const outputTx = currentOutputTranscription.current.trim();
               if (inputTx || outputTx) {
                 addMessage('user', inputTx || '(Silence)');
                 addMessage('model', outputTx || '...');
               }
               currentInputTranscription.current = '';
               currentOutputTranscription.current = '';
            }
            const audioData = msg.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
            if (audioData) {
               playAudioResponse(audioData);
            }
          },
          onclose: () => {
            console.log("Session Closed");
            stopConnection();
          },
          onerror: (err) => {
            console.error("Session Error", err);
            setError("Connection disrupted. Please retry.");
            stopConnection();
          }
        }
      });
    } catch (e: any) {
      console.error(e);
      setError(`Failed to initialize: ${e.message}`);
      stopConnection();
    }
  };

  // 4. Offline Logic (Web Speech API)
  const startOfflineRecognition = () => {
    // Check if browser supports Web Speech API
    if (!('webkitSpeechRecognition' in window)) {
      setError("Offline speech recognition is not supported in this browser.");
      return;
    }

    // Check if the pack is "downloaded"
    const currentPack = offlinePacks.find(p => p.name.includes(targetLang));
    if (!currentPack?.downloaded) {
      // Allow it anyway for demo purposes, but warn user
      // setError(`Please download the ${targetLang} pack for offline use.`);
      // return;
    }

    try {
      // @ts-ignore
      const Recognition = window.webkitSpeechRecognition;
      const recognition = new Recognition();
      recognition.lang = 'tr-TR'; // Input is Turkish
      recognition.continuous = true;
      recognition.interimResults = false;

      recognition.onstart = () => {
        setIsConnected(true);
      };

      recognition.onresult = (event: any) => {
        const transcript = event.results[event.results.length - 1][0].transcript;
        addMessage('user', transcript);

        // Simulate Offline Translation (Naive Mock)
        // In a real app, you would use a WASM model like transformers.js here
        const translationMock = `(Offline ${targetLang}) ${transcript}`; 

        setTimeout(() => {
          addMessage('model', translationMock);
          speakOffline(transcript, targetLang); // Speak the result
        }, 500);
      };

      recognition.onerror = (event: any) => {
        console.error("Offline Speech Error", event.error);
        if (event.error === 'not-allowed') {
          setError("Microphone access denied.");
        }
        stopConnection();
      };

      recognition.onend = () => {
        // Auto-restart if still connected
        if (isConnected) {
            // recognition.start(); 
            // Note: Preventing infinite loops in this demo, usually you'd check a flag
            setIsConnected(false); 
        }
      };

      recognitionRef.current = recognition;
      recognition.start();

    } catch (e) {
      console.error(e);
      setIsConnected(false);
    }
  };

  const speakOffline = (text: string, lang: TargetLanguage) => {
    if ('speechSynthesis' in window) {
      const utterance = new SpeechSynthesisUtterance(text); // In reality, translate first
      // Map TargetLanguage to BCP-47 tags
      const langMap: Record<TargetLanguage, string> = {
        [TargetLanguage.ENGLISH]: 'en-US',
        [TargetLanguage.DUTCH]: 'nl-NL',
        [TargetLanguage.ARABIC]: 'ar-SA',
        [TargetLanguage.RUSSIAN]: 'ru-RU'
      };
      utterance.lang = langMap[lang];
      window.speechSynthesis.speak(utterance);
    }
  };


  // 5. Play Output Audio (Online)
  const playAudioResponse = async (base64Audio: string) => {
    if (!outputAudioContextRef.current || !outputAnalyserRef.current) return;
    const ctx = outputAudioContextRef.current;
    try {
      const arrayBuffer = base64ToArrayBuffer(base64Audio);
      const float32Data = pcm16ToFloat32(arrayBuffer);
      const audioBuffer = ctx.createBuffer(1, float32Data.length, OUTPUT_SAMPLE_RATE);
      audioBuffer.getChannelData(0).set(float32Data);
      const source = ctx.createBufferSource();
      source.buffer = audioBuffer;
      source.connect(outputAnalyserRef.current);
      const currentTime = ctx.currentTime;
      const startTime = Math.max(nextStartTimeRef.current, currentTime);
      source.start(startTime);
      nextStartTimeRef.current = startTime + audioBuffer.duration;
      source.onended = () => sourcesRef.current.delete(source);
      sourcesRef.current.add(source);
    } catch (err) {
      console.error("Audio playback error", err);
    }
  };

  // 6. Helpers & Cleanup
  const addMessage = (role: 'user' | 'model', text: string) => {
    setMessages(prev => [...prev, { 
      id: Date.now().toString() + Math.random(), 
      role, 
      text, 
      timestamp: new Date(), 
      isFinal: true 
    }]);
  };

  const stopConnection = useCallback(() => {
    setIsConnected(false);

    // Stop Live API
    if (mediaStreamRef.current) {
      mediaStreamRef.current.getTracks().forEach(track => track.stop());
      mediaStreamRef.current = null;
    }
    if (inputAudioContextRef.current) {
      inputAudioContextRef.current.close();
      inputAudioContextRef.current = null;
    }
    if (outputAudioContextRef.current) {
      outputAudioContextRef.current.close();
      outputAudioContextRef.current = null;
    }
    sessionPromiseRef.current = null;

    // Stop Offline API
    if (recognitionRef.current) {
      recognitionRef.current.stop();
      recognitionRef.current = null;
    }
  }, []);

  const chatContainerRef = useRef<HTMLDivElement>(null);
  useEffect(() => {
    if (chatContainerRef.current) {
      chatContainerRef.current.scrollTop = chatContainerRef.current.scrollHeight;
    }
  }, [messages]);

  // Settings: Download Simulation
  const downloadPack = (id: string) => {
    setOfflinePacks(prev => prev.map(p => p.id === id ? { ...p, progress: 5 } : p));

    let progress = 5;
    const interval = setInterval(() => {
      progress += Math.floor(Math.random() * 15);
      if (progress >= 100) {
        progress = 100;
        clearInterval(interval);
        setOfflinePacks(prev => {
          const newPacks = prev.map(p => p.id === id ? { ...p, progress: 100, downloaded: true } : p);
          localStorage.setItem('offlinePacks', JSON.stringify(newPacks));
          return newPacks;
        });
      } else {
        setOfflinePacks(prev => prev.map(p => p.id === id ? { ...p, progress } : p));
      }
    }, 300);
  };

  const deletePack = (id: string) => {
     setOfflinePacks(prev => {
       const newPacks = prev.map(p => p.id === id ? { ...p, progress: 0, downloaded: false } : p);
       localStorage.setItem('offlinePacks', JSON.stringify(newPacks));
       return newPacks;
     });
  };

  return (
    <div className="min-h-screen bg-slate-900 text-slate-100 flex flex-col font-sans relative overflow-hidden">

      {/* Background Gradients */}
      <div className="absolute top-0 left-0 w-full h-full overflow-hidden z-0 pointer-events-none">
        <div className={`absolute top-[-10%] left-[-10%] w-[500px] h-[500px] rounded-full blur-[100px] animate-pulse ${isOfflineActive ? 'bg-orange-600/20' : 'bg-blue-600/20'}`}></div>
        <div className={`absolute bottom-[-10%] right-[-10%] w-[500px] h-[500px] rounded-full blur-[100px] animate-pulse ${isOfflineActive ? 'bg-red-600/20' : 'bg-purple-600/20'}`} style={{ animationDelay: '2s' }}></div>
      </div>

      {/* Header */}
      <header className="z-10 p-4 border-b border-slate-700/50 glass-panel flex justify-between items-center sticky top-0">
        <div className="flex items-center gap-2">
          <div className={`w-8 h-8 rounded-lg flex items-center justify-center bg-gradient-to-br ${isOfflineActive ? 'from-orange-500 to-red-600' : 'from-cyan-400 to-blue-600'}`}>
            <Globe size={18} className="text-white" />
          </div>
          <h1 className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-slate-100 to-slate-300">
            LinguaFlow {isOfflineActive ? 'Offline' : 'Live'}
          </h1>
        </div>
        <div className="flex items-center gap-3">
          <button 
             onClick={() => setShowSettings(true)}
             className="p-2 rounded-full hover:bg-slate-800 transition-colors"
          >
            <Settings size={20} className="text-slate-400" />
          </button>
          <div className={`flex items-center gap-2 px-3 py-1 rounded-full border ${isOfflineActive ? 'border-orange-500/30 bg-orange-500/10' : 'border-blue-500/30 bg-blue-500/10'}`}>
             {isOfflineActive ? <WifiOff size={14} className="text-orange-400"/> : <Wifi size={14} className="text-blue-400"/>}
             <span className={`text-xs font-bold ${isOfflineActive ? 'text-orange-400' : 'text-blue-400'}`}>
                {isOfflineActive ? 'OFFLINE' : 'ONLINE'}
             </span>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 flex flex-col max-w-3xl w-full mx-auto p-4 z-10 relative h-[calc(100vh-80px)]">

        {/* Error Banner */}
        {error && (
          <div className="bg-red-500/10 border border-red-500/50 text-red-200 p-3 rounded-lg mb-4 text-sm flex justify-between items-center animate-fade-in">
            <span>{error}</span>
            <button onClick={() => setError(null)} className="text-white hover:text-red-200">&times;</button>
          </div>
        )}

        {/* Chat Area */}
        <div ref={chatContainerRef} className="flex-1 overflow-y-auto space-y-4 mb-4 pr-2 pb-20">
          {messages.length === 0 && (
            <div className="h-full flex flex-col items-center justify-center text-slate-500 opacity-60">
              {isOfflineActive ? <WifiOff size={48} className="mb-4 text-orange-600/50" /> : <Volume2 size={48} className="mb-4 text-blue-600/50" />}
              <p className="text-center font-medium">
                {isOfflineActive ? 'Offline Mode Active' : 'Real-time Live Translation'}
              </p>
              <p className="text-sm mt-2 max-w-xs text-center">
                {isOfflineActive 
                  ? 'Using on-device speech recognition. Accuracy may vary.' 
                  : 'Select a language and press start to begin simultaneous translation.'}
              </p>
            </div>
          )}

          {messages.map((msg) => (
            <div key={msg.id} className={`flex ${msg.role === 'user' ? 'justify-start' : 'justify-end'}`}>
              <div className={`max-w-[80%] rounded-2xl p-4 shadow-lg ${
                msg.role === 'user' 
                  ? 'bg-slate-800 border border-slate-700 text-slate-200 rounded-bl-none' 
                  : isOfflineActive 
                    ? 'bg-gradient-to-br from-orange-700 to-red-800 text-white rounded-br-none border border-orange-500/20'
                    : 'bg-gradient-to-br from-blue-600 to-cyan-600 text-white rounded-br-none'
              }`}>
                <div className="text-xs opacity-50 mb-1 font-semibold tracking-wider flex justify-between items-center">
                  <span>{msg.role === 'user' ? 'TURKISH (You)' : targetLang.toUpperCase()}</span>
                  {isOfflineActive && msg.role === 'model' && <WifiOff size={10} />}
                </div>
                <p className="text-lg leading-relaxed">{msg.text}</p>
              </div>
            </div>
          ))}

          {/* Realtime Transcripts */}
          {(currentInputTranscription.current || currentOutputTranscription.current) && isConnected && !isOfflineActive && (
             <div className="flex justify-center my-2">
               <span className="text-xs text-slate-400 animate-pulse">Processing...</span>
             </div>
          )}
        </div>

        {/* Control Deck */}
        <div className="glass-panel rounded-3xl p-4 shadow-2xl border border-white/5">

          {/* Visualizers (Only for Online, simplistic for Offline) */}
          <div className="flex gap-4 h-16 mb-4">
             <div className="flex-1 bg-black/20 rounded-xl overflow-hidden relative border border-white/5">
                <span className="absolute top-1 left-2 text-[10px] text-slate-500 uppercase">Input</span>
                {isOfflineActive && isConnected 
                  ? <div className="w-full h-full flex items-center justify-center"><div className="w-24 h-1 bg-orange-500 animate-pulse rounded-full"></div></div>
                  : <AudioVisualizer analyser={inputAnalyserRef.current} isActive={isConnected} color="#22d3ee" />
                }
             </div>
             <div className="flex-1 bg-black/20 rounded-xl overflow-hidden relative border border-white/5">
                <span className="absolute top-1 right-2 text-[10px] text-slate-500 uppercase">Output</span>
                {isOfflineActive && isConnected 
                   ? <div className="w-full h-full flex items-center justify-center text-xs text-orange-400">Synthesizing...</div>
                   : <AudioVisualizer analyser={outputAnalyserRef.current} isActive={isConnected} color={isOfflineActive ? '#f97316' : '#a855f7'} />
                }
             </div>
          </div>

          <div className="flex items-center justify-between gap-4">

            {/* Language Selector */}
            <div className="flex-1">
              <label className="text-xs text-slate-400 ml-1 mb-1 block uppercase font-bold tracking-wider">Target</label>
              <div className="relative group">
                <select 
                  value={targetLang}
                  onChange={(e) => {
                    if (isConnected) stopConnection();
                    setTargetLang(e.target.value as TargetLanguage);
                  }}
                  disabled={isConnected}
                  className="w-full bg-slate-800/80 border border-slate-600 text-white rounded-xl px-4 py-3 appearance-none focus:outline-none focus:ring-2 focus:ring-blue-500 transition-all disabled:opacity-50"
                >
                  {Object.values(TargetLanguage).map((lang) => (
                    <option key={lang} value={lang}>{lang}</option>
                  ))}
                </select>
                <div className="absolute right-3 top-1/2 -translate-y-1/2 pointer-events-none text-slate-400">
                  <Globe size={16} />
                </div>
              </div>
            </div>

            {/* Main Action Button */}
            <div className="flex-none">
              <button
                onClick={isConnected ? stopConnection : connectToLiveAPI}
                className={`w-16 h-16 rounded-full flex items-center justify-center transition-all duration-300 shadow-lg ${
                  isConnected 
                    ? 'bg-red-500 hover:bg-red-600 shadow-red-500/30 scale-105' 
                    : isOfflineActive 
                      ? 'bg-orange-500 hover:bg-orange-400 shadow-orange-500/30'
                      : 'bg-blue-500 hover:bg-blue-400 shadow-blue-500/30'
                }`}
              >
                {isConnected ? (
                  <MicOff size={28} className="text-white" />
                ) : (
                  <Mic size={28} className="text-white" />
                )}
              </button>
            </div>

             {/* Clear History */}
             <div className="flex-none flex items-end h-full pb-2">
                <button 
                  onClick={() => setMessages([])} 
                  className="p-2 text-slate-400 hover:text-white transition-colors"
                  title="Clear History"
                >
                  <RotateCcw size={20} />
                </button>
             </div>
          </div>
        </div>
      </main>

      {/* Settings Modal */}
      {showSettings && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm">
          <div className="bg-slate-900 border border-slate-700 rounded-2xl w-full max-w-md shadow-2xl overflow-hidden flex flex-col max-h-[90vh]">
             <div className="p-4 border-b border-slate-800 flex justify-between items-center bg-slate-800/50">
                <h2 className="text-lg font-bold flex items-center gap-2">
                  <Settings size={20} className="text-blue-400"/> Settings
                </h2>
                <button onClick={() => setShowSettings(false)} className="text-slate-400 hover:text-white">
                  <X size={24} />
                </button>
             </div>

             <div className="p-6 overflow-y-auto">

               {/* Mode Toggle */}
               <div className="mb-8">
                 <h3 className="text-sm font-semibold text-slate-400 uppercase tracking-wider mb-3">Connection</h3>
                 <div className="flex items-center justify-between bg-slate-800/50 p-4 rounded-xl border border-slate-700">
                    <div className="flex items-center gap-3">
                       {forceOfflineMode ? <WifiOff size={20} className="text-orange-400"/> : <Wifi size={20} className="text-blue-400"/>}
                       <div>
                         <div className="font-medium">Offline Mode</div>
                         <div className="text-xs text-slate-400">Force offline translation</div>
                       </div>
                    </div>
                    <button 
                       onClick={() => {
                         if (isConnected) stopConnection();
                         setForceOfflineMode(!forceOfflineMode);
                       }}
                       className={`w-12 h-6 rounded-full p-1 transition-colors ${forceOfflineMode ? 'bg-orange-500' : 'bg-slate-600'}`}
                    >
                       <div className={`w-4 h-4 rounded-full bg-white transition-transform ${forceOfflineMode ? 'translate-x-6' : ''}`}></div>
                    </button>
                 </div>
               </div>

               {/* Offline Packs */}
               <div>
                 <h3 className="text-sm font-semibold text-slate-400 uppercase tracking-wider mb-3">Offline Language Packs</h3>
                 <div className="space-y-3">
                    {offlinePacks.map(pack => (
                       <div key={pack.id} className="bg-slate-800/50 p-3 rounded-xl border border-slate-700 flex items-center justify-between">
                          <div className="flex-1">
                             <div className="flex items-center gap-2">
                               <span className="font-semibold">{pack.pair}</span>
                               <span className="text-xs bg-slate-700 px-1.5 py-0.5 rounded">{pack.size}</span>
                             </div>
                             <div className="text-sm text-slate-400">{pack.name}</div>
                             {pack.progress > 0 && pack.progress < 100 && (
                               <div className="w-full h-1 bg-slate-700 mt-2 rounded-full overflow-hidden">
                                  <div className="h-full bg-blue-500 transition-all" style={{width: `${pack.progress}%`}}></div>
                               </div>
                             )}
                          </div>

                          <div className="ml-4">
                             {pack.downloaded ? (
                               <button 
                                 onClick={() => deletePack(pack.id)}
                                 className="w-10 h-10 rounded-full bg-slate-700/50 hover:bg-red-500/20 hover:text-red-400 flex items-center justify-center text-green-400 transition-colors"
                               >
                                  <div className="group relative">
                                    <Check size={20} className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 group-hover:opacity-0 transition-opacity" />
                                    <Trash2 size={20} className="opacity-0 group-hover:opacity-100 transition-opacity" />
                                  </div>
                               </button>
                             ) : pack.progress > 0 ? (
                               <div className="text-xs text-blue-400 font-bold">{pack.progress}%</div>
                             ) : (
                               <button 
                                 onClick={() => downloadPack(pack.id)}
                                 className="w-10 h-10 rounded-full bg-slate-700 hover:bg-blue-600 transition-colors flex items-center justify-center text-white"
                               >
                                 <Download size={20} />
                               </button>
                             )}
                          </div>
                       </div>
                    ))}
                 </div>
               </div>
             </div>
          </div>
        </div>
      )}

    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';
import { TargetLanguage, ChatMessage, OfflinePack } from './types';
import { float32To16BitPCM, arrayBufferToBase64, base64ToArrayBuffer, pcm16ToFloat32 } from './utils/audioUtils';
import AudioVisualizer from './components/AudioVisualizer';
import { Mic, MicOff, Globe, Settings, Volume2, RotateCcw, Wifi, WifiOff, Download, Check, Trash2, X } from 'lucide-react';

// Live API Configuration
const MODEL_NAME = 'gemini-2.5-flash-native-audio-preview-09-2025';
const INPUT_SAMPLE_RATE = 16000;
const OUTPUT_SAMPLE_RATE = 24000;

// Mock Offline Packs
const INITIAL_PACKS: OfflinePack[] = [
  { id: 'tr-en', pair: 'TR ↔ EN', name: 'English Pack', size: '45 MB', downloaded: false, progress: 0 },
  { id: 'tr-nl', pair: 'TR ↔ NL', name: 'Dutch Pack', size: '42 MB', downloaded: false, progress: 0 },
  { id: 'tr-ar', pair: 'TR ↔ AR', name: 'Arabic Pack', size: '50 MB', downloaded: false, progress: 0 },
  { id: 'tr-ru', pair: 'TR ↔ RU', name: 'Russian Pack', size: '48 MB', downloaded: false, progress: 0 },
];

const App: React.FC = () => {
  const [targetLang, setTargetLang] = useState<TargetLanguage>(TargetLanguage.ENGLISH);
  const [isConnected, setIsConnected] = useState(false);
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [error, setError] = useState<string | null>(null);

  // Offline / Network State
  const [isOnline, setIsOnline] = useState(navigator.onLine);
  const [forceOfflineMode, setForceOfflineMode] = useState(false);
  const [showSettings, setShowSettings] = useState(false);
  const [offlinePacks, setOfflinePacks] = useState<OfflinePack[]>(INITIAL_PACKS);

  // Audio Context Refs
  const inputAudioContextRef = useRef<AudioContext | null>(null);
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const inputAnalyserRef = useRef<AnalyserNode | null>(null);
  const outputAnalyserRef = useRef<AnalyserNode | null>(null);
  const mediaStreamRef = useRef<MediaStream | null>(null);

  // Logic Refs
  const aiClientRef = useRef<GoogleGenAI | null>(null);
  const sessionPromiseRef = useRef<Promise<any> | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());

  // Transcription Buffers
  const currentInputTranscription = useRef('');
  const currentOutputTranscription = useRef('');

  // Offline Recognition Ref
  const recognitionRef = useRef<any>(null);

  // 1. Initialize Gemini Client & Network Listeners
  useEffect(() => {
    if (process.env.API_KEY) {
      aiClientRef.current = new GoogleGenAI({ apiKey: process.env.API_KEY });
    } else {
      setError("API Key not found in environment variables.");
    }

    // Network Listeners
    const handleOnline = () => setIsOnline(true);
    const handleOffline = () => {
      setIsOnline(false);
      stopConnection(); // Stop Gemini if network drops
    };

    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);

    // Load packs from localStorage (Simulation)
    const savedPacks = localStorage.getItem('offlinePacks');
    if (savedPacks) {
      setOfflinePacks(JSON.parse(savedPacks));
    }

    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
    };
  }, []);

  const isOfflineActive = !isOnline || forceOfflineMode;

  // 2. Audio Processing Helper: Resample and Send (Online Only)
  const processAudioInput = useCallback((inputData: Float32Array) => {
    if (!sessionPromiseRef.current) return;
    const pcmData = float32To16BitPCM(inputData);
    const base64Data = arrayBufferToBase64(pcmData);

    sessionPromiseRef.current.then((session) => {
      session.sendRealtimeInput({
        media: {
          mimeType: `audio/pcm;rate=${INPUT_SAMPLE_RATE}`,
          data: base64Data,
        },
      });
    });
  }, []);

  // 3. Connect to Live API (Online)
  const connectToLiveAPI = async () => {
    if (isOfflineActive) {
      startOfflineRecognition();
      return;
    }

    if (!aiClientRef.current) return;
    setError(null);

    try {
      // Setup Audio Input
      const stream = await navigator.mediaDevices.getUserMedia({ audio: {
        sampleRate: INPUT_SAMPLE_RATE,
        channelCount: 1,
        echoCancellation: true,
        noiseSuppression: true,
        autoGainControl: true
      }});
      mediaStreamRef.current = stream;

      const audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ 
        sampleRate: INPUT_SAMPLE_RATE 
      });
      inputAudioContextRef.current = audioCtx;

      const source = audioCtx.createMediaStreamSource(stream);
      const analyser = audioCtx.createAnalyser();
      analyser.fftSize = 256;
      inputAnalyserRef.current = analyser;

      const scriptProcessor = audioCtx.createScriptProcessor(4096, 1, 1);

      scriptProcessor.onaudioprocess = (e) => {
        const inputData = e.inputBuffer.getChannelData(0);
        processAudioInput(inputData);
      };

      source.connect(analyser);
      analyser.connect(scriptProcessor);
      scriptProcessor.connect(audioCtx.destination);

      // Setup Audio Output
      const outCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ 
        sampleRate: OUTPUT_SAMPLE_RATE 
      });
      outputAudioContextRef.current = outCtx;
      const outAnalyser = outCtx.createAnalyser();
      outAnalyser.fftSize = 256;
      outputAnalyserRef.current = outAnalyser;
      outAnalyser.connect(outCtx.destination);

      const systemPrompt = `You are a world-class simultaneous interpreter. 
      Your task is to translate spoken Turkish into ${targetLang} immediately.
      Simply output the translated audio in ${targetLang}.
      Also provide the text transcriptions for both input and output.`;

      sessionPromiseRef.current = aiClientRef.current.live.connect({
        model: MODEL_NAME,
        config: {
          systemInstruction: systemPrompt,
          responseModalities: [Modality.AUDIO],
          inputAudioTranscription: {},
          outputAudioTranscription: {},
        },
        callbacks: {
          onopen: () => {
            console.log("Gemini Live Session Opened");
            setIsConnected(true);
            nextStartTimeRef.current = 0;
          },
          onmessage: async (msg: LiveServerMessage) => {
            if (msg.serverContent?.inputTranscription) {
               currentInputTranscription.current += msg.serverContent.inputTranscription.text;
            }
            if (msg.serverContent?.outputTranscription) {
               currentOutputTranscription.current += msg.serverContent.outputTranscription.text;
            }
            if (msg.serverContent?.turnComplete) {
               const inputTx = currentInputTranscription.current.trim();
               const outputTx = currentOutputTranscription.current.trim();
               if (inputTx || outputTx) {
                 addMessage('user', inputTx || '(Silence)');
                 addMessage('model', outputTx || '...');
               }
               currentInputTranscription.current = '';
               currentOutputTranscription.current = '';
            }
            const audioData = msg.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
            if (audioData) {
               playAudioResponse(audioData);
            }
          },
          onclose: () => {
            console.log("Session Closed");
            stopConnection();
          },
          onerror: (err) => {
            console.error("Session Error", err);
            setError("Connection disrupted. Please retry.");
            stopConnection();
          }
        }
      });
    } catch (e: any) {
      console.error(e);
      setError(`Failed to initialize: ${e.message}`);
      stopConnection();
    }
  };

  // 4. Offline Logic (Web Speech API)
  const startOfflineRecognition = () => {
    // Check if browser supports Web Speech API
    if (!('webkitSpeechRecognition' in window)) {
      setError("Offline speech recognition is not supported in this browser.");
      return;
    }

    // Check if the pack is "downloaded"
    const currentPack = offlinePacks.find(p => p.name.includes(targetLang));
    if (!currentPack?.downloaded) {
      // Allow it anyway for demo purposes, but warn user
      // setError(`Please download the ${targetLang} pack for offline use.`);
      // return;
    }

    try {
      const Recognition = (window as any).webkitSpeechRecognition;
      const recognition = new Recognition();
      recognition.lang = 'tr-TR'; // Input is Turkish
      recognition.continuous = true;
      recognition.interimResults = false;

      recognition.onstart = () => {
        setIsConnected(true);
      };

      recognition.onresult = (event: any) => {
        const transcript = event.results[event.results.length - 1][0].transcript;
        addMessage('user', transcript);

        // Simulate Offline Translation (Naive Mock)
        // In a real app, you would use a WASM model like transformers.js here
        const translationMock = `(Offline ${targetLang}) ${transcript}`; 

        setTimeout(() => {
          addMessage('model', translationMock);
          speakOffline(transcript, targetLang); // Speak the result
        }, 500);
      };

      recognition.onerror = (event: any) => {
        console.error("Offline Speech Error", event.error);
        if (event.error === 'not-allowed') {
          setError("Microphone access denied.");
        }
        stopConnection();
      };

      recognition.onend = () => {
        // Auto-restart if still connected
        if (isConnected) {
            // recognition.start(); 
            // Note: Preventing infinite loops in this demo, usually you'd check a flag
            setIsConnected(false); 
        }
      };

      recognitionRef.current = recognition;
      recognition.start();

    } catch (e) {
      console.error(e);
      setIsConnected(false);
    }
  };

  const speakOffline = (text: string, lang: TargetLanguage) => {
    if ('speechSynthesis' in window) {
      const utterance = new SpeechSynthesisUtterance(text); // In reality, translate first
      // Map TargetLanguage to BCP-47 tags
      const langMap: Record<TargetLanguage, string> = {
        [TargetLanguage.ENGLISH]: 'en-US',
        [TargetLanguage.DUTCH]: 'nl-NL',
        [TargetLanguage.ARABIC]: 'ar-SA',
        [TargetLanguage.RUSSIAN]: 'ru-RU'
      };
      utterance.lang = langMap[lang];
      window.speechSynthesis.speak(utterance);
    }
  };


  // 5. Play Output Audio (Online)
  const playAudioResponse = async (base64Audio: string) => {
    if (!outputAudioContextRef.current || !outputAnalyserRef.current) return;
    const ctx = outputAudioContextRef.current;
    try {
      const arrayBuffer = base64ToArrayBuffer(base64Audio);
      const float32Data = pcm16ToFloat32(arrayBuffer);
      const audioBuffer = ctx.createBuffer(1, float32Data.length, OUTPUT_SAMPLE_RATE);
      audioBuffer.getChannelData(0).set(float32Data);
      const source = ctx.createBufferSource();
      source.buffer = audioBuffer;
      source.connect(outputAnalyserRef.current);
      const currentTime = ctx.currentTime;
      const startTime = Math.max(nextStartTimeRef.current, currentTime);
      source.start(startTime);
      nextStartTimeRef.current = startTime + audioBuffer.duration;
      source.onended = () => sourcesRef.current.delete(source);
      sourcesRef.current.add(source);
    } catch (err) {
      console.error("Audio playback error", err);
    }
  };

  // 6. Helpers & Cleanup
  const addMessage = (role: 'user' | 'model', text: string) => {
    setMessages(prev => [...prev, { 
      id: Date.now().toString() + Math.random(), 
      role, 
      text, 
      timestamp: new Date(), 
      isFinal: true 
    }]);
  };

  const stopConnection = useCallback(() => {
    setIsConnected(false);

    // Stop Live API
    if (mediaStreamRef.current) {
      mediaStreamRef.current.getTracks().forEach(track => track.stop());
      mediaStreamRef.current = null;
    }
    if (inputAudioContextRef.current) {
      inputAudioContextRef.current.close();
      inputAudioContextRef.current = null;
    }
    if (outputAudioContextRef.current) {
      outputAudioContextRef.current.close();
      outputAudioContextRef.current = null;
    }
    sessionPromiseRef.current = null;

    // Stop Offline API
    if (recognitionRef.current) {
      recognitionRef.current.stop();
      recognitionRef.current = null;
    }
  }, []);

  const chatContainerRef = useRef<HTMLDivElement>(null);
  useEffect(() => {
    if (chatContainerRef.current) {
      chatContainerRef.current.scrollTop = chatContainerRef.current.scrollHeight;
    }
  }, [messages]);

  // Settings: Download Simulation
  const downloadPack = (id: string) => {
    setOfflinePacks(prev => prev.map(p => p.id === id ? { ...p, progress: 5 } : p));

    let progress = 5;
    const interval = setInterval(() => {
      progress += Math.floor(Math.random() * 15);
      if (progress >= 100) {
        progress = 100;
        clearInterval(interval);
        setOfflinePacks(prev => {
          const newPacks = prev.map(p => p.id === id ? { ...p, progress: 100, downloaded: true } : p);
          localStorage.setItem('offlinePacks', JSON.stringify(newPacks));
          return newPacks;
        });
      } else {
        setOfflinePacks(prev => prev.map(p => p.id === id ? { ...p, progress } : p));
      }
    }, 300);
  };

  const deletePack = (id: string) => {
     setOfflinePacks(prev => {
       const newPacks = prev.map(p => p.id === id ? { ...p, progress: 0, downloaded: false } : p);
       localStorage.setItem('offlinePacks', JSON.stringify(newPacks));
       return newPacks;
     });
  };

  return (
    <div className="min-h-screen bg-slate-900 text-slate-100 flex flex-col font-sans relative overflow-hidden">

      {/* Background Gradients */}
      <div className="absolute top-0 left-0 w-full h-full overflow-hidden z-0 pointer-events-none">
        <div className={`absolute top-[-10%] left-[-10%] w-[500px] h-[500px] rounded-full blur-[100px] animate-pulse ${isOfflineActive ? 'bg-orange-600/20' : 'bg-blue-600/20'}`}></div>
        <div className={`absolute bottom-[-10%] right-[-10%] w-[500px] h-[500px] rounded-full blur-[100px] animate-pulse ${isOfflineActive ? 'bg-red-600/20' : 'bg-purple-600/20'}`} style={{ animationDelay: '2s' }}></div>
      </div>

      {/* Header */}
      <header className="z-10 p-4 border-b border-slate-700/50 glass-panel flex justify-between items-center sticky top-0">
        <div className="flex items-center gap-2">
          <div className={`w-8 h-8 rounded-lg flex items-center justify-center bg-gradient-to-br ${isOfflineActive ? 'from-orange-500 to-red-600' : 'from-cyan-400 to-blue-600'}`}>
            <Globe size={18} className="text-white" />
          </div>
          <h1 className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-slate-100 to-slate-300">
            LinguaFlow {isOfflineActive ? 'Offline' : 'Live'}
          </h1>
        </div>
        <div className="flex items-center gap-3">
          <button 
             onClick={() => setShowSettings(true)}
             className="p-2 rounded-full hover:bg-slate-800 transition-colors"
          >
            <Settings size={20} className="text-slate-400" />
          </button>
          <div className={`flex items-center gap-2 px-3 py-1 rounded-full border ${isOfflineActive ? 'border-orange-500/30 bg-orange-500/10' : 'border-blue-500/30 bg-blue-500/10'}`}>
             {isOfflineActive ? <WifiOff size={14} className="text-orange-400"/> : <Wifi size={14} className="text-blue-400"/>}
             <span className={`text-xs font-bold ${isOfflineActive ? 'text-orange-400' : 'text-blue-400'}`}>
                {isOfflineActive ? 'OFFLINE' : 'ONLINE'}
             </span>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 flex flex-col max-w-3xl w-full mx-auto p-4 z-10 relative h-[calc(100vh-80px)]">

        {/* Error Banner */}
        {error && (
          <div className="bg-red-500/10 border border-red-500/50 text-red-200 p-3 rounded-lg mb-4 text-sm flex justify-between items-center animate-fade-in">
            <span>{error}</span>
            <button onClick={() => setError(null)} className="text-white hover:text-red-200">&times;</button>
          </div>
        )}

        {/* Chat Area */}
        <div ref={chatContainerRef} className="flex-1 overflow-y-auto space-y-4 mb-4 pr-2 pb-20">
          {messages.length === 0 && (
            <div className="h-full flex flex-col items-center justify-center text-slate-500 opacity-60">
              {isOfflineActive ? <WifiOff size={48} className="mb-4 text-orange-600/50" /> : <Volume2 size={48} className="mb-4 text-blue-600/50" />}
              <p className="text-center font-medium">
                {isOfflineActive ? 'Offline Mode Active' : 'Real-time Live Translation'}
              </p>
              <p className="text-sm mt-2 max-w-xs text-center">
                {isOfflineActive 
                  ? 'Using on-device speech recognition. Accuracy may vary.' 
                  : 'Select a language and press start to begin simultaneous translation.'}
              </p>
            </div>
          )}

          {messages.map((msg) => (
            <div key={msg.id} className={`flex ${msg.role === 'user' ? 'justify-start' : 'justify-end'}`}>
              <div className={`max-w-[80%] rounded-2xl p-4 shadow-lg ${
                msg.role === 'user' 
                  ? 'bg-slate-800 border border-slate-700 text-slate-200 rounded-bl-none' 
                  : isOfflineActive 
                    ? 'bg-gradient-to-br from-orange-700 to-red-800 text-white rounded-br-none border border-orange-500/20'
                    : 'bg-gradient-to-br from-blue-600 to-cyan-600 text-white rounded-br-none'
              }`}>
                <div className="text-xs opacity-50 mb-1 font-semibold tracking-wider flex justify-between items-center">
                  <span>{msg.role === 'user' ? 'TURKISH (You)' : targetLang.toUpperCase()}</span>
                  {isOfflineActive && msg.role === 'model' && <WifiOff size={10} />}
                </div>
                <p className="text-lg leading-relaxed">{msg.text}</p>
              </div>
            </div>
          ))}

          {/* Realtime Transcripts */}
          {(currentInputTranscription.current || currentOutputTranscription.current) && isConnected && !isOfflineActive && (
             <div className="flex justify-center my-2">
               <span className="text-xs text-slate-400 animate-pulse">Processing...</span>
             </div>
          )}
        </div>

        {/* Control Deck */}
        <div className="glass-panel rounded-3xl p-4 shadow-2xl border border-white/5">

          {/* Visualizers (Only for Online, simplistic for Offline) */}
          <div className="flex gap-4 h-16 mb-4">
             <div className="flex-1 bg-black/20 rounded-xl overflow-hidden relative border border-white/5">
                <span className="absolute top-1 left-2 text-[10px] text-slate-500 uppercase">Input</span>
                {isOfflineActive && isConnected 
                  ? <div className="w-full h-full flex items-center justify-center"><div className="w-24 h-1 bg-orange-500 animate-pulse rounded-full"></div></div>
                  : <AudioVisualizer analyser={inputAnalyserRef.current} isActive={isConnected} color="#22d3ee" />
                }
             </div>
             <div className="flex-1 bg-black/20 rounded-xl overflow-hidden relative border border-white/5">
                <span className="absolute top-1 right-2 text-[10px] text-slate-500 uppercase">Output</span>
                {isOfflineActive && isConnected 
                   ? <div className="w-full h-full flex items-center justify-center text-xs text-orange-400">Synthesizing...</div>
                   : <AudioVisualizer analyser={outputAnalyserRef.current} isActive={isConnected} color={isOfflineActive ? '#f97316' : '#a855f7'} />
                }
             </div>
          </div>

          <div className="flex items-center justify-between gap-4">

            {/* Language Selector */}
            <div className="flex-1">
              <label className="text-xs text-slate-400 ml-1 mb-1 block uppercase font-bold tracking-wider">Target</label>
              <div className="relative group">
                <select 
                  value={targetLang}
                  onChange={(e) => {
                    if (isConnected) stopConnection();
                    setTargetLang(e.target.value as TargetLanguage);
                  }}
                  disabled={isConnected}
                  className="w-full bg-slate-800/80 border border-slate-600 text-white rounded-xl px-4 py-3 appearance-none focus:outline-none focus:ring-2 focus:ring-blue-500 transition-all disabled:opacity-50"
                >
                  {Object.values(TargetLanguage).map((lang) => (
                    <option key={lang} value={lang}>{lang}</option>
                  ))}
                </select>
                <div className="absolute right-3 top-1/2 -translate-y-1/2 pointer-events-none text-slate-400">
                  <Globe size={16} />
                </div>
              </div>
            </div>

            {/* Main Action Button */}
            <div className="flex-none">
              <button
                onClick={isConnected ? stopConnection : connectToLiveAPI}
                className={`w-16 h-16 rounded-full flex items-center justify-center transition-all duration-300 shadow-lg ${
                  isConnected 
                    ? 'bg-red-500 hover:bg-red-600 shadow-red-500/30 scale-105' 
                    : isOfflineActive 
                      ? 'bg-orange-500 hover:bg-orange-400 shadow-orange-500/30'
                      : 'bg-blue-500 hover:bg-blue-400 shadow-blue-500/30'
                }`}
              >
                {isConnected ? (
                  <MicOff size={28} className="text-white" />
                ) : (
                  <Mic size={28} className="text-white" />
                )}
              </button>
            </div>

             {/* Clear History */}
             <div className="flex-none flex items-end h-full pb-2">
                <button 
                  onClick={() => setMessages([])} 
                  className="p-2 text-slate-400 hover:text-white transition-colors"
                  title="Clear History"
                >
                  <RotateCcw size={20} />
                </button>
             </div>
          </div>
        </div>
      </main>

      {/* Settings Modal */}
      {showSettings && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm">
          <div className="bg-slate-900 border border-slate-700 rounded-2xl w-full max-w-md shadow-2xl overflow-hidden flex flex-col max-h-[90vh]">
             <div className="p-4 border-b border-slate-800 flex justify-between items-center bg-slate-800/50">
                <h2 className="text-lg font-bold flex items-center gap-2">
                  <Settings size={20} className="text-blue-400"/> Settings
                </h2>
                <button onClick={() => setShowSettings(false)} className="text-slate-400 hover:text-white">
                  <X size={24} />
                </button>
             </div>

             <div className="p-6 overflow-y-auto">

               {/* Mode Toggle */}
               <div className="mb-8">
                 <h3 className="text-sm font-semibold text-slate-400 uppercase tracking-wider mb-3">Connection</h3>
                 <div className="flex items-center justify-between bg-slate-800/50 p-4 rounded-xl border border-slate-700">
                    <div className="flex items-center gap-3">
                       {forceOfflineMode ? <WifiOff size={20} className="text-orange-400"/> : <Wifi size={20} className="text-blue-400"/>}
                       <div>
                         <div className="font-medium">Offline Mode</div>
                         <div className="text-xs text-slate-400">Force offline translation</div>
                       </div>
                    </div>
                    <button 
                       onClick={() => {
                         if (isConnected) stopConnection();
                         setForceOfflineMode(!forceOfflineMode);
                       }}
                       className={`w-12 h-6 rounded-full p-1 transition-colors ${forceOfflineMode ? 'bg-orange-500' : 'bg-slate-600'}`}
                    >
                       <div className={`w-4 h-4 rounded-full bg-white transition-transform ${forceOfflineMode ? 'translate-x-6' : ''}`}></div>
                    </button>
                 </div>
               </div>

               {/* Offline Packs */}
               <div>
                 <h3 className="text-sm font-semibold text-slate-400 uppercase tracking-wider mb-3">Offline Language Packs</h3>
                 <div className="space-y-3">
                    {offlinePacks.map(pack => (
                       <div key={pack.id} className="bg-slate-800/50 p-3 rounded-xl border border-slate-700 flex items-center justify-between">
                          <div className="flex-1">
                             <div className="flex items-center gap-2">
                               <span className="font-semibold">{pack.pair}</span>
                               <span className="text-xs bg-slate-700 px-1.5 py-0.5 rounded">{pack.size}</span>
                             </div>
                             <div className="text-sm text-slate-400">{pack.name}</div>
                             {pack.progress > 0 && pack.progress < 100 && (
                               <div className="w-full h-1 bg-slate-700 mt-2 rounded-full overflow-hidden">
                                  <div className="h-full bg-blue-500 transition-all" style={{width: `${pack.progress}%`}}></div>
                               </div>
                             )}
                          </div>

                          <div className="ml-4">
                             {pack.downloaded ? (
                               <button 
                                 onClick={() => deletePack(pack.id)}
                                 className="w-10 h-10 rounded-full bg-slate-700/50 hover:bg-red-500/20 hover:text-red-400 flex items-center justify-center text-green-400 transition-colors"
                               >
                                  <div className="group relative">
                                    <Check size={20} className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 group-hover:opacity-0 transition-opacity" />
                                    <Trash2 size={20} className="opacity-0 group-hover:opacity-100 transition-opacity" />
                                  </div>
                               </button>
                             ) : pack.progress > 0 ? (
                               <div className="text-xs text-blue-400 font-bold">{pack.progress}%</div>
                             ) : (
                               <button 
                                 onClick={() => downloadPack(pack.id)}
                                 className="w-10 h-10 rounded-full bg-slate-700 hover:bg-blue-600 transition-colors flex items-center justify-center text-white"
                               >
                                 <Download size={20} />
                               </button>
                             )}
                          </div>
                       </div>
                    ))}
                 </div>
               </div>
             </div>
          </div>
        </div>
      )}

    </div>
  );
};

export default App;

const CACHE_NAME = 'linguaflow-v2';
const PRE_CACHE_ASSETS = [
  '/',
  '/index.html',
];

self.addEventListener('install', (event) => {
  event.waitUntil(
    caches.open(CACHE_NAME).then((cache) => {
      return cache.addAll(PRE_CACHE_ASSETS);
    })
  );
  self.skipWaiting();
});

self.addEventListener('activate', (event) => {
  event.waitUntil(
    caches.keys().then((cacheNames) => {
      return Promise.all(
        cacheNames.map((cacheName) => {
          if (cacheName !== CACHE_NAME) {
            return caches.delete(cacheName);
          }
        })
      );
    })
  );
  self.clients.claim();
});

self.addEventListener('fetch', (event) => {
  // Skip non-GET requests
  if (event.request.method !== 'GET') return;

  event.respondWith(
    caches.match(event.request).then((cachedResponse) => {
      if (cachedResponse) {
        return cachedResponse;
      }

      return fetch(event.request).then((response) => {
        // Check if we received a valid response
        if (!response || response.status !== 200 || response.type !== 'basic' && response.type !== 'cors') {
          return response;
        }

        // Clone the response
        const responseToCache = response.clone();

        // Cache the response for future offline use (Runtime Caching)
        caches.open(CACHE_NAME).then((cache) => {
          cache.put(event.request, responseToCache);
        });

        return response;
      }).catch(() => {
        // Fallback Logic
        if (event.request.mode === 'navigate') {
          return caches.match('/index.html');
        }
      });
    })
  );
});

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';
import { TargetLanguage, ChatMessage, OfflinePack } from './types';
import { float32To16BitPCM, arrayBufferToBase64, base64ToArrayBuffer, pcm16ToFloat32 } from './utils/audioUtils';
import AudioVisualizer from './components/AudioVisualizer';
import { Mic, MicOff, Globe, Settings, Volume2, RotateCcw, Wifi, WifiOff, Download, Check, Trash2, X, MessageSquare } from 'lucide-react';

// Live API Configuration
const MODEL_NAME = 'gemini-2.5-flash-native-audio-preview-09-2025';
const INPUT_SAMPLE_RATE = 16000;
const OUTPUT_SAMPLE_RATE = 24000;

// Mock Offline Packs
const INITIAL_PACKS: OfflinePack[] = [
  { id: 'tr-en', pair: 'TR ↔ EN', name: 'İngilizce Paketi', size: '45 MB', downloaded: false, progress: 0 },
  { id: 'tr-nl', pair: 'TR ↔ NL', name: 'Hollandaca Paketi', size: '42 MB', downloaded: false, progress: 0 },
  { id: 'tr-ar', pair: 'TR ↔ AR', name: 'Arapça Paketi', size: '50 MB', downloaded: false, progress: 0 },
  { id: 'tr-ru', pair: 'TR ↔ RU', name: 'Rusça Paketi', size: '48 MB', downloaded: false, progress: 0 },
];

const App: React.FC = () => {
  const [targetLang, setTargetLang] = useState<TargetLanguage>(TargetLanguage.ENGLISH);
  const [isConnected, setIsConnected] = useState(false);
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [error, setError] = useState<string | null>(null);

  // Real-time Display States
  const [realtimeInput, setRealtimeInput] = useState('');
  const [realtimeOutput, setRealtimeOutput] = useState('');

  // Offline / Network State
  const [isOnline, setIsOnline] = useState(navigator.onLine);
  const [forceOfflineMode, setForceOfflineMode] = useState(false);
  const [showSettings, setShowSettings] = useState(false);
  const [offlinePacks, setOfflinePacks] = useState<OfflinePack[]>(INITIAL_PACKS);

  // Audio Context Refs
  const inputAudioContextRef = useRef<AudioContext | null>(null);
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const inputAnalyserRef = useRef<AnalyserNode | null>(null);
  const outputAnalyserRef = useRef<AnalyserNode | null>(null);
  const mediaStreamRef = useRef<MediaStream | null>(null);

  // Logic Refs
  const aiClientRef = useRef<GoogleGenAI | null>(null);
  const sessionPromiseRef = useRef<Promise<any> | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());

  // Transcription Buffers
  const currentInputTranscription = useRef('');
  const currentOutputTranscription = useRef('');

  // Offline Recognition Ref
  const recognitionRef = useRef<any>(null);

  // 1. Initialize Gemini Client & Network Listeners
  useEffect(() => {
    if (process.env.API_KEY) {
      aiClientRef.current = new GoogleGenAI({ apiKey: process.env.API_KEY });
    } else {
      setError("API Anahtarı bulunamadı.");
    }

    // Network Listeners
    const handleOnline = () => setIsOnline(true);
    const handleOffline = () => {
      setIsOnline(false);
      stopConnection(); // Stop Gemini if network drops
    };

    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);

    // Load packs from localStorage (Simulation)
    const savedPacks = localStorage.getItem('offlinePacks');
    if (savedPacks) {
      setOfflinePacks(JSON.parse(savedPacks));
    }

    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
    };
  }, []);

  const isOfflineActive = !isOnline || forceOfflineMode;

  // 2. Audio Processing Helper: Resample and Send (Online Only)
  const processAudioInput = useCallback((inputData: Float32Array) => {
    if (!sessionPromiseRef.current) return;
    const pcmData = float32To16BitPCM(inputData);
    const base64Data = arrayBufferToBase64(pcmData);

    sessionPromiseRef.current.then((session) => {
      session.sendRealtimeInput({
        media: {
          mimeType: `audio/pcm;rate=${INPUT_SAMPLE_RATE}`,
          data: base64Data,
        },
      });
    });
  }, []);

  // 3. Connect to Live API (Online)
  const connectToLiveAPI = async () => {
    if (isOfflineActive) {
      startOfflineRecognition();
      return;
    }

    if (!aiClientRef.current) return;
    setError(null);

    try {
      // Setup Audio Input
      const stream = await navigator.mediaDevices.getUserMedia({ audio: {
        sampleRate: INPUT_SAMPLE_RATE,
        channelCount: 1,
        echoCancellation: true,
        noiseSuppression: true,
        autoGainControl: true
      }});
      mediaStreamRef.current = stream;

      const audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ 
        sampleRate: INPUT_SAMPLE_RATE 
      });
      inputAudioContextRef.current = audioCtx;

      const source = audioCtx.createMediaStreamSource(stream);
      const analyser = audioCtx.createAnalyser();
      analyser.fftSize = 256;
      inputAnalyserRef.current = analyser;

      const scriptProcessor = audioCtx.createScriptProcessor(4096, 1, 1);

      scriptProcessor.onaudioprocess = (e) => {
        const inputData = e.inputBuffer.getChannelData(0);
        processAudioInput(inputData);
      };

      source.connect(analyser);
      analyser.connect(scriptProcessor);
      scriptProcessor.connect(audioCtx.destination);

      // Setup Audio Output
      const outCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ 
        sampleRate: OUTPUT_SAMPLE_RATE 
      });
      outputAudioContextRef.current = outCtx;
      const outAnalyser = outCtx.createAnalyser();
      outAnalyser.fftSize = 256;
      outputAnalyserRef.current = outAnalyser;
      outAnalyser.connect(outCtx.destination);

      const systemPrompt = `You are a world-class simultaneous interpreter. 
      Your task is to translate spoken Turkish into ${targetLang} immediately.
      Simply output the translated audio in ${targetLang}.
      Do not add any introductory text or filler words.
      Also provide the text transcriptions for both input and output.`;

      sessionPromiseRef.current = aiClientRef.current.live.connect({
        model: MODEL_NAME,
        config: {
          systemInstruction: systemPrompt,
          responseModalities: [Modality.AUDIO],
          inputAudioTranscription: {},
          outputAudioTranscription: {},
        },
        callbacks: {
          onopen: () => {
            console.log("Gemini Live Session Opened");
            setIsConnected(true);
            nextStartTimeRef.current = 0;
            setRealtimeInput('');
            setRealtimeOutput('');
          },
          onmessage: async (msg: LiveServerMessage) => {
            // Partial Input Transcript
            if (msg.serverContent?.inputTranscription) {
               currentInputTranscription.current += msg.serverContent.inputTranscription.text;
               setRealtimeInput(currentInputTranscription.current);
            }
            // Partial Output Transcript
            if (msg.serverContent?.outputTranscription) {
               currentOutputTranscription.current += msg.serverContent.outputTranscription.text;
               setRealtimeOutput(currentOutputTranscription.current);
            }

            // Turn Complete
            if (msg.serverContent?.turnComplete) {
               const inputTx = currentInputTranscription.current.trim();
               const outputTx = currentOutputTranscription.current.trim();

               if (inputTx || outputTx) {
                 addMessage('user', inputTx || '(Sessizlik)');
                 addMessage('model', outputTx || '...');
               }

               // Reset Buffers
               currentInputTranscription.current = '';
               currentOutputTranscription.current = '';
               setRealtimeInput('');
               setRealtimeOutput('');
            }

            // Audio Output
            const audioData = msg.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
            if (audioData) {
               playAudioResponse(audioData);
            }
          },
          onclose: () => {
            console.log("Session Closed");
            stopConnection();
          },
          onerror: (err) => {
            console.error("Session Error", err);
            setError("Bağlantı koptu. Lütfen tekrar deneyin.");
            stopConnection();
          }
        }
      });
    } catch (e: any) {
      console.error(e);
      setError(`Başlatma hatası: ${e.message}`);
      stopConnection();
    }
  };

  // 4. Offline Logic (Web Speech API)
  const startOfflineRecognition = () => {
    if (!('webkitSpeechRecognition' in window)) {
      setError("Bu tarayıcıda çevrimdışı ses tanıma desteklenmiyor.");
      return;
    }

    try {
      const Recognition = (window as any).webkitSpeechRecognition;
      const recognition = new Recognition();
      recognition.lang = 'tr-TR'; 
      recognition.continuous = true;
      recognition.interimResults = true; // Show partial results

      recognition.onstart = () => {
        setIsConnected(true);
        setRealtimeInput('');
      };

      recognition.onresult = (event: any) => {
        let interimTranscript = '';
        let finalTranscript = '';

        for (let i = event.resultIndex; i < event.results.length; ++i) {
          if (event.results[i].isFinal) {
            finalTranscript += event.results[i][0].transcript;
          } else {
            interimTranscript += event.results[i][0].transcript;
          }
        }

        // Show realtime
        setRealtimeInput(finalTranscript || interimTranscript);

        if (finalTranscript) {
          addMessage('user', finalTranscript);
          setRealtimeInput('');

          // Simulate Offline Translation
          const translationMock = `(Çevrimdışı ${targetLang}) ${finalTranscript}`; 

          setTimeout(() => {
            addMessage('model', translationMock);
            speakOffline(finalTranscript, targetLang);
          }, 300);
        }
      };

      recognition.onerror = (event: any) => {
        console.error("Offline Speech Error", event.error);
        if (event.error === 'not-allowed') {
          setError("Mikrofon erişimi reddedildi.");
        }
        stopConnection();
      };

      recognition.onend = () => {
        // Simple auto-restart simulation for continuous feel, unless manually stopped
        if (isConnected) {
           // recognition.start(); // Caution: Can cause loops
           setIsConnected(false);
        }
      };

      recognitionRef.current = recognition;
      recognition.start();

    } catch (e) {
      console.error(e);
      setIsConnected(false);
    }
  };

  const speakOffline = (text: string, lang: TargetLanguage) => {
    if ('speechSynthesis' in window) {
      const utterance = new SpeechSynthesisUtterance(text); 
      // Mapping for languages
      const langMap: Record<TargetLanguage, string> = {
        [TargetLanguage.ENGLISH]: 'en-US',
        [TargetLanguage.DUTCH]: 'nl-NL',
        [TargetLanguage.ARABIC]: 'ar-SA',
        [TargetLanguage.RUSSIAN]: 'ru-RU'
      };
      utterance.lang = langMap[lang];
      window.speechSynthesis.speak(utterance);
    }
  };

  // 5. Play Output Audio (Online)
  const playAudioResponse = async (base64Audio: string) => {
    if (!outputAudioContextRef.current || !outputAnalyserRef.current) return;
    const ctx = outputAudioContextRef.current;
    try {
      const arrayBuffer = base64ToArrayBuffer(base64Audio);
      const float32Data = pcm16ToFloat32(arrayBuffer);
      const audioBuffer = ctx.createBuffer(1, float32Data.length, OUTPUT_SAMPLE_RATE);
      audioBuffer.getChannelData(0).set(float32Data);
      const source = ctx.createBufferSource();
      source.buffer = audioBuffer;
      source.connect(outputAnalyserRef.current);
      const currentTime = ctx.currentTime;
      const startTime = Math.max(nextStartTimeRef.current, currentTime);
      source.start(startTime);
      nextStartTimeRef.current = startTime + audioBuffer.duration;
      source.onended = () => sourcesRef.current.delete(source);
      sourcesRef.current.add(source);
    } catch (err) {
      console.error("Audio playback error", err);
    }
  };

  // 6. Helpers & Cleanup
  const addMessage = (role: 'user' | 'model', text: string) => {
    setMessages(prev => [...prev, { 
      id: Date.now().toString() + Math.random(), 
      role, 
      text, 
      timestamp: new Date(), 
      isFinal: true 
    }]);
  };

  const stopConnection = useCallback(() => {
    setIsConnected(false);
    setRealtimeInput('');
    setRealtimeOutput('');

    // Stop Live API
    if (mediaStreamRef.current) {
      mediaStreamRef.current.getTracks().forEach(track => track.stop());
      mediaStreamRef.current = null;
    }
    if (inputAudioContextRef.current) {
      inputAudioContextRef.current.close();
      inputAudioContextRef.current = null;
    }
    if (outputAudioContextRef.current) {
      outputAudioContextRef.current.close();
      outputAudioContextRef.current = null;
    }
    sessionPromiseRef.current = null;

    // Stop Offline API
    if (recognitionRef.current) {
      recognitionRef.current.stop();
      recognitionRef.current = null;
    }
  }, []);

  const chatContainerRef = useRef<HTMLDivElement>(null);
  useEffect(() => {
    if (chatContainerRef.current) {
      chatContainerRef.current.scrollTop = chatContainerRef.current.scrollHeight;
    }
  }, [messages, realtimeInput, realtimeOutput]);

  // Settings: Download Simulation
  const downloadPack = (id: string) => {
    setOfflinePacks(prev => prev.map(p => p.id === id ? { ...p, progress: 5 } : p));

    let progress = 5;
    const interval = setInterval(() => {
      progress += Math.floor(Math.random() * 15);
      if (progress >= 100) {
        progress = 100;
        clearInterval(interval);
        setOfflinePacks(prev => {
          const newPacks = prev.map(p => p.id === id ? { ...p, progress: 100, downloaded: true } : p);
          localStorage.setItem('offlinePacks', JSON.stringify(newPacks));
          return newPacks;
        });
      } else {
        setOfflinePacks(prev => prev.map(p => p.id === id ? { ...p, progress } : p));
      }
    }, 300);
  };

  const deletePack = (id: string) => {
     setOfflinePacks(prev => {
       const newPacks = prev.map(p => p.id === id ? { ...p, progress: 0, downloaded: false } : p);
       localStorage.setItem('offlinePacks', JSON.stringify(newPacks));
       return newPacks;
     });
  };

  return (
    <div className="min-h-screen bg-slate-900 text-slate-100 flex flex-col font-sans relative overflow-hidden">

      {/* Background Gradients */}
      <div className="absolute top-0 left-0 w-full h-full overflow-hidden z-0 pointer-events-none">
        <div className={`absolute top-[-10%] left-[-10%] w-[500px] h-[500px] rounded-full blur-[100px] animate-pulse ${isOfflineActive ? 'bg-orange-600/20' : 'bg-blue-600/20'}`}></div>
        <div className={`absolute bottom-[-10%] right-[-10%] w-[500px] h-[500px] rounded-full blur-[100px] animate-pulse ${isOfflineActive ? 'bg-red-600/20' : 'bg-purple-600/20'}`} style={{ animationDelay: '2s' }}></div>
      </div>

      {/* Header */}
      <header className="z-10 p-4 border-b border-slate-700/50 glass-panel flex justify-between items-center sticky top-0">
        <div className="flex items-center gap-2">
          <div className={`w-8 h-8 rounded-lg flex items-center justify-center bg-gradient-to-br ${isOfflineActive ? 'from-orange-500 to-red-600' : 'from-cyan-400 to-blue-600'}`}>
            <Globe size={18} className="text-white" />
          </div>
          <h1 className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-slate-100 to-slate-300">
            LinguaFlow {isOfflineActive ? 'Çevrimdışı' : 'Canlı'}
          </h1>
        </div>
        <div className="flex items-center gap-3">
          <button 
             onClick={() => setShowSettings(true)}
             className="p-2 rounded-full hover:bg-slate-800 transition-colors"
             title="Ayarlar"
          >
            <Settings size={20} className="text-slate-400" />
          </button>
          <div className={`flex items-center gap-2 px-3 py-1 rounded-full border ${isOfflineActive ? 'border-orange-500/30 bg-orange-500/10' : 'border-blue-500/30 bg-blue-500/10'}`}>
             {isOfflineActive ? <WifiOff size={14} className="text-orange-400"/> : <Wifi size={14} className="text-blue-400"/>}
             <span className={`text-xs font-bold ${isOfflineActive ? 'text-orange-400' : 'text-blue-400'}`}>
                {isOfflineActive ? 'OFFLINE' : 'ONLINE'}
             </span>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 flex flex-col max-w-3xl w-full mx-auto p-4 z-10 relative h-[calc(100vh-80px)]">

        {/* Error Banner */}
        {error && (
          <div className="bg-red-500/10 border border-red-500/50 text-red-200 p-3 rounded-lg mb-4 text-sm flex justify-between items-center animate-fade-in">
            <span>{error}</span>
            <button onClick={() => setError(null)} className="text-white hover:text-red-200">&times;</button>
          </div>
        )}

        {/* Chat Area */}
        <div ref={chatContainerRef} className="flex-1 overflow-y-auto space-y-4 mb-4 pr-2 pb-20">
          {messages.length === 0 && !realtimeInput && (
            <div className="h-full flex flex-col items-center justify-center text-slate-500 opacity-60">
              {isOfflineActive ? <WifiOff size={48} className="mb-4 text-orange-600/50" /> : <Volume2 size={48} className="mb-4 text-blue-600/50" />}
              <p className="text-center font-medium">
                {isOfflineActive ? 'Çevrimdışı Mod Aktif' : 'Gerçek Zamanlı Simültane Çeviri'}
              </p>
              <p className="text-sm mt-2 max-w-xs text-center">
                {isOfflineActive 
                  ? 'Cihaz üzerindeki ses tanıma kullanılıyor. Doğruluk oranı değişebilir.' 
                  : 'Başlamak için dili seçin ve mikrofona tıklayın.'}
              </p>
            </div>
          )}

          {messages.map((msg) => (
            <div key={msg.id} className={`flex ${msg.role === 'user' ? 'justify-start' : 'justify-end'}`}>
              <div className={`max-w-[80%] rounded-2xl p-4 shadow-lg ${
                msg.role === 'user' 
                  ? 'bg-slate-800 border border-slate-700 text-slate-200 rounded-bl-none' 
                  : isOfflineActive 
                    ? 'bg-gradient-to-br from-orange-700 to-red-800 text-white rounded-br-none border border-orange-500/20'
                    : 'bg-gradient-to-br from-blue-600 to-cyan-600 text-white rounded-br-none'
              }`}>
                <div className="text-xs opacity-50 mb-1 font-semibold tracking-wider flex justify-between items-center">
                  <span>{msg.role === 'user' ? 'TÜRKÇE (Siz)' : targetLang.toUpperCase()}</span>
                  {isOfflineActive && msg.role === 'model' && <WifiOff size={10} />}
                </div>
                <p className="text-lg leading-relaxed">{msg.text}</p>
              </div>
            </div>
          ))}

          {/* Real-time Streaming Bubbles (Partial Results) */}
          {(realtimeInput || realtimeOutput) && (
             <div className="space-y-2 opacity-80 animate-pulse">
                {realtimeInput && (
                  <div className="flex justify-start">
                     <div className="max-w-[80%] rounded-2xl p-4 bg-slate-800/60 border border-slate-700/50 border-dashed text-slate-300 rounded-bl-none">
                       <div className="text-xs opacity-50 mb-1 font-semibold">DİNLİYOR...</div>
                       <p className="text-lg">{realtimeInput}</p>
                     </div>
                  </div>
                )}
                {realtimeOutput && (
                  <div className="flex justify-end">
                     <div className="max-w-[80%] rounded-2xl p-4 bg-blue-900/40 border border-blue-500/30 border-dashed text-blue-100 rounded-br-none">
                       <div className="text-xs opacity-50 mb-1 font-semibold">ÇEVİRİYOR...</div>
                       <p className="text-lg">{realtimeOutput}</p>
                     </div>
                  </div>
                )}
             </div>
          )}
        </div>

        {/* Control Deck */}
        <div className="glass-panel rounded-3xl p-4 shadow-2xl border border-white/5">

          {/* Visualizers */}
          <div className="flex gap-4 h-16 mb-4">
             <div className="flex-1 bg-black/20 rounded-xl overflow-hidden relative border border-white/5">
                <span className="absolute top-1 left-2 text-[10px] text-slate-500 uppercase">Giriş (Mic)</span>
                {isOfflineActive && isConnected 
                  ? <div className="w-full h-full flex items-center justify-center"><div className="w-24 h-1 bg-orange-500 animate-pulse rounded-full"></div></div>
                  : <AudioVisualizer analyser={inputAnalyserRef.current} isActive={isConnected} color="#22d3ee" />
                }
             </div>
             <div className="flex-1 bg-black/20 rounded-xl overflow-hidden relative border border-white/5">
                <span className="absolute top-1 right-2 text-[10px] text-slate-500 uppercase">Çıkış (AI)</span>
                {isOfflineActive && isConnected 
                   ? <div className="w-full h-full flex items-center justify-center text-xs text-orange-400">Sentezleniyor...</div>
                   : <AudioVisualizer analyser={outputAnalyserRef.current} isActive={isConnected} color={isOfflineActive ? '#f97316' : '#a855f7'} />
                }
             </div>
          </div>

          <div className="flex items-center justify-between gap-4">

            {/* Language Selector */}
            <div className="flex-1">
              <label className="text-xs text-slate-400 ml-1 mb-1 block uppercase font-bold tracking-wider">Hedef Dil</label>
              <div className="relative group">
                <select 
                  value={targetLang}
                  onChange={(e) => {
                    if (isConnected) stopConnection();
                    setTargetLang(e.target.value as TargetLanguage);
                  }}
                  disabled={isConnected}
                  className="w-full bg-slate-800/80 border border-slate-600 text-white rounded-xl px-4 py-3 appearance-none focus:outline-none focus:ring-2 focus:ring-blue-500 transition-all disabled:opacity-50"
                >
                  {Object.values(TargetLanguage).map((lang) => (
                    <option key={lang} value={lang}>{lang}</option>
                  ))}
                </select>
                <div className="absolute right-3 top-1/2 -translate-y-1/2 pointer-events-none text-slate-400">
                  <Globe size={16} />
                </div>
              </div>
            </div>

            {/* Main Action Button */}
            <div className="flex-none">
              <button
                onClick={isConnected ? stopConnection : connectToLiveAPI}
                className={`w-16 h-16 rounded-full flex items-center justify-center transition-all duration-300 shadow-lg ${
                  isConnected 
                    ? 'bg-red-500 hover:bg-red-600 shadow-red-500/30 scale-105' 
                    : isOfflineActive 
                      ? 'bg-orange-500 hover:bg-orange-400 shadow-orange-500/30'
                      : 'bg-blue-500 hover:bg-blue-400 shadow-blue-500/30'
                }`}
              >
                {isConnected ? (
                  <MicOff size={28} className="text-white" />
                ) : (
                  <Mic size={28} className="text-white" />
                )}
              </button>
            </div>

             {/* Clear History */}
             <div className="flex-none flex items-end h-full pb-2">
                <button 
                  onClick={() => {
                    setMessages([]);
                    setRealtimeInput('');
                    setRealtimeOutput('');
                  }} 
                  className="p-2 text-slate-400 hover:text-white transition-colors"
                  title="Geçmişi Temizle"
                >
                  <RotateCcw size={20} />
                </button>
             </div>
          </div>
        </div>
      </main>

      {/* Settings Modal */}
      {showSettings && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm">
          <div className="bg-slate-900 border border-slate-700 rounded-2xl w-full max-w-md shadow-2xl overflow-hidden flex flex-col max-h-[90vh]">
             <div className="p-4 border-b border-slate-800 flex justify-between items-center bg-slate-800/50">
                <h2 className="text-lg font-bold flex items-center gap-2">
                  <Settings size={20} className="text-blue-400"/> Ayarlar
                </h2>
                <button onClick={() => setShowSettings(false)} className="text-slate-400 hover:text-white">
                  <X size={24} />
                </button>
             </div>

             <div className="p-6 overflow-y-auto">

               {/* Mode Toggle */}
               <div className="mb-8">
                 <h3 className="text-sm font-semibold text-slate-400 uppercase tracking-wider mb-3">Bağlantı</h3>
                 <div className="flex items-center justify-between bg-slate-800/50 p-4 rounded-xl border border-slate-700">
                    <div className="flex items-center gap-3">
                       {forceOfflineMode ? <WifiOff size={20} className="text-orange-400"/> : <Wifi size={20} className="text-blue-400"/>}
                       <div>
                         <div className="font-medium">Çevrimdışı Mod</div>
                         <div className="text-xs text-slate-400">Offline çeviriye zorla</div>
                       </div>
                    </div>
                    <button 
                       onClick={() => {
                         if (isConnected) stopConnection();
                         setForceOfflineMode(!forceOfflineMode);
                       }}
                       className={`w-12 h-6 rounded-full p-1 transition-colors ${forceOfflineMode ? 'bg-orange-500' : 'bg-slate-600'}`}
                    >
                       <div className={`w-4 h-4 rounded-full bg-white transition-transform ${forceOfflineMode ? 'translate-x-6' : ''}`}></div>
                    </button>
                 </div>
               </div>

               {/* Offline Packs */}
               <div>
                 <h3 className="text-sm font-semibold text-slate-400 uppercase tracking-wider mb-3">Çevrimdışı Dil Paketleri</h3>
                 <div className="space-y-3">
                    {offlinePacks.map(pack => (
                       <div key={pack.id} className="bg-slate-800/50 p-3 rounded-xl border border-slate-700 flex items-center justify-between">
                          <div className="flex-1">
                             <div className="flex items-center gap-2">
                               <span className="font-semibold">{pack.pair}</span>
                               <span className="text-xs bg-slate-700 px-1.5 py-0.5 rounded">{pack.size}</span>
                             </div>
                             <div className="text-sm text-slate-400">{pack.name}</div>
                             {pack.progress > 0 && pack.progress < 100 && (
                               <div className="w-full h-1 bg-slate-700 mt-2 rounded-full overflow-hidden">
                                  <div className="h-full bg-blue-500 transition-all" style={{width: `${pack.progress}%`}}></div>
                               </div>
                             )}
                          </div>

                          <div className="ml-4">
                             {pack.downloaded ? (
                               <button 
                                 onClick={() => deletePack(pack.id)}
                                 className="w-10 h-10 rounded-full bg-slate-700/50 hover:bg-red-500/20 hover:text-red-400 flex items-center justify-center text-green-400 transition-colors"
                                 title="Paketi Sil"
                               >
                                  <div className="group relative">
                                    <Check size={20} className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 group-hover:opacity-0 transition-opacity" />
                                    <Trash2 size={20} className="opacity-0 group-hover:opacity-100 transition-opacity" />
                                  </div>
                               </button>
                             ) : pack.progress > 0 ? (
                               <div className="text-xs text-blue-400 font-bold">{pack.progress}%</div>
                             ) : (
                               <button 
                                 onClick={() => downloadPack(pack.id)}
                                 className="w-10 h-10 rounded-full bg-slate-700 hover:bg-blue-600 transition-colors flex items-center justify-center text-white"
                                 title="İndir"
                               >
                                 <Download size={20} />
                               </button>
                             )}
                          </div>
                       </div>
                    ))}
                 </div>
               </div>
             </div>
          </div>
        </div>
      )}

    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';
import { TargetLanguage, ChatMessage, OfflinePack } from './types';
import { float32To16BitPCM, arrayBufferToBase64, base64ToArrayBuffer, pcm16ToFloat32 } from './utils/audioUtils';
import AudioVisualizer from './components/AudioVisualizer';
import { Mic, MicOff, Globe, Settings, Volume2, RotateCcw, Wifi, WifiOff, Download, Check, Trash2, X, Power, Zap } from 'lucide-react';

// Live API Configuration
const MODEL_NAME = 'gemini-2.5-flash-native-audio-preview-09-2025';
const INPUT_SAMPLE_RATE = 16000;
const OUTPUT_SAMPLE_RATE = 24000;

// Mock Offline Packs
const INITIAL_PACKS: OfflinePack[] = [
  { id: 'tr-en', pair: 'TR ↔ EN', name: 'İngilizce Paketi', size: '45 MB', downloaded: false, progress: 0 },
  { id: 'tr-nl', pair: 'TR ↔ NL', name: 'Hollandaca Paketi', size: '42 MB', downloaded: false, progress: 0 },
  { id: 'tr-ar', pair: 'TR ↔ AR', name: 'Arapça Paketi', size: '50 MB', downloaded: false, progress: 0 },
  { id: 'tr-ru', pair: 'TR ↔ RU', name: 'Rusça Paketi', size: '48 MB', downloaded: false, progress: 0 },
];

const App: React.FC = () => {
  const [targetLang, setTargetLang] = useState<TargetLanguage>(TargetLanguage.ENGLISH);
  // isConnected: WebSocket/Session is open
  const [isConnected, setIsConnected] = useState(false);
  // isTransmitting: User is holding the button (PTT)
  const [isTransmitting, setIsTransmitting] = useState(false);

  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [error, setError] = useState<string | null>(null);

  // Real-time Display States
  const [realtimeInput, setRealtimeInput] = useState('');
  const [realtimeOutput, setRealtimeOutput] = useState('');

  // Offline / Network State
  const [isOnline, setIsOnline] = useState(navigator.onLine);
  const [forceOfflineMode, setForceOfflineMode] = useState(false);
  const [showSettings, setShowSettings] = useState(false);
  const [offlinePacks, setOfflinePacks] = useState<OfflinePack[]>(INITIAL_PACKS);

  // Audio Context Refs
  const inputAudioContextRef = useRef<AudioContext | null>(null);
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const inputAnalyserRef = useRef<AnalyserNode | null>(null);
  const outputAnalyserRef = useRef<AnalyserNode | null>(null);
  const mediaStreamRef = useRef<MediaStream | null>(null);

  // Logic Refs
  const aiClientRef = useRef<GoogleGenAI | null>(null);
  const sessionPromiseRef = useRef<Promise<any> | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const isTransmittingRef = useRef(false); // Ref for audio processor access

  // Transcription Buffers
  const currentInputTranscription = useRef('');
  const currentOutputTranscription = useRef('');

  // Offline Recognition Ref
  const recognitionRef = useRef<any>(null);

  // 1. Initialize Gemini Client & Network Listeners
  useEffect(() => {
    if (process.env.API_KEY) {
      aiClientRef.current = new GoogleGenAI({ apiKey: process.env.API_KEY });
    } else {
      setError("API Anahtarı bulunamadı.");
    }

    // Network Listeners
    const handleOnline = () => setIsOnline(true);
    const handleOffline = () => {
      setIsOnline(false);
      stopConnection(); // Stop Gemini if network drops
    };

    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);

    // Load packs from localStorage (Simulation)
    const savedPacks = localStorage.getItem('offlinePacks');
    if (savedPacks) {
      setOfflinePacks(JSON.parse(savedPacks));
    }

    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
    };
  }, []);

  const isOfflineActive = !isOnline || forceOfflineMode;

  // 2. Audio Processing Helper: Resample and Send (Online Only)
  const processAudioInput = useCallback((inputData: Float32Array) => {
    // Only send data if connected AND holding the PTT button
    if (!sessionPromiseRef.current || !isTransmittingRef.current) return;

    const pcmData = float32To16BitPCM(inputData);
    const base64Data = arrayBufferToBase64(pcmData);

    sessionPromiseRef.current.then((session) => {
      session.sendRealtimeInput({
        media: {
          mimeType: `audio/pcm;rate=${INPUT_SAMPLE_RATE}`,
          data: base64Data,
        },
      });
    });
  }, []);

  // 3. Connect to Live API (Online Session Start)
  const toggleConnection = async () => {
    if (isConnected) {
      stopConnection();
      return;
    }

    // Offline Mode Logic handled differently (no persistent session needed strictly, but we mimic state)
    if (isOfflineActive) {
      setIsConnected(true);
      return;
    }

    if (!aiClientRef.current) return;
    setError(null);

    try {
      // Setup Audio Input
      const stream = await navigator.mediaDevices.getUserMedia({ audio: {
        sampleRate: INPUT_SAMPLE_RATE,
        channelCount: 1,
        echoCancellation: true,
        noiseSuppression: true,
        autoGainControl: true
      }});
      mediaStreamRef.current = stream;

      const audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ 
        sampleRate: INPUT_SAMPLE_RATE 
      });
      inputAudioContextRef.current = audioCtx;

      const source = audioCtx.createMediaStreamSource(stream);
      const analyser = audioCtx.createAnalyser();
      analyser.fftSize = 256;
      inputAnalyserRef.current = analyser;

      const scriptProcessor = audioCtx.createScriptProcessor(4096, 1, 1);

      scriptProcessor.onaudioprocess = (e) => {
        const inputData = e.inputBuffer.getChannelData(0);
        processAudioInput(inputData);
      };

      source.connect(analyser);
      analyser.connect(scriptProcessor);
      scriptProcessor.connect(audioCtx.destination);

      // Setup Audio Output
      const outCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ 
        sampleRate: OUTPUT_SAMPLE_RATE 
      });
      outputAudioContextRef.current = outCtx;
      const outAnalyser = outCtx.createAnalyser();
      outAnalyser.fftSize = 256;
      outputAnalyserRef.current = outAnalyser;
      outAnalyser.connect(outCtx.destination);

      const systemPrompt = `You are a world-class simultaneous interpreter. 
      Your task is to translate spoken Turkish into ${targetLang} immediately.
      Simply output the translated audio in ${targetLang}.
      Do not add any introductory text or filler words.
      Also provide the text transcriptions for both input and output.`;

      sessionPromiseRef.current = aiClientRef.current.live.connect({
        model: MODEL_NAME,
        config: {
          systemInstruction: systemPrompt,
          responseModalities: [Modality.AUDIO],
          inputAudioTranscription: {},
          outputAudioTranscription: {},
        },
        callbacks: {
          onopen: () => {
            console.log("Gemini Live Session Opened");
            setIsConnected(true);
            nextStartTimeRef.current = 0;
            setRealtimeInput('');
            setRealtimeOutput('');
          },
          onmessage: async (msg: LiveServerMessage) => {
            if (msg.serverContent?.inputTranscription) {
               currentInputTranscription.current += msg.serverContent.inputTranscription.text;
               setRealtimeInput(currentInputTranscription.current);
            }
            if (msg.serverContent?.outputTranscription) {
               currentOutputTranscription.current += msg.serverContent.outputTranscription.text;
               setRealtimeOutput(currentOutputTranscription.current);
            }

            if (msg.serverContent?.turnComplete) {
               const inputTx = currentInputTranscription.current.trim();
               const outputTx = currentOutputTranscription.current.trim();

               if (inputTx || outputTx) {
                 addMessage('user', inputTx || '(Sessizlik)');
                 addMessage('model', outputTx || '...');
               }

               currentInputTranscription.current = '';
               currentOutputTranscription.current = '';
               setRealtimeInput('');
               setRealtimeOutput('');
            }

            const audioData = msg.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
            if (audioData) {
               playAudioResponse(audioData);
            }
          },
          onclose: () => {
            console.log("Session Closed");
            stopConnection();
          },
          onerror: (err) => {
            console.error("Session Error", err);
            setError("Bağlantı hatası. Tekrar bağlanın.");
            stopConnection();
          }
        }
      });
    } catch (e: any) {
      console.error(e);
      setError(`Başlatma hatası: ${e.message}`);
      stopConnection();
    }
  };

  // 4. Push-to-Talk Logic
  const startTalking = () => {
    if (!isConnected) {
      // Shake effect or warning could go here
      return;
    }

    setIsTransmitting(true);
    isTransmittingRef.current = true;

    if (isOfflineActive) {
      startOfflineRecognition();
    }
  };

  const stopTalking = () => {
    setIsTransmitting(false);
    isTransmittingRef.current = false;

    if (isOfflineActive) {
      stopOfflineRecognition();
    }
  };

  // 5. Offline Logic (Web Speech API)
  const startOfflineRecognition = () => {
    if (!('webkitSpeechRecognition' in window)) {
      setError("Bu tarayıcıda çevrimdışı ses tanıma desteklenmiyor.");
      return;
    }

    // If already running, stop it first to reset
    if (recognitionRef.current) {
      try { recognitionRef.current.stop(); } catch(e){}
    }

    try {
      const Recognition = (window as any).webkitSpeechRecognition;
      const recognition = new Recognition();
      recognition.lang = 'tr-TR'; 
      recognition.continuous = true; // Keep listening while holding
      recognition.interimResults = true; 

      recognition.onstart = () => {
        setRealtimeInput('');
      };

      recognition.onresult = (event: any) => {
        let interimTranscript = '';
        let finalTranscript = '';

        for (let i = event.resultIndex; i < event.results.length; ++i) {
          if (event.results[i].isFinal) {
            finalTranscript += event.results[i][0].transcript;
          } else {
            interimTranscript += event.results[i][0].transcript;
          }
        }
        setRealtimeInput(finalTranscript || interimTranscript);

        // In offline PTT, we might just use the final result when they stop talking
      };

      recognition.onerror = (event: any) => {
        // Ignore 'no-speech' errors which happen if user clicks but doesn't speak immediately
        if (event.error !== 'no-speech') {
             console.error("Offline Speech Error", event.error);
        }
      };

      recognitionRef.current = recognition;
      recognition.start();

    } catch (e) {
      console.error(e);
    }
  };

  const stopOfflineRecognition = () => {
    if (recognitionRef.current) {
      // When stopping, we should process the last input
      // The onresult might fire one last time. 
      // We'll give it a small delay or rely on the final event.
      // But since Web Speech API is async, let's just stop.
      recognitionRef.current.stop();

      // Mock translation trigger
      setTimeout(() => {
        const text = realtimeInput.trim();
        if (text) {
           addMessage('user', text);
           setRealtimeInput('');
           const translationMock = `(Çevrimdışı ${targetLang}) ${text}`; 
           setTimeout(() => {
             addMessage('model', translationMock);
             speakOffline(text, targetLang);
           }, 500);
        }
      }, 500);
    }
  };

  const speakOffline = (text: string, lang: TargetLanguage) => {
    if ('speechSynthesis' in window) {
      const utterance = new SpeechSynthesisUtterance(text); 
      const langMap: Record<TargetLanguage, string> = {
        [TargetLanguage.ENGLISH]: 'en-US',
        [TargetLanguage.DUTCH]: 'nl-NL',
        [TargetLanguage.ARABIC]: 'ar-SA',
        [TargetLanguage.RUSSIAN]: 'ru-RU'
      };
      utterance.lang = langMap[lang];
      window.speechSynthesis.speak(utterance);
    }
  };

  // 6. Play Output Audio (Online)
  const playAudioResponse = async (base64Audio: string) => {
    if (!outputAudioContextRef.current || !outputAnalyserRef.current) return;
    const ctx = outputAudioContextRef.current;
    try {
      const arrayBuffer = base64ToArrayBuffer(base64Audio);
      const float32Data = pcm16ToFloat32(arrayBuffer);
      const audioBuffer = ctx.createBuffer(1, float32Data.length, OUTPUT_SAMPLE_RATE);
      audioBuffer.getChannelData(0).set(float32Data);
      const source = ctx.createBufferSource();
      source.buffer = audioBuffer;
      source.connect(outputAnalyserRef.current);
      const currentTime = ctx.currentTime;
      const startTime = Math.max(nextStartTimeRef.current, currentTime);
      source.start(startTime);
      nextStartTimeRef.current = startTime + audioBuffer.duration;
      source.onended = () => sourcesRef.current.delete(source);
      sourcesRef.current.add(source);
    } catch (err) {
      console.error("Audio playback error", err);
    }
  };

  // 7. Helpers & Cleanup
  const addMessage = (role: 'user' | 'model', text: string) => {
    setMessages(prev => [...prev, { 
      id: Date.now().toString() + Math.random(), 
      role, 
      text, 
      timestamp: new Date(), 
      isFinal: true 
    }]);
  };

  const stopConnection = useCallback(() => {
    setIsConnected(false);
    setIsTransmitting(false);
    isTransmittingRef.current = false;
    setRealtimeInput('');
    setRealtimeOutput('');

    if (mediaStreamRef.current) {
      mediaStreamRef.current.getTracks().forEach(track => track.stop());
      mediaStreamRef.current = null;
    }
    if (inputAudioContextRef.current) {
      inputAudioContextRef.current.close();
      inputAudioContextRef.current = null;
    }
    if (outputAudioContextRef.current) {
      outputAudioContextRef.current.close();
      outputAudioContextRef.current = null;
    }
    sessionPromiseRef.current = null;

    if (recognitionRef.current) {
      recognitionRef.current.stop();
      recognitionRef.current = null;
    }
  }, []);

  const chatContainerRef = useRef<HTMLDivElement>(null);
  useEffect(() => {
    if (chatContainerRef.current) {
      chatContainerRef.current.scrollTop = chatContainerRef.current.scrollHeight;
    }
  }, [messages, realtimeInput, realtimeOutput]);

  // Settings Logic
  const downloadPack = (id: string) => {
    setOfflinePacks(prev => prev.map(p => p.id === id ? { ...p, progress: 5 } : p));
    let progress = 5;
    const interval = setInterval(() => {
      progress += Math.floor(Math.random() * 15);
      if (progress >= 100) {
        progress = 100;
        clearInterval(interval);
        setOfflinePacks(prev => {
          const newPacks = prev.map(p => p.id === id ? { ...p, progress: 100, downloaded: true } : p);
          localStorage.setItem('offlinePacks', JSON.stringify(newPacks));
          return newPacks;
        });
      } else {
        setOfflinePacks(prev => prev.map(p => p.id === id ? { ...p, progress } : p));
      }
    }, 300);
  };

  const deletePack = (id: string) => {
     setOfflinePacks(prev => {
       const newPacks = prev.map(p => p.id === id ? { ...p, progress: 0, downloaded: false } : p);
       localStorage.setItem('offlinePacks', JSON.stringify(newPacks));
       return newPacks;
     });
  };

  return (
    <div className="min-h-screen bg-slate-900 text-slate-100 flex flex-col font-sans relative overflow-hidden select-none">

      {/* Background Gradients */}
      <div className="absolute top-0 left-0 w-full h-full overflow-hidden z-0 pointer-events-none">
        <div className={`absolute top-[-10%] left-[-10%] w-[500px] h-[500px] rounded-full blur-[100px] transition-colors duration-700 ${isOfflineActive ? 'bg-orange-600/20' : isConnected ? 'bg-green-600/20' : 'bg-blue-600/20'}`}></div>
        <div className={`absolute bottom-[-10%] right-[-10%] w-[500px] h-[500px] rounded-full blur-[100px] transition-colors duration-700 ${isOfflineActive ? 'bg-red-600/20' : 'bg-purple-600/20'}`} style={{ animationDelay: '2s' }}></div>
      </div>

      {/* Header */}
      <header className="z-10 p-4 border-b border-slate-700/50 glass-panel flex justify-between items-center sticky top-0">
        <div className="flex items-center gap-2">
          <div className={`w-8 h-8 rounded-lg flex items-center justify-center bg-gradient-to-br transition-colors duration-500 ${isOfflineActive ? 'from-orange-500 to-red-600' : isConnected ? 'from-green-500 to-emerald-600' : 'from-cyan-400 to-blue-600'}`}>
            <Globe size={18} className="text-white" />
          </div>
          <h1 className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-slate-100 to-slate-300">
            LinguaFlow
          </h1>
        </div>
        <div className="flex items-center gap-3">
          <button 
             onClick={() => setShowSettings(true)}
             className="p-2 rounded-full hover:bg-slate-800 transition-colors"
             title="Ayarlar"
          >
            <Settings size={20} className="text-slate-400" />
          </button>
          <div className={`flex items-center gap-2 px-3 py-1 rounded-full border transition-all duration-300 ${isOfflineActive ? 'border-orange-500/30 bg-orange-500/10' : 'border-blue-500/30 bg-blue-500/10'}`}>
             {isOfflineActive ? <WifiOff size={14} className="text-orange-400"/> : <Wifi size={14} className="text-blue-400"/>}
             <span className={`text-xs font-bold ${isOfflineActive ? 'text-orange-400' : 'text-blue-400'}`}>
                {isOfflineActive ? 'OFFLINE' : 'ONLINE'}
             </span>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 flex flex-col max-w-3xl w-full mx-auto p-4 z-10 relative h-[calc(100vh-80px)]">

        {/* Error Banner */}
        {error && (
          <div className="bg-red-500/10 border border-red-500/50 text-red-200 p-3 rounded-lg mb-4 text-sm flex justify-between items-center animate-fade-in">
            <span>{error}</span>
            <button onClick={() => setError(null)} className="text-white hover:text-red-200">&times;</button>
          </div>
        )}

        {/* Chat Area */}
        <div ref={chatContainerRef} className="flex-1 overflow-y-auto space-y-4 mb-4 pr-2 pb-24">
          {messages.length === 0 && !realtimeInput && (
            <div className="h-full flex flex-col items-center justify-center text-slate-500 opacity-60">
              {isOfflineActive ? <WifiOff size={48} className="mb-4 text-orange-600/50" /> : <Volume2 size={48} className="mb-4 text-blue-600/50" />}
              <p className="text-center font-medium">
                {isOfflineActive ? 'Çevrimdışı Mod' : 'Canlı Çeviri'}
              </p>
              <p className="text-sm mt-2 max-w-xs text-center px-4">
                {isConnected 
                  ? 'Konuşmak için aşağıdaki butona BASILI TUTUN.' 
                  : 'Başlamak için önce bağlantıyı açın.'}
              </p>
            </div>
          )}

          {messages.map((msg) => (
            <div key={msg.id} className={`flex ${msg.role === 'user' ? 'justify-start' : 'justify-end'}`}>
              <div className={`max-w-[80%] rounded-2xl p-4 shadow-lg ${
                msg.role === 'user' 
                  ? 'bg-slate-800 border border-slate-700 text-slate-200 rounded-bl-none' 
                  : isOfflineActive 
                    ? 'bg-gradient-to-br from-orange-700 to-red-800 text-white rounded-br-none border border-orange-500/20'
                    : 'bg-gradient-to-br from-blue-600 to-cyan-600 text-white rounded-br-none'
              }`}>
                <div className="text-xs opacity-50 mb-1 font-semibold tracking-wider flex justify-between items-center">
                  <span>{msg.role === 'user' ? 'TÜRKÇE' : targetLang.toUpperCase()}</span>
                  {isOfflineActive && msg.role === 'model' && <WifiOff size={10} />}
                </div>
                <p className="text-lg leading-relaxed">{msg.text}</p>
              </div>
            </div>
          ))}

          {/* Real-time Streaming Bubbles */}
          {(realtimeInput || realtimeOutput) && (
             <div className="space-y-2 opacity-90 animate-fade-in">
                {realtimeInput && (
                  <div className="flex justify-start">
                     <div className="max-w-[80%] rounded-2xl p-4 bg-slate-800/80 border border-blue-500/50 text-slate-100 rounded-bl-none shadow-glow">
                       <div className="text-xs opacity-50 mb-1 font-semibold text-blue-400 animate-pulse">DİNLİYOR...</div>
                       <p className="text-lg">{realtimeInput}</p>
                     </div>
                  </div>
                )}
                {realtimeOutput && (
                  <div className="flex justify-end">
                     <div className="max-w-[80%] rounded-2xl p-4 bg-blue-900/60 border border-blue-400/30 text-blue-100 rounded-br-none">
                       <div className="text-xs opacity-50 mb-1 font-semibold animate-pulse">ÇEVİRİYOR...</div>
                       <p className="text-lg">{realtimeOutput}</p>
                     </div>
                  </div>
                )}
             </div>
          )}
        </div>

        {/* Control Deck */}
        <div className="glass-panel rounded-3xl p-4 shadow-2xl border border-white/5 relative z-20">

          {/* Top Row: Language & Tools */}
          <div className="flex items-center justify-between mb-4">
             {/* Language Selector */}
            <div className="flex-1 mr-4">
              <label className="text-[10px] text-slate-500 ml-1 mb-1 block uppercase font-bold tracking-wider">Hedef</label>
              <div className="relative group">
                <select 
                  value={targetLang}
                  onChange={(e) => {
                    // Changing language might require reconnecting if we were using it in system prompt
                    if (isConnected && !isOfflineActive) stopConnection();
                    setTargetLang(e.target.value as TargetLanguage);
                  }}
                  className="w-full bg-slate-800/80 border border-slate-600 text-white text-sm rounded-lg px-3 py-2 appearance-none focus:outline-none focus:ring-1 focus:ring-blue-500"
                >
                  {Object.values(TargetLanguage).map((lang) => (
                    <option key={lang} value={lang}>{lang}</option>
                  ))}
                </select>
                <div className="absolute right-2 top-1/2 -translate-y-1/2 pointer-events-none text-slate-400">
                  <Globe size={14} />
                </div>
              </div>
            </div>

            {/* Clear History */}
            <div>
               <button 
                  onClick={() => {
                    setMessages([]);
                    setRealtimeInput('');
                    setRealtimeOutput('');
                  }} 
                  className="p-2 text-slate-400 hover:text-white transition-colors bg-slate-800/50 rounded-lg"
                  title="Temizle"
                >
                  <RotateCcw size={18} />
                </button>
            </div>
          </div>

          {/* Bottom Row: Controls */}
          <div className="flex items-center justify-between gap-6">

            {/* Connection Toggle (Power) */}
            <div className="flex flex-col items-center gap-1">
              <button
                onClick={toggleConnection}
                className={`w-12 h-12 rounded-full flex items-center justify-center transition-all duration-300 shadow-lg border-2 ${
                  isConnected 
                    ? 'bg-slate-800 border-green-500 text-green-500 shadow-green-500/20' 
                    : 'bg-slate-800 border-slate-600 text-slate-400'
                }`}
                title={isConnected ? "Bağlantıyı Kes" : "Bağlan"}
              >
                <Power size={20} />
              </button>
              <span className={`text-[10px] font-bold uppercase ${isConnected ? 'text-green-500' : 'text-slate-500'}`}>
                {isConnected ? 'Bağlı' : 'Kapalı'}
              </span>
            </div>

            {/* PUSH TO TALK BUTTON (Center) */}
            <div className="flex-1 flex justify-center -mt-8 relative">
                {/* Pulse Effect Background */}
                {isTransmitting && (
                   <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-28 h-28 bg-blue-500/30 rounded-full animate-ping pointer-events-none"></div>
                )}

                <button
                  onMouseDown={startTalking}
                  onMouseUp={stopTalking}
                  onMouseLeave={stopTalking}
                  onTouchStart={(e) => { e.preventDefault(); startTalking(); }}
                  onTouchEnd={(e) => { e.preventDefault(); stopTalking(); }}
                  disabled={!isConnected}
                  className={`w-24 h-24 rounded-full flex flex-col items-center justify-center transition-all duration-150 shadow-2xl relative z-10 select-none touch-none ${
                    !isConnected
                      ? 'bg-slate-700 opacity-50 cursor-not-allowed shadow-none'
                      : isTransmitting
                        ? 'bg-blue-600 scale-95 shadow-inner ring-4 ring-blue-400/50'
                        : isOfflineActive
                          ? 'bg-gradient-to-b from-orange-500 to-orange-600 hover:scale-105 shadow-orange-500/30'
                          : 'bg-gradient-to-b from-blue-500 to-blue-600 hover:scale-105 shadow-blue-500/30'
                  }`}
                >
                   {isTransmitting ? (
                      <Mic size={36} className="text-white animate-pulse" />
                   ) : (
                      <Mic size={36} className="text-white/90" />
                   )}
                   <span className="text-[10px] font-bold text-white/80 mt-1 uppercase tracking-wide">
                     {isTransmitting ? 'Dinliyor' : 'Bas Konuş'}
                   </span>
                </button>
            </div>

            {/* Visualizer (Right) */}
            <div className="w-12 h-12 bg-black/40 rounded-xl overflow-hidden border border-white/10 flex items-center justify-center">
               {isConnected ? (
                  isTransmitting ? (
                    <AudioVisualizer analyser={inputAnalyserRef.current} isActive={true} color={isOfflineActive ? '#f97316' : '#3b82f6'} />
                  ) : (
                    <div className="w-full h-1 bg-slate-700 mx-2 rounded-full"></div>
                  )
               ) : (
                 <WifiOff size={16} className="text-slate-600"/>
               )}
            </div>

          </div>
        </div>
      </main>

      {/* Settings Modal */}
      {showSettings && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm">
          <div className="bg-slate-900 border border-slate-700 rounded-2xl w-full max-w-md shadow-2xl overflow-hidden flex flex-col max-h-[90vh]">
             <div className="p-4 border-b border-slate-800 flex justify-between items-center bg-slate-800/50">
                <h2 className="text-lg font-bold flex items-center gap-2">
                  <Settings size={20} className="text-blue-400"/> Ayarlar
                </h2>
                <button onClick={() => setShowSettings(false)} className="text-slate-400 hover:text-white">
                  <X size={24} />
                </button>
             </div>

             <div className="p-6 overflow-y-auto">

               {/* Mode Toggle */}
               <div className="mb-8">
                 <h3 className="text-sm font-semibold text-slate-400 uppercase tracking-wider mb-3">Bağlantı Tercihi</h3>
                 <div className="flex items-center justify-between bg-slate-800/50 p-4 rounded-xl border border-slate-700">
                    <div className="flex items-center gap-3">
                       {forceOfflineMode ? <WifiOff size={20} className="text-orange-400"/> : <Zap size={20} className="text-blue-400"/>}
                       <div>
                         <div className="font-medium">Çevrimdışı Mod</div>
                         <div className="text-xs text-slate-400">Offline çeviriye zorla</div>
                       </div>
                    </div>
                    <button 
                       onClick={() => {
                         if (isConnected) stopConnection();
                         setForceOfflineMode(!forceOfflineMode);
                       }}
                       className={`w-12 h-6 rounded-full p-1 transition-colors ${forceOfflineMode ? 'bg-orange-500' : 'bg-slate-600'}`}
                    >
                       <div className={`w-4 h-4 rounded-full bg-white transition-transform ${forceOfflineMode ? 'translate-x-6' : ''}`}></div>
                    </button>
                 </div>
               </div>

               {/* Offline Packs */}
               <div>
                 <h3 className="text-sm font-semibold text-slate-400 uppercase tracking-wider mb-3">Çevrimdışı Paketler</h3>
                 <div className="space-y-3">
                    {offlinePacks.map(pack => (
                       <div key={pack.id} className="bg-slate-800/50 p-3 rounded-xl border border-slate-700 flex items-center justify-between">
                          <div className="flex-1">
                             <div className="flex items-center gap-2">
                               <span className="font-semibold">{pack.pair}</span>
                               <span className="text-xs bg-slate-700 px-1.5 py-0.5 rounded">{pack.size}</span>
                             </div>
                             <div className="text-sm text-slate-400">{pack.name}</div>
                             {pack.progress > 0 && pack.progress < 100 && (
                               <div className="w-full h-1 bg-slate-700 mt-2 rounded-full overflow-hidden">
                                  <div className="h-full bg-blue-500 transition-all" style={{width: `${pack.progress}%`}}></div>
                               </div>
                             )}
                          </div>

                          <div className="ml-4">
                             {pack.downloaded ? (
                               <button 
                                 onClick={() => deletePack(pack.id)}
                                 className="w-10 h-10 rounded-full bg-slate-700/50 hover:bg-red-500/20 hover:text-red-400 flex items-center justify-center text-green-400 transition-colors"
                                 title="Paketi Sil"
                               >
                                  <div className="group relative">
                                    <Check size={20} className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 group-hover:opacity-0 transition-opacity" />
                                    <Trash2 size={20} className="opacity-0 group-hover:opacity-100 transition-opacity" />
                                  </div>
                               </button>
                             ) : pack.progress > 0 ? (
                               <div className="text-xs text-blue-400 font-bold">{pack.progress}%</div>
                             ) : (
                               <button 
                                 onClick={() => downloadPack(pack.id)}
                                 className="w-10 h-10 rounded-full bg-slate-700 hover:bg-blue-600 transition-colors flex items-center justify-center text-white"
                                 title="İndir"
                               >
                                 <Download size={20} />
                               </button>
                             )}
                          </div>
                       </div>
                    ))}
                 </div>
               </div>
             </div>
          </div>
        </div>
      )}

    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';
import { TargetLanguage, ChatMessage, OfflinePack } from './types';
import { float32To16BitPCM, arrayBufferToBase64, base64ToArrayBuffer, pcm16ToFloat32 } from './utils/audioUtils';
import AudioVisualizer from './components/AudioVisualizer';
import { Mic, MicOff, Globe, Settings, Volume2, RotateCcw, Wifi, WifiOff, Download, Check, Trash2, X, Power, Zap, Pause } from 'lucide-react';

// Live API Configuration
const MODEL_NAME = 'gemini-2.5-flash-native-audio-preview-09-2025';
const INPUT_SAMPLE_RATE = 16000;
const OUTPUT_SAMPLE_RATE = 24000;

// Mock Offline Packs
const INITIAL_PACKS: OfflinePack[] = [
  { id: 'tr-en', pair: 'TR ↔ EN', name: 'İngilizce Paketi', size: '45 MB', downloaded: false, progress: 0 },
  { id: 'tr-nl', pair: 'TR ↔ NL', name: 'Hollandaca Paketi', size: '42 MB', downloaded: false, progress: 0 },
  { id: 'tr-ar', pair: 'TR ↔ AR', name: 'Arapça Paketi', size: '50 MB', downloaded: false, progress: 0 },
  { id: 'tr-ru', pair: 'TR ↔ RU', name: 'Rusça Paketi', size: '48 MB', downloaded: false, progress: 0 },
];

const App: React.FC = () => {
  const [targetLang, setTargetLang] = useState<TargetLanguage>(TargetLanguage.ENGLISH);
  // isConnected: WebSocket/Session is open
  const [isConnected, setIsConnected] = useState(false);
  // isTransmitting: Toggle state for microphone (Listening or Paused)
  const [isTransmitting, setIsTransmitting] = useState(false);

  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [error, setError] = useState<string | null>(null);

  // Real-time Display States
  const [realtimeInput, setRealtimeInput] = useState('');
  const [realtimeOutput, setRealtimeOutput] = useState('');

  // Offline / Network State
  const [isOnline, setIsOnline] = useState(navigator.onLine);
  const [forceOfflineMode, setForceOfflineMode] = useState(false);
  const [showSettings, setShowSettings] = useState(false);
  const [offlinePacks, setOfflinePacks] = useState<OfflinePack[]>(INITIAL_PACKS);

  // Audio Context Refs
  const inputAudioContextRef = useRef<AudioContext | null>(null);
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const inputAnalyserRef = useRef<AnalyserNode | null>(null);
  const outputAnalyserRef = useRef<AnalyserNode | null>(null);
  const mediaStreamRef = useRef<MediaStream | null>(null);
  const scriptProcessorRef = useRef<ScriptProcessorNode | null>(null); // Keep reference to prevent GC

  // Logic Refs
  const aiClientRef = useRef<GoogleGenAI | null>(null);
  const sessionPromiseRef = useRef<Promise<any> | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const isTransmittingRef = useRef(false); // Ref for audio processor access

  // Transcription Buffers
  const currentInputTranscription = useRef('');
  const currentOutputTranscription = useRef('');

  // Offline Recognition Ref
  const recognitionRef = useRef<any>(null);

  // 1. Initialize Gemini Client & Network Listeners
  useEffect(() => {
    if (process.env.API_KEY) {
      aiClientRef.current = new GoogleGenAI({ apiKey: process.env.API_KEY });
    } else {
      setError("API Anahtarı bulunamadı.");
    }

    // Network Listeners
    const handleOnline = () => setIsOnline(true);
    const handleOffline = () => {
      setIsOnline(false);
      stopConnection(); // Stop Gemini if network drops
    };

    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);

    // Load packs from localStorage (Simulation)
    const savedPacks = localStorage.getItem('offlinePacks');
    if (savedPacks) {
      setOfflinePacks(JSON.parse(savedPacks));
    }

    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
    };
  }, []);

  const isOfflineActive = !isOnline || forceOfflineMode;

  // 2. Audio Processing Helper: Resample and Send (Online Only)
  const processAudioInput = useCallback((inputData: Float32Array) => {
    // Only send data if connected AND toggled ON
    if (!sessionPromiseRef.current || !isTransmittingRef.current) return;

    const pcmData = float32To16BitPCM(inputData);
    const base64Data = arrayBufferToBase64(pcmData);

    sessionPromiseRef.current.then((session) => {
      session.sendRealtimeInput({
        media: {
          mimeType: `audio/pcm;rate=${INPUT_SAMPLE_RATE}`,
          data: base64Data,
        },
      });
    });
  }, []);

  // 3. Connect to Live API (Session Start)
  const toggleConnection = async () => {
    if (isConnected) {
      stopConnection();
      return;
    }

    // Offline Mode Logic
    if (isOfflineActive) {
      setIsConnected(true);
      return;
    }

    if (!aiClientRef.current) return;
    setError(null);

    try {
      // Setup Audio Input
      const stream = await navigator.mediaDevices.getUserMedia({ audio: {
        sampleRate: INPUT_SAMPLE_RATE,
        channelCount: 1,
        echoCancellation: true,
        noiseSuppression: true,
        autoGainControl: true
      }});
      mediaStreamRef.current = stream;

      const audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ 
        sampleRate: INPUT_SAMPLE_RATE 
      });
      inputAudioContextRef.current = audioCtx;

      const source = audioCtx.createMediaStreamSource(stream);
      const analyser = audioCtx.createAnalyser();
      analyser.fftSize = 256;
      inputAnalyserRef.current = analyser;

      // Create ScriptProcessor
      const scriptProcessor = audioCtx.createScriptProcessor(4096, 1, 1);
      scriptProcessorRef.current = scriptProcessor; // CRITICAL: Save to ref to prevent Garbage Collection

      scriptProcessor.onaudioprocess = (e) => {
        const inputData = e.inputBuffer.getChannelData(0);
        processAudioInput(inputData);
      };

      source.connect(analyser);
      analyser.connect(scriptProcessor);
      scriptProcessor.connect(audioCtx.destination);

      // Setup Audio Output
      const outCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ 
        sampleRate: OUTPUT_SAMPLE_RATE 
      });
      outputAudioContextRef.current = outCtx;
      const outAnalyser = outCtx.createAnalyser();
      outAnalyser.fftSize = 256;
      outputAnalyserRef.current = outAnalyser;
      outAnalyser.connect(outCtx.destination);

      const systemPrompt = `You are a world-class simultaneous interpreter. 
      Your task is to translate spoken Turkish into ${targetLang} immediately.
      Simply output the translated audio in ${targetLang}.
      Do not add any introductory text or filler words.
      Also provide the text transcriptions for both input and output.`;

      sessionPromiseRef.current = aiClientRef.current.live.connect({
        model: MODEL_NAME,
        config: {
          systemInstruction: systemPrompt,
          responseModalities: [Modality.AUDIO],
          inputAudioTranscription: {},
          outputAudioTranscription: {},
        },
        callbacks: {
          onopen: () => {
            console.log("Gemini Live Session Opened");
            setIsConnected(true);
            // Auto-start transmitting when connected for convenience? 
            // Let's keep it manual as per "toggle" request to control when to start.
            nextStartTimeRef.current = 0;
            setRealtimeInput('');
            setRealtimeOutput('');
          },
          onmessage: async (msg: LiveServerMessage) => {
            if (msg.serverContent?.inputTranscription) {
               currentInputTranscription.current += msg.serverContent.inputTranscription.text;
               setRealtimeInput(currentInputTranscription.current);
            }
            if (msg.serverContent?.outputTranscription) {
               currentOutputTranscription.current += msg.serverContent.outputTranscription.text;
               setRealtimeOutput(currentOutputTranscription.current);
            }

            if (msg.serverContent?.turnComplete) {
               const inputTx = currentInputTranscription.current.trim();
               const outputTx = currentOutputTranscription.current.trim();

               if (inputTx || outputTx) {
                 addMessage('user', inputTx || '(Sessizlik)');
                 addMessage('model', outputTx || '...');
               }

               currentInputTranscription.current = '';
               currentOutputTranscription.current = '';
               setRealtimeInput('');
               setRealtimeOutput('');
            }

            const audioData = msg.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
            if (audioData) {
               playAudioResponse(audioData);
            }
          },
          onclose: () => {
            console.log("Session Closed");
            stopConnection();
          },
          onerror: (err) => {
            console.error("Session Error", err);
            setError("Bağlantı hatası. Tekrar bağlanın.");
            stopConnection();
          }
        }
      });
    } catch (e: any) {
      console.error(e);
      setError(`Başlatma hatası: ${e.message}`);
      stopConnection();
    }
  };

  // 4. Toggle Logic (New Interaction)
  const toggleMicrophone = async () => {
    if (!isConnected) {
       // Optional: Add visual cue that connection is needed
       return;
    }

    const newState = !isTransmitting;
    setIsTransmitting(newState);
    isTransmittingRef.current = newState;

    if (newState) {
        // RESUME AudioContext if suspended (Browser Auto-play policy)
        if (inputAudioContextRef.current?.state === 'suspended') {
            await inputAudioContextRef.current.resume();
        }

        if (isOfflineActive) {
            startOfflineRecognition();
        }
    } else {
        if (isOfflineActive) {
            stopOfflineRecognition();
        }
    }
  };

  // 5. Offline Logic (Web Speech API)
  const startOfflineRecognition = () => {
    if (!('webkitSpeechRecognition' in window)) {
      setError("Bu tarayıcıda çevrimdışı ses tanıma desteklenmiyor.");
      return;
    }

    if (recognitionRef.current) {
      try { recognitionRef.current.stop(); } catch(e){}
    }

    try {
      const Recognition = (window as any).webkitSpeechRecognition;
      const recognition = new Recognition();
      recognition.lang = 'tr-TR'; 
      recognition.continuous = true; 
      recognition.interimResults = true; 

      recognition.onstart = () => {
        setRealtimeInput('');
      };

      recognition.onresult = (event: any) => {
        let interimTranscript = '';
        let finalTranscript = '';

        for (let i = event.resultIndex; i < event.results.length; ++i) {
          if (event.results[i].isFinal) {
            finalTranscript += event.results[i][0].transcript;
          } else {
            interimTranscript += event.results[i][0].transcript;
          }
        }
        setRealtimeInput(finalTranscript || interimTranscript);
      };

      recognition.onerror = (event: any) => {
        if (event.error !== 'no-speech') {
             console.error("Offline Speech Error", event.error);
        }
      };

      recognitionRef.current = recognition;
      recognition.start();

    } catch (e) {
      console.error(e);
    }
  };

  const stopOfflineRecognition = () => {
    if (recognitionRef.current) {
      recognitionRef.current.stop();

      // Trigger translation on stop
      setTimeout(() => {
        const text = realtimeInput.trim();
        if (text) {
           addMessage('user', text);
           setRealtimeInput('');
           const translationMock = `(Çevrimdışı ${targetLang}) ${text}`; 
           setTimeout(() => {
             addMessage('model', translationMock);
             speakOffline(text, targetLang);
           }, 500);
        }
      }, 500);
    }
  };

  const speakOffline = (text: string, lang: TargetLanguage) => {
    if ('speechSynthesis' in window) {
      const utterance = new SpeechSynthesisUtterance(text); 
      const langMap: Record<TargetLanguage, string> = {
        [TargetLanguage.ENGLISH]: 'en-US',
        [TargetLanguage.DUTCH]: 'nl-NL',
        [TargetLanguage.ARABIC]: 'ar-SA',
        [TargetLanguage.RUSSIAN]: 'ru-RU'
      };
      utterance.lang = langMap[lang];
      window.speechSynthesis.speak(utterance);
    }
  };

  // 6. Play Output Audio (Online)
  const playAudioResponse = async (base64Audio: string) => {
    if (!outputAudioContextRef.current || !outputAnalyserRef.current) return;
    const ctx = outputAudioContextRef.current;
    try {
      const arrayBuffer = base64ToArrayBuffer(base64Audio);
      const float32Data = pcm16ToFloat32(arrayBuffer);
      const audioBuffer = ctx.createBuffer(1, float32Data.length, OUTPUT_SAMPLE_RATE);
      audioBuffer.getChannelData(0).set(float32Data);
      const source = ctx.createBufferSource();
      source.buffer = audioBuffer;
      source.connect(outputAnalyserRef.current);
      const currentTime = ctx.currentTime;
      const startTime = Math.max(nextStartTimeRef.current, currentTime);
      source.start(startTime);
      nextStartTimeRef.current = startTime + audioBuffer.duration;
      source.onended = () => sourcesRef.current.delete(source);
      sourcesRef.current.add(source);
    } catch (err) {
      console.error("Audio playback error", err);
    }
  };

  // 7. Helpers & Cleanup
  const addMessage = (role: 'user' | 'model', text: string) => {
    setMessages(prev => [...prev, { 
      id: Date.now().toString() + Math.random(), 
      role, 
      text, 
      timestamp: new Date(), 
      isFinal: true 
    }]);
  };

  const stopConnection = useCallback(() => {
    setIsConnected(false);
    setIsTransmitting(false);
    isTransmittingRef.current = false;
    setRealtimeInput('');
    setRealtimeOutput('');

    // Stop Tracks
    if (mediaStreamRef.current) {
      mediaStreamRef.current.getTracks().forEach(track => track.stop());
      mediaStreamRef.current = null;
    }

    // Disconnect ScriptProcessor
    if (scriptProcessorRef.current) {
      scriptProcessorRef.current.disconnect();
      scriptProcessorRef.current = null;
    }

    // Close Contexts
    if (inputAudioContextRef.current) {
      inputAudioContextRef.current.close();
      inputAudioContextRef.current = null;
    }
    if (outputAudioContextRef.current) {
      outputAudioContextRef.current.close();
      outputAudioContextRef.current = null;
    }
    sessionPromiseRef.current = null;

    if (recognitionRef.current) {
      recognitionRef.current.stop();
      recognitionRef.current = null;
    }
  }, []);

  const chatContainerRef = useRef<HTMLDivElement>(null);
  useEffect(() => {
    if (chatContainerRef.current) {
      chatContainerRef.current.scrollTop = chatContainerRef.current.scrollHeight;
    }
  }, [messages, realtimeInput, realtimeOutput]);

  // Settings Logic
  const downloadPack = (id: string) => {
    setOfflinePacks(prev => prev.map(p => p.id === id ? { ...p, progress: 5 } : p));
    let progress = 5;
    const interval = setInterval(() => {
      progress += Math.floor(Math.random() * 15);
      if (progress >= 100) {
        progress = 100;
        clearInterval(interval);
        setOfflinePacks(prev => {
          const newPacks = prev.map(p => p.id === id ? { ...p, progress: 100, downloaded: true } : p);
          localStorage.setItem('offlinePacks', JSON.stringify(newPacks));
          return newPacks;
        });
      } else {
        setOfflinePacks(prev => prev.map(p => p.id === id ? { ...p, progress } : p));
      }
    }, 300);
  };

  const deletePack = (id: string) => {
     setOfflinePacks(prev => {
       const newPacks = prev.map(p => p.id === id ? { ...p, progress: 0, downloaded: false } : p);
       localStorage.setItem('offlinePacks', JSON.stringify(newPacks));
       return newPacks;
     });
  };

  return (
    <div className="min-h-screen bg-slate-900 text-slate-100 flex flex-col font-sans relative overflow-hidden select-none">

      {/* Background Gradients */}
      <div className="absolute top-0 left-0 w-full h-full overflow-hidden z-0 pointer-events-none">
        <div className={`absolute top-[-10%] left-[-10%] w-[500px] h-[500px] rounded-full blur-[100px] transition-colors duration-700 ${isOfflineActive ? 'bg-orange-600/20' : isConnected ? 'bg-green-600/20' : 'bg-blue-600/20'}`}></div>
        <div className={`absolute bottom-[-10%] right-[-10%] w-[500px] h-[500px] rounded-full blur-[100px] transition-colors duration-700 ${isOfflineActive ? 'bg-red-600/20' : 'bg-purple-600/20'}`} style={{ animationDelay: '2s' }}></div>
      </div>

      {/* Header */}
      <header className="z-10 p-4 border-b border-slate-700/50 glass-panel flex justify-between items-center sticky top-0">
        <div className="flex items-center gap-2">
          <div className={`w-8 h-8 rounded-lg flex items-center justify-center bg-gradient-to-br transition-colors duration-500 ${isOfflineActive ? 'from-orange-500 to-red-600' : isConnected ? 'from-green-500 to-emerald-600' : 'from-cyan-400 to-blue-600'}`}>
            <Globe size={18} className="text-white" />
          </div>
          <h1 className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-slate-100 to-slate-300">
            LinguaFlow
          </h1>
        </div>
        <div className="flex items-center gap-3">
          <button 
             onClick={() => setShowSettings(true)}
             className="p-2 rounded-full hover:bg-slate-800 transition-colors"
             title="Ayarlar"
          >
            <Settings size={20} className="text-slate-400" />
          </button>
          <div className={`flex items-center gap-2 px-3 py-1 rounded-full border transition-all duration-300 ${isOfflineActive ? 'border-orange-500/30 bg-orange-500/10' : 'border-blue-500/30 bg-blue-500/10'}`}>
             {isOfflineActive ? <WifiOff size={14} className="text-orange-400"/> : <Wifi size={14} className="text-blue-400"/>}
             <span className={`text-xs font-bold ${isOfflineActive ? 'text-orange-400' : 'text-blue-400'}`}>
                {isOfflineActive ? 'OFFLINE' : 'ONLINE'}
             </span>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 flex flex-col max-w-3xl w-full mx-auto p-4 z-10 relative h-[calc(100vh-80px)]">

        {/* Error Banner */}
        {error && (
          <div className="bg-red-500/10 border border-red-500/50 text-red-200 p-3 rounded-lg mb-4 text-sm flex justify-between items-center animate-fade-in">
            <span>{error}</span>
            <button onClick={() => setError(null)} className="text-white hover:text-red-200">&times;</button>
          </div>
        )}

        {/* Chat Area */}
        <div ref={chatContainerRef} className="flex-1 overflow-y-auto space-y-4 mb-4 pr-2 pb-24">
          {messages.length === 0 && !realtimeInput && (
            <div className="h-full flex flex-col items-center justify-center text-slate-500 opacity-60">
              {isOfflineActive ? <WifiOff size={48} className="mb-4 text-orange-600/50" /> : <Volume2 size={48} className="mb-4 text-blue-600/50" />}
              <p className="text-center font-medium">
                {isOfflineActive ? 'Çevrimdışı Mod' : 'Canlı Çeviri'}
              </p>
              <p className="text-sm mt-2 max-w-xs text-center px-4">
                {isConnected 
                  ? 'Konuşmayı başlatmak için Mikrofona dokunun.' 
                  : 'Başlamak için önce bağlantıyı açın (Güç Butonu).'}
              </p>
            </div>
          )}

          {messages.map((msg) => (
            <div key={msg.id} className={`flex ${msg.role === 'user' ? 'justify-start' : 'justify-end'}`}>
              <div className={`max-w-[80%] rounded-2xl p-4 shadow-lg ${
                msg.role === 'user' 
                  ? 'bg-slate-800 border border-slate-700 text-slate-200 rounded-bl-none' 
                  : isOfflineActive 
                    ? 'bg-gradient-to-br from-orange-700 to-red-800 text-white rounded-br-none border border-orange-500/20'
                    : 'bg-gradient-to-br from-blue-600 to-cyan-600 text-white rounded-br-none'
              }`}>
                <div className="text-xs opacity-50 mb-1 font-semibold tracking-wider flex justify-between items-center">
                  <span>{msg.role === 'user' ? 'TÜRKÇE' : targetLang.toUpperCase()}</span>
                  {isOfflineActive && msg.role === 'model' && <WifiOff size={10} />}
                </div>
                <p className="text-lg leading-relaxed">{msg.text}</p>
              </div>
            </div>
          ))}

          {/* Real-time Streaming Bubbles */}
          {(realtimeInput || realtimeOutput) && (
             <div className="space-y-2 opacity-90 animate-fade-in">
                {realtimeInput && (
                  <div className="flex justify-start">
                     <div className="max-w-[80%] rounded-2xl p-4 bg-slate-800/80 border border-blue-500/50 text-slate-100 rounded-bl-none shadow-glow">
                       <div className="text-xs opacity-50 mb-1 font-semibold text-blue-400 animate-pulse">DİNLİYOR...</div>
                       <p className="text-lg">{realtimeInput}</p>
                     </div>
                  </div>
                )}
                {realtimeOutput && (
                  <div className="flex justify-end">
                     <div className="max-w-[80%] rounded-2xl p-4 bg-blue-900/60 border border-blue-400/30 text-blue-100 rounded-br-none">
                       <div className="text-xs opacity-50 mb-1 font-semibold animate-pulse">ÇEVİRİYOR...</div>
                       <p className="text-lg">{realtimeOutput}</p>
                     </div>
                  </div>
                )}
             </div>
          )}
        </div>

        {/* Control Deck */}
        <div className="glass-panel rounded-3xl p-4 shadow-2xl border border-white/5 relative z-20">

          {/* Top Row: Language & Tools */}
          <div className="flex items-center justify-between mb-4">
             {/* Language Selector */}
            <div className="flex-1 mr-4">
              <label className="text-[10px] text-slate-500 ml-1 mb-1 block uppercase font-bold tracking-wider">Hedef</label>
              <div className="relative group">
                <select 
                  value={targetLang}
                  onChange={(e) => {
                    // Changing language might require reconnecting if we were using it in system prompt
                    if (isConnected && !isOfflineActive) stopConnection();
                    setTargetLang(e.target.value as TargetLanguage);
                  }}
                  className="w-full bg-slate-800/80 border border-slate-600 text-white text-sm rounded-lg px-3 py-2 appearance-none focus:outline-none focus:ring-1 focus:ring-blue-500"
                >
                  {Object.values(TargetLanguage).map((lang) => (
                    <option key={lang} value={lang}>{lang}</option>
                  ))}
                </select>
                <div className="absolute right-2 top-1/2 -translate-y-1/2 pointer-events-none text-slate-400">
                  <Globe size={14} />
                </div>
              </div>
            </div>

            {/* Clear History */}
            <div>
               <button 
                  onClick={() => {
                    setMessages([]);
                    setRealtimeInput('');
                    setRealtimeOutput('');
                  }} 
                  className="p-2 text-slate-400 hover:text-white transition-colors bg-slate-800/50 rounded-lg"
                  title="Temizle"
                >
                  <RotateCcw size={18} />
                </button>
            </div>
          </div>

          {/* Bottom Row: Controls */}
          <div className="flex items-center justify-between gap-6">

            {/* Connection Toggle (Power) */}
            <div className="flex flex-col items-center gap-1">
              <button
                onClick={toggleConnection}
                className={`w-12 h-12 rounded-full flex items-center justify-center transition-all duration-300 shadow-lg border-2 ${
                  isConnected 
                    ? 'bg-slate-800 border-green-500 text-green-500 shadow-green-500/20' 
                    : 'bg-slate-800 border-slate-600 text-slate-400'
                }`}
                title={isConnected ? "Bağlantıyı Kes" : "Bağlan"}
              >
                <Power size={20} />
              </button>
              <span className={`text-[10px] font-bold uppercase ${isConnected ? 'text-green-500' : 'text-slate-500'}`}>
                {isConnected ? 'Bağlı' : 'Kapalı'}
              </span>
            </div>

            {/* MICROPHONE TOGGLE BUTTON (Center) */}
            <div className="flex-1 flex justify-center -mt-8 relative">
                {/* Pulse Effect Background */}
                {isTransmitting && (
                   <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-28 h-28 bg-blue-500/30 rounded-full animate-ping pointer-events-none"></div>
                )}

                <button
                  onClick={toggleMicrophone}
                  disabled={!isConnected}
                  className={`w-24 h-24 rounded-full flex flex-col items-center justify-center transition-all duration-200 shadow-2xl relative z-10 select-none ${
                    !isConnected
                      ? 'bg-slate-700 opacity-50 cursor-not-allowed shadow-none'
                      : isTransmitting
                        ? 'bg-red-600 hover:bg-red-500 scale-105 shadow-red-500/40 ring-4 ring-red-400/20'
                        : isOfflineActive
                          ? 'bg-gradient-to-b from-orange-500 to-orange-600 hover:scale-105 shadow-orange-500/30'
                          : 'bg-gradient-to-b from-blue-500 to-blue-600 hover:scale-105 shadow-blue-500/30'
                  }`}
                >
                   {isTransmitting ? (
                      <Pause size={36} className="text-white animate-pulse" />
                   ) : (
                      <Mic size={36} className="text-white/90" />
                   )}
                   <span className="text-[10px] font-bold text-white/80 mt-1 uppercase tracking-wide">
                     {isTransmitting ? 'Dinliyor' : 'Başlat'}
                   </span>
                </button>
            </div>

            {/* Visualizer (Right) */}
            <div className="w-12 h-12 bg-black/40 rounded-xl overflow-hidden border border-white/10 flex items-center justify-center">
               {isConnected ? (
                  isTransmitting ? (
                    <AudioVisualizer analyser={inputAnalyserRef.current} isActive={true} color={isOfflineActive ? '#f97316' : '#3b82f6'} />
                  ) : (
                    <div className="w-full h-1 bg-slate-700 mx-2 rounded-full"></div>
                  )
               ) : (
                 <WifiOff size={16} className="text-slate-600"/>
               )}
            </div>

          </div>
        </div>
      </main>

      {/* Settings Modal */}
      {showSettings && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm">
          <div className="bg-slate-900 border border-slate-700 rounded-2xl w-full max-w-md shadow-2xl overflow-hidden flex flex-col max-h-[90vh]">
             <div className="p-4 border-b border-slate-800 flex justify-between items-center bg-slate-800/50">
                <h2 className="text-lg font-bold flex items-center gap-2">
                  <Settings size={20} className="text-blue-400"/> Ayarlar
                </h2>
                <button onClick={() => setShowSettings(false)} className="text-slate-400 hover:text-white">
                  <X size={24} />
                </button>
             </div>

             <div className="p-6 overflow-y-auto">

               {/* Mode Toggle */}
               <div className="mb-8">
                 <h3 className="text-sm font-semibold text-slate-400 uppercase tracking-wider mb-3">Bağlantı Tercihi</h3>
                 <div className="flex items-center justify-between bg-slate-800/50 p-4 rounded-xl border border-slate-700">
                    <div className="flex items-center gap-3">
                       {forceOfflineMode ? <WifiOff size={20} className="text-orange-400"/> : <Zap size={20} className="text-blue-400"/>}
                       <div>
                         <div className="font-medium">Çevrimdışı Mod</div>
                         <div className="text-xs text-slate-400">Offline çeviriye zorla</div>
                       </div>
                    </div>
                    <button 
                       onClick={() => {
                         if (isConnected) stopConnection();
                         setForceOfflineMode(!forceOfflineMode);
                       }}
                       className={`w-12 h-6 rounded-full p-1 transition-colors ${forceOfflineMode ? 'bg-orange-500' : 'bg-slate-600'}`}
                    >
                       <div className={`w-4 h-4 rounded-full bg-white transition-transform ${forceOfflineMode ? 'translate-x-6' : ''}`}></div>
                    </button>
                 </div>
               </div>

               {/* Offline Packs */}
               <div>
                 <h3 className="text-sm font-semibold text-slate-400 uppercase tracking-wider mb-3">Çevrimdışı Paketler</h3>
                 <div className="space-y-3">
                    {offlinePacks.map(pack => (
                       <div key={pack.id} className="bg-slate-800/50 p-3 rounded-xl border border-slate-700 flex items-center justify-between">
                          <div className="flex-1">
                             <div className="flex items-center gap-2">
                               <span className="font-semibold">{pack.pair}</span>
                               <span className="text-xs bg-slate-700 px-1.5 py-0.5 rounded">{pack.size}</span>
                             </div>
                             <div className="text-sm text-slate-400">{pack.name}</div>
                             {pack.progress > 0 && pack.progress < 100 && (
                               <div className="w-full h-1 bg-slate-700 mt-2 rounded-full overflow-hidden">
                                  <div className="h-full bg-blue-500 transition-all" style={{width: `${pack.progress}%`}}></div>
                               </div>
                             )}
                          </div>

                          <div className="ml-4">
                             {pack.downloaded ? (
                               <button 
                                 onClick={() => deletePack(pack.id)}
                                 className="w-10 h-10 rounded-full bg-slate-700/50 hover:bg-red-500/20 hover:text-red-400 flex items-center justify-center text-green-400 transition-colors"
                                 title="Paketi Sil"
                               >
                                  <div className="group relative">
                                    <Check size={20} className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 group-hover:opacity-0 transition-opacity" />
                                    <Trash2 size={20} className="opacity-0 group-hover:opacity-100 transition-opacity" />
                                  </div>
                               </button>
                             ) : pack.progress > 0 ? (
                               <div className="text-xs text-blue-400 font-bold">{pack.progress}%</div>
                             ) : (
                               <button 
                                 onClick={() => downloadPack(pack.id)}
                                 className="w-10 h-10 rounded-full bg-slate-700 hover:bg-blue-600 transition-colors flex items-center justify-center text-white"
                                 title="İndir"
                               >
                                 <Download size={20} />
                               </button>
                             )}
                          </div>
                       </div>
                    ))}
                 </div>
               </div>
             </div>
          </div>
        </div>
      )}

    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';
import { TargetLanguage, ChatMessage, OfflinePack } from './types';
import { float32To16BitPCM, arrayBufferToBase64, base64ToArrayBuffer, pcm16ToFloat32 } from './utils/audioUtils';
import AudioVisualizer from './components/AudioVisualizer';
import { Mic, Globe, Settings, RotateCcw, Wifi, WifiOff, Download, Check, Trash2, X, Power, Zap, Pause, ChevronDown, Sparkles } from 'lucide-react';

// Live API Configuration
const MODEL_NAME = 'gemini-2.5-flash-native-audio-preview-09-2025';
const INPUT_SAMPLE_RATE = 16000;
const OUTPUT_SAMPLE_RATE = 24000;

// Mock Offline Packs
const INITIAL_PACKS: OfflinePack[] = [
  { id: 'tr-en', pair: 'TR ↔ EN', name: 'İngilizce', size: '45 MB', downloaded: false, progress: 0 },
  { id: 'tr-nl', pair: 'TR ↔ NL', name: 'Hollandaca', size: '42 MB', downloaded: false, progress: 0 },
  { id: 'tr-ar', pair: 'TR ↔ AR', name: 'Arapça', size: '50 MB', downloaded: false, progress: 0 },
  { id: 'tr-ru', pair: 'TR ↔ RU', name: 'Rusça', size: '48 MB', downloaded: false, progress: 0 },
];

const App: React.FC = () => {
  const [targetLang, setTargetLang] = useState<TargetLanguage>(TargetLanguage.ENGLISH);
  const [isConnected, setIsConnected] = useState(false);
  const [isTransmitting, setIsTransmitting] = useState(false);

  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [error, setError] = useState<string | null>(null);

  // Real-time Display States
  const [realtimeInput, setRealtimeInput] = useState('');
  const [realtimeOutput, setRealtimeOutput] = useState('');

  // Offline / Network State
  const [isOnline, setIsOnline] = useState(navigator.onLine);
  const [forceOfflineMode, setForceOfflineMode] = useState(false);
  const [showSettings, setShowSettings] = useState(false);
  const [offlinePacks, setOfflinePacks] = useState<OfflinePack[]>(INITIAL_PACKS);

  // Audio Context Refs
  const inputAudioContextRef = useRef<AudioContext | null>(null);
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const inputAnalyserRef = useRef<AnalyserNode | null>(null);
  const outputAnalyserRef = useRef<AnalyserNode | null>(null);
  const mediaStreamRef = useRef<MediaStream | null>(null);
  const scriptProcessorRef = useRef<ScriptProcessorNode | null>(null);

  // Logic Refs
  const aiClientRef = useRef<GoogleGenAI | null>(null);
  const sessionPromiseRef = useRef<Promise<any> | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const isTransmittingRef = useRef(false);

  // Transcription Buffers
  const currentInputTranscription = useRef('');
  const currentOutputTranscription = useRef('');
  const recognitionRef = useRef<any>(null);

  // 1. Initialize & Network
  useEffect(() => {
    if (process.env.API_KEY) {
      aiClientRef.current = new GoogleGenAI({ apiKey: process.env.API_KEY });
    } else {
      setError("API Anahtarı bulunamadı.");
    }

    const handleOnline = () => setIsOnline(true);
    const handleOffline = () => {
      setIsOnline(false);
      stopConnection();
    };

    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);

    const savedPacks = localStorage.getItem('offlinePacks');
    if (savedPacks) {
      setOfflinePacks(JSON.parse(savedPacks));
    }

    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
    };
  }, []);

  const isOfflineActive = !isOnline || forceOfflineMode;

  // 2. Audio Processing
  const processAudioInput = useCallback((inputData: Float32Array) => {
    if (!sessionPromiseRef.current || !isTransmittingRef.current) return;

    const pcmData = float32To16BitPCM(inputData);
    const base64Data = arrayBufferToBase64(pcmData);

    sessionPromiseRef.current.then((session) => {
      session.sendRealtimeInput({
        media: {
          mimeType: `audio/pcm;rate=${INPUT_SAMPLE_RATE}`,
          data: base64Data,
        },
      });
    });
  }, []);

  // 3. Connection Logic
  const toggleConnection = async () => {
    if (isConnected) {
      stopConnection();
      return;
    }
    if (isOfflineActive) {
      setIsConnected(true);
      return;
    }
    if (!aiClientRef.current) return;
    setError(null);

    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: {
        sampleRate: INPUT_SAMPLE_RATE,
        channelCount: 1,
        echoCancellation: true,
        noiseSuppression: true,
        autoGainControl: true
      }});
      mediaStreamRef.current = stream;

      const audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ 
        sampleRate: INPUT_SAMPLE_RATE 
      });
      inputAudioContextRef.current = audioCtx;

      const source = audioCtx.createMediaStreamSource(stream);
      const analyser = audioCtx.createAnalyser();
      analyser.fftSize = 256;
      inputAnalyserRef.current = analyser;

      const scriptProcessor = audioCtx.createScriptProcessor(4096, 1, 1);
      scriptProcessorRef.current = scriptProcessor;

      scriptProcessor.onaudioprocess = (e) => {
        const inputData = e.inputBuffer.getChannelData(0);
        processAudioInput(inputData);
      };

      source.connect(analyser);
      analyser.connect(scriptProcessor);
      scriptProcessor.connect(audioCtx.destination);

      const outCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ 
        sampleRate: OUTPUT_SAMPLE_RATE 
      });
      outputAudioContextRef.current = outCtx;
      const outAnalyser = outCtx.createAnalyser();
      outAnalyser.fftSize = 256;
      outputAnalyserRef.current = outAnalyser;
      outAnalyser.connect(outCtx.destination);

      const systemPrompt = `You are a simultaneous interpreter. Translate Turkish to ${targetLang}. Output audio only.`;

      sessionPromiseRef.current = aiClientRef.current.live.connect({
        model: MODEL_NAME,
        config: {
          systemInstruction: systemPrompt,
          responseModalities: [Modality.AUDIO],
          inputAudioTranscription: {},
          outputAudioTranscription: {},
        },
        callbacks: {
          onopen: () => {
            setIsConnected(true);
            nextStartTimeRef.current = 0;
            setRealtimeInput('');
            setRealtimeOutput('');
          },
          onmessage: async (msg: LiveServerMessage) => {
            if (msg.serverContent?.inputTranscription) {
               currentInputTranscription.current += msg.serverContent.inputTranscription.text;
               setRealtimeInput(currentInputTranscription.current);
            }
            if (msg.serverContent?.outputTranscription) {
               currentOutputTranscription.current += msg.serverContent.outputTranscription.text;
               setRealtimeOutput(currentOutputTranscription.current);
            }
            if (msg.serverContent?.turnComplete) {
               const inputTx = currentInputTranscription.current.trim();
               const outputTx = currentOutputTranscription.current.trim();
               if (inputTx || outputTx) {
                 addMessage('user', inputTx || '...');
                 addMessage('model', outputTx || '...');
               }
               currentInputTranscription.current = '';
               currentOutputTranscription.current = '';
               setRealtimeInput('');
               setRealtimeOutput('');
            }
            const audioData = msg.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
            if (audioData) {
               playAudioResponse(audioData);
            }
          },
          onclose: () => stopConnection(),
          onerror: () => { setError("Bağlantı hatası."); stopConnection(); }
        }
      });
    } catch (e: any) {
      setError(`Hata: ${e.message}`);
      stopConnection();
    }
  };

  // 4. Toggle Mic
  const toggleMicrophone = async () => {
    if (!isConnected) return;
    const newState = !isTransmitting;
    setIsTransmitting(newState);
    isTransmittingRef.current = newState;

    if (newState) {
        if (inputAudioContextRef.current?.state === 'suspended') {
            await inputAudioContextRef.current.resume();
        }
        if (isOfflineActive) startOfflineRecognition();
    } else {
        if (isOfflineActive) stopOfflineRecognition();
    }
  };

  // 5. Offline Logic
  const startOfflineRecognition = () => {
    if (!('webkitSpeechRecognition' in window)) return;
    try {
      const Recognition = (window as any).webkitSpeechRecognition;
      const recognition = new Recognition();
      recognition.lang = 'tr-TR'; 
      recognition.continuous = true; 
      recognition.interimResults = true; 

      recognition.onstart = () => setRealtimeInput('');
      recognition.onresult = (event: any) => {
        let interim = '';
        let final = '';
        for (let i = event.resultIndex; i < event.results.length; ++i) {
          if (event.results[i].isFinal) final += event.results[i][0].transcript;
          else interim += event.results[i][0].transcript;
        }
        setRealtimeInput(final || interim);
      };
      recognition.onerror = (e: any) => console.log(e);
      recognitionRef.current = recognition;
      recognition.start();
    } catch (e) {}
  };

  const stopOfflineRecognition = () => {
    if (recognitionRef.current) {
      recognitionRef.current.stop();
      setTimeout(() => {
        const text = realtimeInput.trim();
        if (text) {
           addMessage('user', text);
           setRealtimeInput('');
           setTimeout(() => {
             const mock = `(${targetLang}) ${text}`;
             addMessage('model', mock);
             speakOffline(text, targetLang);
           }, 500);
        }
      }, 500);
    }
  };

  const speakOffline = (text: string, lang: TargetLanguage) => {
    if ('speechSynthesis' in window) {
      const utterance = new SpeechSynthesisUtterance(text); 
      const langMap: Record<TargetLanguage, string> = {
        [TargetLanguage.ENGLISH]: 'en-US', [TargetLanguage.DUTCH]: 'nl-NL',
        [TargetLanguage.ARABIC]: 'ar-SA', [TargetLanguage.RUSSIAN]: 'ru-RU'
      };
      utterance.lang = langMap[lang];
      window.speechSynthesis.speak(utterance);
    }
  };

  // 6. Play Audio
  const playAudioResponse = async (base64Audio: string) => {
    if (!outputAudioContextRef.current || !outputAnalyserRef.current) return;
    const ctx = outputAudioContextRef.current;
    try {
      const arrayBuffer = base64ToArrayBuffer(base64Audio);
      const float32Data = pcm16ToFloat32(arrayBuffer);
      const audioBuffer = ctx.createBuffer(1, float32Data.length, OUTPUT_SAMPLE_RATE);
      audioBuffer.getChannelData(0).set(float32Data);
      const source = ctx.createBufferSource();
      source.buffer = audioBuffer;
      source.connect(outputAnalyserRef.current);
      source.start(Math.max(nextStartTimeRef.current, ctx.currentTime));
      nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime) + audioBuffer.duration;
      source.onended = () => sourcesRef.current.delete(source);
      sourcesRef.current.add(source);
    } catch (err) {}
  };

  const addMessage = (role: 'user' | 'model', text: string) => {
    setMessages(prev => [...prev, { id: Date.now().toString() + Math.random(), role, text, timestamp: new Date(), isFinal: true }]);
  };

  const stopConnection = useCallback(() => {
    setIsConnected(false);
    setIsTransmitting(false);
    isTransmittingRef.current = false;
    setRealtimeInput(''); setRealtimeOutput('');
    if (mediaStreamRef.current) mediaStreamRef.current.getTracks().forEach(track => track.stop());
    if (scriptProcessorRef.current) scriptProcessorRef.current.disconnect();
    if (inputAudioContextRef.current) inputAudioContextRef.current.close();
    if (outputAudioContextRef.current) outputAudioContextRef.current.close();
    sessionPromiseRef.current = null;
    if (recognitionRef.current) recognitionRef.current.stop();
  }, []);

  const chatContainerRef = useRef<HTMLDivElement>(null);
  useEffect(() => {
    if (chatContainerRef.current) chatContainerRef.current.scrollTop = chatContainerRef.current.scrollHeight;
  }, [messages, realtimeInput, realtimeOutput]);

  const downloadPack = (id: string) => {
    setOfflinePacks(prev => prev.map(p => p.id === id ? { ...p, progress: 5 } : p));
    let progress = 5;
    const interval = setInterval(() => {
      progress += 10;
      if (progress >= 100) {
        clearInterval(interval);
        setOfflinePacks(prev => {
          const newPacks = prev.map(p => p.id === id ? { ...p, progress: 100, downloaded: true } : p);
          localStorage.setItem('offlinePacks', JSON.stringify(newPacks));
          return newPacks;
        });
      } else {
        setOfflinePacks(prev => prev.map(p => p.id === id ? { ...p, progress } : p));
      }
    }, 200);
  };

  const deletePack = (id: string) => {
     setOfflinePacks(prev => {
       const newPacks = prev.map(p => p.id === id ? { ...p, progress: 0, downloaded: false } : p);
       localStorage.setItem('offlinePacks', JSON.stringify(newPacks));
       return newPacks;
     });
  };

  return (
    <div className="h-screen w-full bg-slate-950 text-slate-100 flex flex-col font-sans relative overflow-hidden select-none">

      {/* Dynamic Background */}
      <div className="absolute inset-0 z-0 pointer-events-none">
        <div className={`absolute top-[-10%] left-[-20%] w-[150vw] h-[60vh] rounded-full blur-[80px] opacity-20 transition-colors duration-1000 ${isOfflineActive ? 'bg-orange-600' : isTransmitting ? 'bg-indigo-600' : 'bg-blue-900'}`}></div>
        <div className="absolute bottom-[-10%] right-[-20%] w-[150vw] h-[50vh] bg-purple-900/10 rounded-full blur-[100px]"></div>
      </div>

      {/* Mobile Header */}
      <header className="z-20 h-16 flex items-center justify-between px-5 bg-gradient-to-b from-slate-950/80 to-transparent backdrop-blur-sm sticky top-0">
        <div className="flex items-center gap-2.5">
          <div className={`w-8 h-8 rounded-xl flex items-center justify-center bg-gradient-to-br shadow-lg ${isOfflineActive ? 'from-orange-500 to-red-600' : 'from-blue-500 to-indigo-600'}`}>
            <Sparkles size={16} className="text-white" />
          </div>
          <span className="font-bold text-lg tracking-tight">LinguaFlow</span>
        </div>
        <div className="flex items-center gap-3">
          <div className={`px-2.5 py-1 rounded-full text-[10px] font-bold border ${isOfflineActive ? 'bg-orange-500/10 border-orange-500/20 text-orange-400' : 'bg-blue-500/10 border-blue-500/20 text-blue-400'}`}>
            {isOfflineActive ? 'OFFLINE' : 'ONLINE'}
          </div>
          <button onClick={() => setShowSettings(true)} className="p-2 rounded-full bg-slate-800/50 hover:bg-slate-800 transition-colors">
            <Settings size={20} className="text-slate-400" />
          </button>
        </div>
      </header>

      {/* Main Chat Area */}
      <main className="flex-1 flex flex-col z-10 relative overflow-hidden">

        {/* Messages */}
        <div ref={chatContainerRef} className="flex-1 overflow-y-auto px-4 pt-2 pb-6 space-y-6 scroll-smooth">
          {error && (
            <div className="bg-red-500/10 border border-red-500/20 text-red-200 p-3 rounded-xl text-sm flex justify-between items-center mx-2">
              <span>{error}</span>
              <button onClick={() => setError(null)}><X size={16} /></button>
            </div>
          )}

          {messages.length === 0 && !realtimeInput && (
             <div className="h-full flex flex-col items-center justify-center text-slate-500 opacity-40 space-y-4">
                <Globe size={64} strokeWidth={1} />
                <p className="text-center text-sm px-10">
                  {isConnected ? 'Mikrofonu açın ve konuşmaya başlayın.' : 'Başlamak için güç düğmesine basın.'}
                </p>
             </div>
          )}

          {messages.map((msg) => (
            <div key={msg.id} className={`flex flex-col ${msg.role === 'user' ? 'items-start' : 'items-end'}`}>
              <span className="text-[10px] text-slate-500 mb-1 px-1">{msg.role === 'user' ? 'TR' : targetLang.toUpperCase()}</span>
              <div className={`max-w-[85%] px-5 py-3.5 shadow-sm text-[15px] leading-relaxed ${
                msg.role === 'user' 
                  ? 'bg-slate-800 text-slate-200 rounded-2xl rounded-tl-sm' 
                  : isOfflineActive 
                    ? 'bg-orange-600 text-white rounded-2xl rounded-tr-sm'
                    : 'bg-blue-600 text-white rounded-2xl rounded-tr-sm'
              }`}>
                {msg.text}
              </div>
            </div>
          ))}

          {/* Real-time Bubbles */}
          {(realtimeInput || realtimeOutput) && (
             <div className="space-y-4">
                {realtimeInput && (
                  <div className="flex flex-col items-start opacity-70">
                     <span className="text-[10px] text-blue-400 mb-1 px-1 animate-pulse">DİNLİYOR...</span>
                     <div className="max-w-[85%] px-5 py-3 bg-slate-800/50 border border-slate-700 border-dashed text-slate-300 rounded-2xl rounded-tl-sm">
                       {realtimeInput}
                     </div>
                  </div>
                )}
                {realtimeOutput && (
                  <div className="flex flex-col items-end opacity-70">
                     <span className="text-[10px] text-indigo-400 mb-1 px-1 animate-pulse">ÇEVİRİYOR...</span>
                     <div className="max-w-[85%] px-5 py-3 bg-blue-900/30 border border-blue-500/30 border-dashed text-blue-200 rounded-2xl rounded-tr-sm">
                       {realtimeOutput}
                     </div>
                  </div>
                )}
             </div>
          )}
        </div>

        {/* BOTTOM DOCK (Controls) */}
        <div className="bg-slate-950/80 backdrop-blur-xl border-t border-slate-800/50 px-6 pb-8 pt-2 z-30">

          {/* Visualizer Bar (Above Dock) */}
          <div className="h-10 w-full flex items-center justify-center mb-2">
            {isConnected && isTransmitting ? (
              <div className="w-full h-full opacity-80">
                 <AudioVisualizer analyser={inputAnalyserRef.current} isActive={true} color={isOfflineActive ? '#f97316' : '#6366f1'} />
              </div>
            ) : (
              <div className="h-1 w-16 bg-slate-800 rounded-full"></div>
            )}
          </div>

          <div className="flex items-center justify-between">

            {/* Left: Power Toggle */}
            <button
              onClick={toggleConnection}
              className={`flex flex-col items-center gap-1 group w-16 ${isConnected ? 'text-emerald-500' : 'text-slate-500'}`}
            >
              <div className={`w-12 h-12 rounded-full flex items-center justify-center transition-all ${
                isConnected ? 'bg-emerald-500/10 border border-emerald-500/30' : 'bg-slate-800 border border-slate-700'
              }`}>
                <Power size={22} />
              </div>
              <span className="text-[10px] font-medium">{isConnected ? 'Açık' : 'Kapalı'}</span>
            </button>

            {/* Center: Main Mic Toggle */}
            <div className="relative -mt-6">
              {/* Ring Animation */}
              {isTransmitting && (
                <div className="absolute inset-0 rounded-full animate-ping opacity-30 bg-indigo-500"></div>
              )}

              <button
                onClick={toggleMicrophone}
                disabled={!isConnected}
                className={`w-20 h-20 rounded-full flex items-center justify-center shadow-2xl transition-all duration-200 transform active:scale-95 ${
                  !isConnected 
                    ? 'bg-slate-800 text-slate-600 cursor-not-allowed'
                    : isTransmitting
                      ? isOfflineActive 
                        ? 'bg-orange-600 text-white shadow-orange-600/40 ring-4 ring-orange-900/50' 
                        : 'bg-indigo-600 text-white shadow-indigo-600/40 ring-4 ring-indigo-900/50'
                      : 'bg-slate-700 text-white hover:bg-slate-600 border-4 border-slate-900'
                }`}
              >
                {isTransmitting ? <Pause size={32} fill="currentColor" /> : <Mic size={32} />}
              </button>
            </div>

            {/* Right: Language Selector */}
            <div className="w-16 flex flex-col items-center gap-1">
               <div className="relative w-full">
                  <select 
                    value={targetLang}
                    onChange={(e) => {
                      if (isConnected && !isOfflineActive) stopConnection();
                      setTargetLang(e.target.value as TargetLanguage);
                    }}
                    className="appearance-none w-full h-12 bg-slate-800 border border-slate-700 text-slate-200 text-xs font-semibold rounded-2xl text-center pl-2 pr-6 focus:outline-none focus:ring-1 focus:ring-blue-500"
                  >
                    <option value={TargetLanguage.ENGLISH}>EN</option>
                    <option value={TargetLanguage.DUTCH}>NL</option>
                    <option value={TargetLanguage.ARABIC}>AR</option>
                    <option value={TargetLanguage.RUSSIAN}>RU</option>
                  </select>
                  <ChevronDown size={12} className="absolute right-2 top-1/2 -translate-y-1/2 text-slate-500 pointer-events-none"/>
               </div>
               <span className="text-[10px] text-slate-500 font-medium">Hedef</span>
            </div>

          </div>
        </div>

      </main>

      {/* Settings Sheet (Bottom Sheet Style) */}
      {showSettings && (
        <div className="fixed inset-0 z-50 flex items-end justify-center bg-black/60 backdrop-blur-sm animate-fade-in" onClick={() => setShowSettings(false)}>
          <div className="bg-slate-900 border-t border-slate-700 w-full max-w-lg rounded-t-3xl shadow-2xl overflow-hidden max-h-[85vh] flex flex-col" onClick={e => e.stopPropagation()}>
             <div className="p-5 flex justify-between items-center bg-slate-800/50">
                <h2 className="text-lg font-bold flex items-center gap-2 text-white">
                  <Settings size={20} className="text-blue-400"/> Ayarlar
                </h2>
                <div className="w-12 h-1 bg-slate-700 rounded-full absolute top-3 left-1/2 -translate-x-1/2"></div>
                <button onClick={() => setShowSettings(false)} className="p-1 bg-slate-800 rounded-full text-slate-400"><X size={20} /></button>
             </div>

             <div className="p-6 overflow-y-auto space-y-6">
               {/* Mode */}
               <div className="bg-slate-800/30 p-4 rounded-2xl border border-slate-800">
                  <div className="flex justify-between items-center mb-2">
                    <span className="font-semibold text-slate-200">Çevrimdışı Mod</span>
                    <button onClick={() => { if(isConnected) stopConnection(); setForceOfflineMode(!forceOfflineMode); }} 
                      className={`w-12 h-7 rounded-full p-1 transition-colors ${forceOfflineMode ? 'bg-orange-500' : 'bg-slate-700'}`}>
                      <div className={`w-5 h-5 rounded-full bg-white transition-transform ${forceOfflineMode ? 'translate-x-5' : ''}`}></div>
                    </button>
                  </div>
                  <p className="text-xs text-slate-500">İnternet bağlantısı olmadan cihaz üzerinde basit çeviri yapın.</p>
               </div>

               {/* Packs */}
               <div>
                 <h3 className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-3 px-1">Dil Paketleri</h3>
                 <div className="space-y-3">
                    {offlinePacks.map(pack => (
                       <div key={pack.id} className="bg-slate-800/50 p-3 rounded-xl border border-slate-700/50 flex items-center justify-between">
                          <div className="flex-1">
                             <div className="flex items-center gap-2">
                               <span className="font-semibold text-sm">{pack.pair}</span>
                               <span className="text-[10px] bg-slate-700 text-slate-300 px-1.5 py-0.5 rounded">{pack.size}</span>
                             </div>
                             <div className="text-xs text-slate-400 mt-1">{pack.name}</div>
                             {pack.progress > 0 && pack.progress < 100 && (
                               <div className="w-full h-1 bg-slate-700 mt-2 rounded-full overflow-hidden">
                                  <div className="h-full bg-blue-500 transition-all" style={{width: `${pack.progress}%`}}></div>
                               </div>
                             )}
                          </div>

                          <div className="ml-4">
                             {pack.downloaded ? (
                               <button onClick={() => deletePack(pack.id)} className="p-2 text-green-400 bg-green-400/10 rounded-full hover:bg-red-500/20 hover:text-red-400 transition-colors">
                                  <Check size={18} />
                               </button>
                             ) : pack.progress > 0 ? (
                               <span className="text-xs font-bold text-blue-400">{pack.progress}%</span>
                             ) : (
                               <button onClick={() => downloadPack(pack.id)} className="p-2 bg-slate-700 hover:bg-blue-600 rounded-full text-white transition-colors">
                                 <Download size={18} />
                               </button>
                             )}
                          </div>
                       </div>
                    ))}
                 </div>
               </div>

               {/* Clear History */}
               <button onClick={() => { setMessages([]); setRealtimeInput(''); setRealtimeOutput(''); setShowSettings(false); }} className="w-full py-4 text-sm text-red-400 font-medium bg-red-500/10 rounded-2xl hover:bg-red-500/20 transition-colors flex items-center justify-center gap-2">
                  <Trash2 size={16} /> Geçmişi Temizle
               </button>
             </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';
import { TargetLanguage, ChatMessage, OfflinePack } from './types';
import { float32To16BitPCM, arrayBufferToBase64, base64ToArrayBuffer, pcm16ToFloat32 } from './utils/audioUtils';
import AudioVisualizer from './components/AudioVisualizer';
import { Mic, Globe, Settings, RotateCcw, Wifi, WifiOff, Download, Check, Trash2, X, Zap, Square, ChevronDown, Sparkles, Loader2 } from 'lucide-react';

// Live API Configuration
const MODEL_NAME = 'gemini-2.5-flash-native-audio-preview-09-2025';
const INPUT_SAMPLE_RATE = 16000;
const OUTPUT_SAMPLE_RATE = 24000;

// Mock Offline Packs
const INITIAL_PACKS: OfflinePack[] = [
  { id: 'tr-en', pair: 'TR ↔ EN', name: 'İngilizce', size: '45 MB', downloaded: false, progress: 0 },
  { id: 'tr-nl', pair: 'TR ↔ NL', name: 'Hollandaca', size: '42 MB', downloaded: false, progress: 0 },
  { id: 'tr-ar', pair: 'TR ↔ AR', name: 'Arapça', size: '50 MB', downloaded: false, progress: 0 },
  { id: 'tr-ru', pair: 'TR ↔ RU', name: 'Rusça', size: '48 MB', downloaded: false, progress: 0 },
];

const App: React.FC = () => {
  const [targetLang, setTargetLang] = useState<TargetLanguage>(TargetLanguage.ENGLISH);
  const [isConnected, setIsConnected] = useState(false);
  const [isConnecting, setIsConnecting] = useState(false);
  // isTransmitting is effectively same as isConnected now, but kept for logic consistency
  const [isTransmitting, setIsTransmitting] = useState(false);

  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [error, setError] = useState<string | null>(null);

  // Real-time Display States
  const [realtimeInput, setRealtimeInput] = useState('');
  const [realtimeOutput, setRealtimeOutput] = useState('');

  // Offline / Network State
  const [isOnline, setIsOnline] = useState(navigator.onLine);
  const [forceOfflineMode, setForceOfflineMode] = useState(false);
  const [showSettings, setShowSettings] = useState(false);
  const [offlinePacks, setOfflinePacks] = useState<OfflinePack[]>(INITIAL_PACKS);

  // Audio Context Refs
  const inputAudioContextRef = useRef<AudioContext | null>(null);
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const inputAnalyserRef = useRef<AnalyserNode | null>(null);
  const outputAnalyserRef = useRef<AnalyserNode | null>(null);
  const mediaStreamRef = useRef<MediaStream | null>(null);
  const scriptProcessorRef = useRef<ScriptProcessorNode | null>(null);

  // Logic Refs
  const aiClientRef = useRef<GoogleGenAI | null>(null);
  const sessionPromiseRef = useRef<Promise<any> | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const isTransmittingRef = useRef(false);

  // Transcription Buffers
  const currentInputTranscription = useRef('');
  const currentOutputTranscription = useRef('');
  const recognitionRef = useRef<any>(null);

  // 1. Initialize & Network
  useEffect(() => {
    if (process.env.API_KEY) {
      aiClientRef.current = new GoogleGenAI({ apiKey: process.env.API_KEY });
    } else {
      setError("API Anahtarı bulunamadı.");
    }

    const handleOnline = () => setIsOnline(true);
    const handleOffline = () => {
      setIsOnline(false);
      stopConnection();
    };

    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);

    const savedPacks = localStorage.getItem('offlinePacks');
    if (savedPacks) {
      setOfflinePacks(JSON.parse(savedPacks));
    }

    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
    };
  }, []);

  const isOfflineActive = !isOnline || forceOfflineMode;

  // 2. Audio Processing
  const processAudioInput = useCallback((inputData: Float32Array) => {
    if (!sessionPromiseRef.current || !isTransmittingRef.current) return;

    const pcmData = float32To16BitPCM(inputData);
    const base64Data = arrayBufferToBase64(pcmData);

    sessionPromiseRef.current.then((session) => {
      session.sendRealtimeInput({
        media: {
          mimeType: `audio/pcm;rate=${INPUT_SAMPLE_RATE}`,
          data: base64Data,
        },
      });
    });
  }, []);

  // 3. Single Button Handler (Connect/Disconnect)
  const handleMicToggle = async () => {
    // Prevent double clicks while connecting
    if (isConnecting) return;

    // If already connected, Stop.
    if (isConnected) {
      stopConnection();
      return;
    }

    // Start Connection Process
    setIsConnecting(true);
    setError(null);

    // --- Offline Mode ---
    if (isOfflineActive) {
      // Simulate connection delay slightly for UX
      setTimeout(() => {
        setIsConnected(true);
        setIsTransmitting(true);
        isTransmittingRef.current = true;
        setIsConnecting(false);
        startOfflineRecognition();
      }, 300);
      return;
    }

    // --- Online Mode (Gemini Live) ---
    if (!aiClientRef.current) {
       setError("API Anahtarı eksik.");
       setIsConnecting(false);
       return;
    }

    try {
      // 1. Setup Input Audio
      const stream = await navigator.mediaDevices.getUserMedia({ audio: {
        sampleRate: INPUT_SAMPLE_RATE,
        channelCount: 1,
        echoCancellation: true,
        noiseSuppression: true,
        autoGainControl: true
      }});
      mediaStreamRef.current = stream;

      const audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ 
        sampleRate: INPUT_SAMPLE_RATE 
      });
      inputAudioContextRef.current = audioCtx;

      const source = audioCtx.createMediaStreamSource(stream);
      const analyser = audioCtx.createAnalyser();
      analyser.fftSize = 256;
      inputAnalyserRef.current = analyser;

      const scriptProcessor = audioCtx.createScriptProcessor(4096, 1, 1);
      scriptProcessorRef.current = scriptProcessor;

      scriptProcessor.onaudioprocess = (e) => {
        const inputData = e.inputBuffer.getChannelData(0);
        processAudioInput(inputData);
      };

      source.connect(analyser);
      analyser.connect(scriptProcessor);
      scriptProcessor.connect(audioCtx.destination);

      // 2. Setup Output Audio
      const outCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ 
        sampleRate: OUTPUT_SAMPLE_RATE 
      });
      outputAudioContextRef.current = outCtx;
      const outAnalyser = outCtx.createAnalyser();
      outAnalyser.fftSize = 256;
      outputAnalyserRef.current = outAnalyser;
      outAnalyser.connect(outCtx.destination);

      // 3. Connect API
      const systemPrompt = `You are a simultaneous interpreter. Translate Turkish to ${targetLang}. Output audio only.`;

      sessionPromiseRef.current = aiClientRef.current.live.connect({
        model: MODEL_NAME,
        config: {
          systemInstruction: systemPrompt,
          responseModalities: [Modality.AUDIO],
          inputAudioTranscription: {},
          outputAudioTranscription: {},
        },
        callbacks: {
          onopen: () => {
            console.log("Connected");
            setIsConnecting(false);
            setIsConnected(true);
            setIsTransmitting(true);
            isTransmittingRef.current = true;
            nextStartTimeRef.current = 0;
            setRealtimeInput('');
            setRealtimeOutput('');
          },
          onmessage: async (msg: LiveServerMessage) => {
             handleServerMessage(msg);
          },
          onclose: () => {
            console.log("Closed");
            stopConnection();
          },
          onerror: (e) => {
            console.error(e);
            setError("Bağlantı hatası.");
            stopConnection();
          }
        }
      });
    } catch (e: any) {
      console.error(e);
      setError(`Hata: ${e.message}`);
      stopConnection();
    }
  };

  const handleServerMessage = (msg: LiveServerMessage) => {
    if (msg.serverContent?.inputTranscription) {
       currentInputTranscription.current += msg.serverContent.inputTranscription.text;
       setRealtimeInput(currentInputTranscription.current);
    }
    if (msg.serverContent?.outputTranscription) {
       currentOutputTranscription.current += msg.serverContent.outputTranscription.text;
       setRealtimeOutput(currentOutputTranscription.current);
    }
    if (msg.serverContent?.turnComplete) {
       const inputTx = currentInputTranscription.current.trim();
       const outputTx = currentOutputTranscription.current.trim();
       if (inputTx || outputTx) {
         addMessage('user', inputTx || '...');
         addMessage('model', outputTx || '...');
       }
       currentInputTranscription.current = '';
       currentOutputTranscription.current = '';
       setRealtimeInput('');
       setRealtimeOutput('');
    }
    const audioData = msg.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
    if (audioData) {
       playAudioResponse(audioData);
    }
  };

  // 5. Offline Logic
  const startOfflineRecognition = () => {
    if (!('webkitSpeechRecognition' in window)) return;
    try {
      const Recognition = (window as any).webkitSpeechRecognition;
      const recognition = new Recognition();
      recognition.lang = 'tr-TR'; 
      recognition.continuous = true; 
      recognition.interimResults = true; 

      recognition.onstart = () => setRealtimeInput('');
      recognition.onresult = (event: any) => {
        let interim = '';
        let final = '';
        for (let i = event.resultIndex; i < event.results.length; ++i) {
          if (event.results[i].isFinal) final += event.results[i][0].transcript;
          else interim += event.results[i][0].transcript;
        }
        setRealtimeInput(final || interim);
      };
      recognition.onerror = (e: any) => console.log(e);
      recognitionRef.current = recognition;
      recognition.start();
    } catch (e) {}
  };

  const stopOfflineRecognition = () => {
    if (recognitionRef.current) {
      recognitionRef.current.stop();
      setTimeout(() => {
        const text = realtimeInput.trim();
        if (text) {
           addMessage('user', text);
           setRealtimeInput('');
           setTimeout(() => {
             const mock = `(${targetLang}) ${text}`;
             addMessage('model', mock);
             speakOffline(text, targetLang);
           }, 500);
        }
      }, 500);
    }
  };

  const speakOffline = (text: string, lang: TargetLanguage) => {
    if ('speechSynthesis' in window) {
      const utterance = new SpeechSynthesisUtterance(text); 
      const langMap: Record<TargetLanguage, string> = {
        [TargetLanguage.ENGLISH]: 'en-US', [TargetLanguage.DUTCH]: 'nl-NL',
        [TargetLanguage.ARABIC]: 'ar-SA', [TargetLanguage.RUSSIAN]: 'ru-RU'
      };
      utterance.lang = langMap[lang];
      window.speechSynthesis.speak(utterance);
    }
  };

  // 6. Play Audio
  const playAudioResponse = async (base64Audio: string) => {
    if (!outputAudioContextRef.current || !outputAnalyserRef.current) return;
    const ctx = outputAudioContextRef.current;
    try {
      const arrayBuffer = base64ToArrayBuffer(base64Audio);
      const float32Data = pcm16ToFloat32(arrayBuffer);
      const audioBuffer = ctx.createBuffer(1, float32Data.length, OUTPUT_SAMPLE_RATE);
      audioBuffer.getChannelData(0).set(float32Data);
      const source = ctx.createBufferSource();
      source.buffer = audioBuffer;
      source.connect(outputAnalyserRef.current);
      source.start(Math.max(nextStartTimeRef.current, ctx.currentTime));
      nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime) + audioBuffer.duration;
      source.onended = () => sourcesRef.current.delete(source);
      sourcesRef.current.add(source);
    } catch (err) {}
  };

  const addMessage = (role: 'user' | 'model', text: string) => {
    setMessages(prev => [...prev, { id: Date.now().toString() + Math.random(), role, text, timestamp: new Date(), isFinal: true }]);
  };

  const stopConnection = useCallback(() => {
    setIsConnecting(false);
    setIsConnected(false);
    setIsTransmitting(false);
    isTransmittingRef.current = false;

    setRealtimeInput(''); setRealtimeOutput('');

    if (mediaStreamRef.current) mediaStreamRef.current.getTracks().forEach(track => track.stop());
    if (scriptProcessorRef.current) scriptProcessorRef.current.disconnect();
    if (inputAudioContextRef.current) inputAudioContextRef.current.close();
    if (outputAudioContextRef.current) outputAudioContextRef.current.close();

    sessionPromiseRef.current = null;

    if (recognitionRef.current) {
        // Handle last offline input if any
        if (recognitionRef.current) recognitionRef.current.stop();
        // We can optionally trigger one last translation here similar to before
        // But for simplicity of "Stop", we just stop.
    }
  }, []);

  const chatContainerRef = useRef<HTMLDivElement>(null);
  useEffect(() => {
    if (chatContainerRef.current) chatContainerRef.current.scrollTop = chatContainerRef.current.scrollHeight;
  }, [messages, realtimeInput, realtimeOutput]);

  const downloadPack = (id: string) => {
    setOfflinePacks(prev => prev.map(p => p.id === id ? { ...p, progress: 5 } : p));
    let progress = 5;
    const interval = setInterval(() => {
      progress += 10;
      if (progress >= 100) {
        clearInterval(interval);
        setOfflinePacks(prev => {
          const newPacks = prev.map(p => p.id === id ? { ...p, progress: 100, downloaded: true } : p);
          localStorage.setItem('offlinePacks', JSON.stringify(newPacks));
          return newPacks;
        });
      } else {
        setOfflinePacks(prev => prev.map(p => p.id === id ? { ...p, progress } : p));
      }
    }, 200);
  };

  const deletePack = (id: string) => {
     setOfflinePacks(prev => {
       const newPacks = prev.map(p => p.id === id ? { ...p, progress: 0, downloaded: false } : p);
       localStorage.setItem('offlinePacks', JSON.stringify(newPacks));
       return newPacks;
     });
  };

  return (
    <div className="h-screen w-full bg-slate-950 text-slate-100 flex flex-col font-sans relative overflow-hidden select-none">

      {/* Dynamic Background */}
      <div className="absolute inset-0 z-0 pointer-events-none">
        <div className={`absolute top-[-10%] left-[-20%] w-[150vw] h-[60vh] rounded-full blur-[80px] opacity-20 transition-colors duration-1000 ${isOfflineActive ? 'bg-orange-600' : isConnected ? 'bg-indigo-600' : 'bg-blue-900'}`}></div>
        <div className="absolute bottom-[-10%] right-[-20%] w-[150vw] h-[50vh] bg-purple-900/10 rounded-full blur-[100px]"></div>
      </div>

      {/* Mobile Header */}
      <header className="z-20 h-16 flex items-center justify-between px-5 bg-gradient-to-b from-slate-950/80 to-transparent backdrop-blur-sm sticky top-0">
        <div className="flex items-center gap-2.5">
          <div className={`w-8 h-8 rounded-xl flex items-center justify-center bg-gradient-to-br shadow-lg ${isOfflineActive ? 'from-orange-500 to-red-600' : 'from-blue-500 to-indigo-600'}`}>
            <Sparkles size={16} className="text-white" />
          </div>
          <span className="font-bold text-lg tracking-tight">LinguaFlow</span>
        </div>
        <div className="flex items-center gap-3">
          <div className={`px-2.5 py-1 rounded-full text-[10px] font-bold border ${isOfflineActive ? 'bg-orange-500/10 border-orange-500/20 text-orange-400' : 'bg-blue-500/10 border-blue-500/20 text-blue-400'}`}>
            {isOfflineActive ? 'OFFLINE' : 'ONLINE'}
          </div>
          <button onClick={() => setShowSettings(true)} className="p-2 rounded-full bg-slate-800/50 hover:bg-slate-800 transition-colors">
            <Settings size={20} className="text-slate-400" />
          </button>
        </div>
      </header>

      {/* Main Chat Area */}
      <main className="flex-1 flex flex-col z-10 relative overflow-hidden">

        {/* Messages */}
        <div ref={chatContainerRef} className="flex-1 overflow-y-auto px-4 pt-2 pb-6 space-y-6 scroll-smooth">
          {error && (
            <div className="bg-red-500/10 border border-red-500/20 text-red-200 p-3 rounded-xl text-sm flex justify-between items-center mx-2">
              <span>{error}</span>
              <button onClick={() => setError(null)}><X size={16} /></button>
            </div>
          )}

          {messages.length === 0 && !realtimeInput && (
             <div className="h-full flex flex-col items-center justify-center text-slate-500 opacity-40 space-y-4">
                <Globe size={64} strokeWidth={1} />
                <p className="text-center text-sm px-10">
                  Konuşmaya başlamak için aşağıdaki mikrofona dokunun.
                </p>
             </div>
          )}

          {messages.map((msg) => (
            <div key={msg.id} className={`flex flex-col ${msg.role === 'user' ? 'items-start' : 'items-end'}`}>
              <span className="text-[10px] text-slate-500 mb-1 px-1">{msg.role === 'user' ? 'TR' : targetLang.toUpperCase()}</span>
              <div className={`max-w-[85%] px-5 py-3.5 shadow-sm text-[15px] leading-relaxed ${
                msg.role === 'user' 
                  ? 'bg-slate-800 text-slate-200 rounded-2xl rounded-tl-sm' 
                  : isOfflineActive 
                    ? 'bg-orange-600 text-white rounded-2xl rounded-tr-sm'
                    : 'bg-blue-600 text-white rounded-2xl rounded-tr-sm'
              }`}>
                {msg.text}
              </div>
            </div>
          ))}

          {/* Real-time Bubbles */}
          {(realtimeInput || realtimeOutput) && (
             <div className="space-y-4">
                {realtimeInput && (
                  <div className="flex flex-col items-start opacity-70">
                     <span className="text-[10px] text-blue-400 mb-1 px-1 animate-pulse">DİNLİYOR...</span>
                     <div className="max-w-[85%] px-5 py-3 bg-slate-800/50 border border-slate-700 border-dashed text-slate-300 rounded-2xl rounded-tl-sm">
                       {realtimeInput}
                     </div>
                  </div>
                )}
                {realtimeOutput && (
                  <div className="flex flex-col items-end opacity-70">
                     <span className="text-[10px] text-indigo-400 mb-1 px-1 animate-pulse">ÇEVİRİYOR...</span>
                     <div className="max-w-[85%] px-5 py-3 bg-blue-900/30 border border-blue-500/30 border-dashed text-blue-200 rounded-2xl rounded-tr-sm">
                       {realtimeOutput}
                     </div>
                  </div>
                )}
             </div>
          )}
        </div>

        {/* BOTTOM DOCK (Controls) */}
        <div className="bg-slate-950/80 backdrop-blur-xl border-t border-slate-800/50 px-6 pb-10 pt-4 z-30">

          {/* Visualizer Bar (Above Dock) */}
          <div className="h-10 w-full flex items-center justify-center mb-4">
            {isConnected ? (
              <div className="w-full h-full opacity-80">
                 <AudioVisualizer analyser={inputAnalyserRef.current} isActive={true} color={isOfflineActive ? '#f97316' : '#6366f1'} />
              </div>
            ) : (
              <div className="h-1 w-16 bg-slate-800 rounded-full"></div>
            )}
          </div>

          <div className="flex items-center justify-between max-w-sm mx-auto">

            {/* Left: Language Selector */}
            <div className="w-16 flex flex-col items-center gap-1">
               <div className="relative w-full">
                  <select 
                    value={targetLang}
                    onChange={(e) => {
                      if (isConnected && !isOfflineActive) stopConnection();
                      setTargetLang(e.target.value as TargetLanguage);
                    }}
                    className="appearance-none w-full h-12 bg-slate-800 border border-slate-700 text-slate-200 text-xs font-semibold rounded-2xl text-center pl-2 pr-6 focus:outline-none focus:ring-1 focus:ring-blue-500 transition-colors hover:border-slate-500"
                  >
                    <option value={TargetLanguage.ENGLISH}>EN</option>
                    <option value={TargetLanguage.DUTCH}>NL</option>
                    <option value={TargetLanguage.ARABIC}>AR</option>
                    <option value={TargetLanguage.RUSSIAN}>RU</option>
                  </select>
                  <ChevronDown size={12} className="absolute right-2 top-1/2 -translate-y-1/2 text-slate-500 pointer-events-none"/>
               </div>
               <span className="text-[10px] text-slate-500 font-medium">Hedef</span>
            </div>

            {/* Center: Main Mic Toggle */}
            <div className="relative -mt-6">
              {/* Ring Animation */}
              {isConnected && (
                <div className="absolute inset-0 rounded-full animate-ping opacity-30 bg-indigo-500"></div>
              )}

              <button
                onClick={handleMicToggle}
                className={`w-20 h-20 rounded-full flex items-center justify-center shadow-2xl transition-all duration-300 transform active:scale-95 ${
                  isConnecting
                    ? 'bg-slate-800 border-4 border-slate-700 cursor-wait'
                    : isConnected
                      ? isOfflineActive 
                        ? 'bg-orange-600 text-white shadow-orange-600/40 ring-4 ring-orange-900/50 scale-105' 
                        : 'bg-indigo-600 text-white shadow-indigo-600/40 ring-4 ring-indigo-900/50 scale-105'
                      : 'bg-slate-100 text-slate-900 hover:bg-white border-4 border-slate-300 shadow-white/10'
                }`}
              >
                {isConnecting ? (
                   <Loader2 size={32} className="animate-spin text-slate-400" />
                ) : isConnected ? (
                   <Square size={28} fill="currentColor" className="rounded-sm" />
                ) : (
                   <Mic size={32} strokeWidth={2.5} />
                )}
              </button>
            </div>

            {/* Right: Clear Button */}
            <div className="w-16 flex flex-col items-center gap-1">
               <button 
                 onClick={() => {
                   setMessages([]);
                   setRealtimeInput('');
                   setRealtimeOutput('');
                 }}
                 className="w-full h-12 flex items-center justify-center rounded-2xl bg-slate-800 border border-slate-700 text-slate-400 hover:text-white hover:bg-slate-700 transition-colors"
               >
                 <RotateCcw size={18} />
               </button>
               <span className="text-[10px] text-slate-500 font-medium">Temizle</span>
            </div>

          </div>
        </div>

      </main>

      {/* Settings Sheet (Bottom Sheet Style) */}
      {showSettings && (
        <div className="fixed inset-0 z-50 flex items-end justify-center bg-black/60 backdrop-blur-sm animate-fade-in" onClick={() => setShowSettings(false)}>
          <div className="bg-slate-900 border-t border-slate-700 w-full max-w-lg rounded-t-3xl shadow-2xl overflow-hidden max-h-[85vh] flex flex-col" onClick={e => e.stopPropagation()}>
             <div className="p-5 flex justify-between items-center bg-slate-800/50">
                <h2 className="text-lg font-bold flex items-center gap-2 text-white">
                  <Settings size={20} className="text-blue-400"/> Ayarlar
                </h2>
                <div className="w-12 h-1 bg-slate-700 rounded-full absolute top-3 left-1/2 -translate-x-1/2"></div>
                <button onClick={() => setShowSettings(false)} className="p-1 bg-slate-800 rounded-full text-slate-400"><X size={20} /></button>
             </div>

             <div className="p-6 overflow-y-auto space-y-6">
               {/* Mode */}
               <div className="bg-slate-800/30 p-4 rounded-2xl border border-slate-800">
                  <div className="flex justify-between items-center mb-2">
                    <span className="font-semibold text-slate-200">Çevrimdışı Mod</span>
                    <button onClick={() => { if(isConnected) stopConnection(); setForceOfflineMode(!forceOfflineMode); }} 
                      className={`w-12 h-7 rounded-full p-1 transition-colors ${forceOfflineMode ? 'bg-orange-500' : 'bg-slate-700'}`}>
                      <div className={`w-5 h-5 rounded-full bg-white transition-transform ${forceOfflineMode ? 'translate-x-5' : ''}`}></div>
                    </button>
                  </div>
                  <p className="text-xs text-slate-500">İnternet bağlantısı olmadan cihaz üzerinde basit çeviri yapın.</p>
               </div>

               {/* Packs */}
               <div>
                 <h3 className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-3 px-1">Dil Paketleri</h3>
                 <div className="space-y-3">
                    {offlinePacks.map(pack => (
                       <div key={pack.id} className="bg-slate-800/50 p-3 rounded-xl border border-slate-700/50 flex items-center justify-between">
                          <div className="flex-1">
                             <div className="flex items-center gap-2">
                               <span className="font-semibold text-sm">{pack.pair}</span>
                               <span className="text-[10px] bg-slate-700 text-slate-300 px-1.5 py-0.5 rounded">{pack.size}</span>
                             </div>
                             <div className="text-xs text-slate-400 mt-1">{pack.name}</div>
                             {pack.progress > 0 && pack.progress < 100 && (
                               <div className="w-full h-1 bg-slate-700 mt-2 rounded-full overflow-hidden">
                                  <div className="h-full bg-blue-500 transition-all" style={{width: `${pack.progress}%`}}></div>
                               </div>
                             )}
                          </div>

                          <div className="ml-4">
                             {pack.downloaded ? (
                               <button onClick={() => deletePack(pack.id)} className="p-2 text-green-400 bg-green-400/10 rounded-full hover:bg-red-500/20 hover:text-red-400 transition-colors">
                                  <Check size={18} />
                               </button>
                             ) : pack.progress > 0 ? (
                               <span className="text-xs font-bold text-blue-400">{pack.progress}%</span>
                             ) : (
                               <button onClick={() => downloadPack(pack.id)} className="p-2 bg-slate-700 hover:bg-blue-600 rounded-full text-white transition-colors">
                                 <Download size={18} />
                               </button>
                             )}
                          </div>
                       </div>
                    ))}
                 </div>
               </div>

               {/* Clear History */}
               <button onClick={() => { setMessages([]); setRealtimeInput(''); setRealtimeOutput(''); setShowSettings(false); }} className="w-full py-4 text-sm text-red-400 font-medium bg-red-500/10 rounded-2xl hover:bg-red-500/20 transition-colors flex items-center justify-center gap-2">
                  <Trash2 size={16} /> Geçmişi Temizle
               </button>
             </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';
import { TargetLanguage, ChatMessage, OfflinePack } from './types';
import { float32To16BitPCM, arrayBufferToBase64, base64ToArrayBuffer, pcm16ToFloat32 } from './utils/audioUtils';
import AudioVisualizer from './components/AudioVisualizer';
import { Mic, Globe, Settings, RotateCcw, Wifi, WifiOff, Download, Check, Trash2, X, Zap, Square, ChevronDown, Sparkles, Loader2 } from 'lucide-react';

// Live API Configuration
const MODEL_NAME = 'gemini-2.5-flash-native-audio-preview-09-2025';
const INPUT_SAMPLE_RATE = 16000;
const OUTPUT_SAMPLE_RATE = 24000;

// Mock Offline Packs
const INITIAL_PACKS: OfflinePack[] = [
  { id: 'tr-en', pair: 'TR ↔ EN', name: 'İngilizce', size: '45 MB', downloaded: false, progress: 0 },
  { id: 'tr-nl', pair: 'TR ↔ NL', name: 'Hollandaca', size: '42 MB', downloaded: false, progress: 0 },
  { id: 'tr-ar', pair: 'TR ↔ AR', name: 'Arapça', size: '50 MB', downloaded: false, progress: 0 },
  { id: 'tr-ru', pair: 'TR ↔ RU', name: 'Rusça', size: '48 MB', downloaded: false, progress: 0 },
];

const App: React.FC = () => {
  const [targetLang, setTargetLang] = useState<TargetLanguage>(TargetLanguage.ENGLISH);
  const [isConnected, setIsConnected] = useState(false);
  const [isConnecting, setIsConnecting] = useState(false);
  const [isTransmitting, setIsTransmitting] = useState(false);

  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [error, setError] = useState<string | null>(null);

  // Real-time Display States
  const [realtimeInput, setRealtimeInput] = useState('');
  const [realtimeOutput, setRealtimeOutput] = useState('');

  // Offline / Network State
  const [isOnline, setIsOnline] = useState(navigator.onLine);
  const [forceOfflineMode, setForceOfflineMode] = useState(false);
  const [showSettings, setShowSettings] = useState(false);
  const [offlinePacks, setOfflinePacks] = useState<OfflinePack[]>(INITIAL_PACKS);

  // Audio Context Refs
  const inputAudioContextRef = useRef<AudioContext | null>(null);
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const inputAnalyserRef = useRef<AnalyserNode | null>(null);
  const outputAnalyserRef = useRef<AnalyserNode | null>(null);
  const mediaStreamRef = useRef<MediaStream | null>(null);
  const scriptProcessorRef = useRef<ScriptProcessorNode | null>(null);

  // Logic Refs
  const aiClientRef = useRef<GoogleGenAI | null>(null);
  const sessionPromiseRef = useRef<Promise<any> | null>(null);
  const activeSessionRef = useRef<any>(null); // To store actual session object for cleanup
  const shouldReconnectRef = useRef(false); // Flag for auto-reconnect logic
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const isTransmittingRef = useRef(false);

  // Transcription Buffers
  const currentInputTranscription = useRef('');
  const currentOutputTranscription = useRef('');
  const recognitionRef = useRef<any>(null);

  // 1. Initialize & Network
  useEffect(() => {
    if (process.env.API_KEY) {
      aiClientRef.current = new GoogleGenAI({ apiKey: process.env.API_KEY });
    } else {
      setError("API Anahtarı bulunamadı.");
    }

    const handleOnline = () => setIsOnline(true);
    const handleOffline = () => {
      setIsOnline(false);
      stopConnection();
    };

    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);

    const savedPacks = localStorage.getItem('offlinePacks');
    if (savedPacks) {
      setOfflinePacks(JSON.parse(savedPacks));
    }

    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
    };
  }, []);

  const isOfflineActive = !isOnline || forceOfflineMode;

  // 2. Audio Processing
  const processAudioInput = useCallback((inputData: Float32Array) => {
    if (!sessionPromiseRef.current || !isTransmittingRef.current) return;

    const pcmData = float32To16BitPCM(inputData);
    const base64Data = arrayBufferToBase64(pcmData);

    sessionPromiseRef.current.then((session) => {
      session.sendRealtimeInput({
        media: {
          mimeType: `audio/pcm;rate=${INPUT_SAMPLE_RATE}`,
          data: base64Data,
        },
      });
    });
  }, []);

  // 3. Stop Connection (Robust Cleanup)
  const stopConnection = useCallback(() => {
    setIsConnecting(false);
    setIsConnected(false);
    setIsTransmitting(false);
    isTransmittingRef.current = false;

    setRealtimeInput(''); setRealtimeOutput('');

    // Clear Media Stream
    if (mediaStreamRef.current) {
        mediaStreamRef.current.getTracks().forEach(track => track.stop());
        mediaStreamRef.current = null;
    }

    // Clear Script Processor
    if (scriptProcessorRef.current) {
        scriptProcessorRef.current.disconnect();
        scriptProcessorRef.current = null;
    }

    // Close Audio Contexts
    if (inputAudioContextRef.current) {
        inputAudioContextRef.current.close();
        inputAudioContextRef.current = null;
    }
    if (outputAudioContextRef.current) {
        outputAudioContextRef.current.close();
        outputAudioContextRef.current = null;
    }

    // Close Active Session Explicitly
    if (activeSessionRef.current) {
        activeSessionRef.current.close();
        activeSessionRef.current = null;
    }
    sessionPromiseRef.current = null;

    if (recognitionRef.current) {
        recognitionRef.current.stop();
        // recognitionRef.current = null;
    }
  }, []);

  // 4. Toggle Handler
  const handleMicToggle = async () => {
    if (isConnecting) return;

    if (isConnected) {
      stopConnection();
      return;
    }

    setIsConnecting(true);
    setError(null);

    // --- Offline Mode ---
    if (isOfflineActive) {
      setTimeout(() => {
        setIsConnected(true);
        setIsTransmitting(true);
        isTransmittingRef.current = true;
        setIsConnecting(false);
        startOfflineRecognition();
      }, 300);
      return;
    }

    // --- Online Mode ---
    if (!aiClientRef.current) {
       setError("API Anahtarı eksik.");
       setIsConnecting(false);
       return;
    }

    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: {
        sampleRate: INPUT_SAMPLE_RATE,
        channelCount: 1,
        echoCancellation: true,
        noiseSuppression: true,
        autoGainControl: true
      }});
      mediaStreamRef.current = stream;

      const audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ 
        sampleRate: INPUT_SAMPLE_RATE 
      });
      inputAudioContextRef.current = audioCtx;

      const source = audioCtx.createMediaStreamSource(stream);
      const analyser = audioCtx.createAnalyser();
      analyser.fftSize = 256;
      inputAnalyserRef.current = analyser;

      const scriptProcessor = audioCtx.createScriptProcessor(4096, 1, 1);
      scriptProcessorRef.current = scriptProcessor;

      scriptProcessor.onaudioprocess = (e) => {
        const inputData = e.inputBuffer.getChannelData(0);
        processAudioInput(inputData);
      };

      source.connect(analyser);
      analyser.connect(scriptProcessor);
      scriptProcessor.connect(audioCtx.destination);

      const outCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ 
        sampleRate: OUTPUT_SAMPLE_RATE 
      });
      outputAudioContextRef.current = outCtx;
      const outAnalyser = outCtx.createAnalyser();
      outAnalyser.fftSize = 256;
      outputAnalyserRef.current = outAnalyser;
      outAnalyser.connect(outCtx.destination);

      const systemPrompt = `You are a simultaneous interpreter. Translate Turkish to ${targetLang}. Output audio only.`;

      const connectPromise = aiClientRef.current.live.connect({
        model: MODEL_NAME,
        config: {
          systemInstruction: systemPrompt,
          responseModalities: [Modality.AUDIO],
          inputAudioTranscription: {},
          outputAudioTranscription: {},
        },
        callbacks: {
          onopen: () => {
            console.log("Connected");
            setIsConnecting(false);
            setIsConnected(true);
            setIsTransmitting(true);
            isTransmittingRef.current = true;
            nextStartTimeRef.current = 0;
            setRealtimeInput('');
            setRealtimeOutput('');
          },
          onmessage: (msg: LiveServerMessage) => handleServerMessage(msg),
          onclose: () => {
            console.log("Closed");
            stopConnection();
          },
          onerror: (e) => {
            console.error(e);
            setError("Bağlantı hatası.");
            stopConnection();
          }
        }
      });

      sessionPromiseRef.current = connectPromise;
      connectPromise.then(session => {
          activeSessionRef.current = session;
      });

    } catch (e: any) {
      console.error(e);
      setError(`Hata: ${e.message}`);
      stopConnection();
    }
  };

  const handleServerMessage = (msg: LiveServerMessage) => {
    if (msg.serverContent?.inputTranscription) {
       currentInputTranscription.current += msg.serverContent.inputTranscription.text;
       setRealtimeInput(currentInputTranscription.current);
    }
    if (msg.serverContent?.outputTranscription) {
       currentOutputTranscription.current += msg.serverContent.outputTranscription.text;
       setRealtimeOutput(currentOutputTranscription.current);
    }
    if (msg.serverContent?.turnComplete) {
       const inputTx = currentInputTranscription.current.trim();
       const outputTx = currentOutputTranscription.current.trim();
       if (inputTx || outputTx) {
         addMessage('user', inputTx || '...');
         addMessage('model', outputTx || '...');
       }
       currentInputTranscription.current = '';
       currentOutputTranscription.current = '';
       setRealtimeInput('');
       setRealtimeOutput('');
    }
    const audioData = msg.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
    if (audioData) {
       playAudioResponse(audioData);
    }
  };

  // 5. Language Change Logic
  const handleLanguageChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
      const newLang = e.target.value as TargetLanguage;

      // Only restart connection if we are ONLINE (to update system prompt).
      // Offline mode uses dynamic TTS so no restart needed.
      if (isConnected && !isOfflineActive) {
          shouldReconnectRef.current = true;
          stopConnection();
      }
      setTargetLang(newLang);
  };

  // Auto-reconnect effect
  useEffect(() => {
      if (shouldReconnectRef.current) {
          shouldReconnectRef.current = false;
          handleMicToggle();
      }
  }, [targetLang]);

  // 6. Offline Logic
  const startOfflineRecognition = () => {
    if (!('webkitSpeechRecognition' in window)) return;
    try {
      const Recognition = (window as any).webkitSpeechRecognition;
      const recognition = new Recognition();
      recognition.lang = 'tr-TR'; 
      recognition.continuous = true; 
      recognition.interimResults = true; 

      recognition.onstart = () => setRealtimeInput('');
      recognition.onresult = (event: any) => {
        let interim = '';
        let final = '';
        for (let i = event.resultIndex; i < event.results.length; ++i) {
          if (event.results[i].isFinal) final += event.results[i][0].transcript;
          else interim += event.results[i][0].transcript;
        }
        setRealtimeInput(final || interim);
      };
      recognition.onerror = (e: any) => console.log(e);
      recognitionRef.current = recognition;
      recognition.start();
    } catch (e) {}
  };

  const stopOfflineRecognition = () => {
    if (recognitionRef.current) {
      recognitionRef.current.stop();
      setTimeout(() => {
        const text = realtimeInput.trim();
        if (text) {
           addMessage('user', text);
           setRealtimeInput('');
           setTimeout(() => {
             const mock = `(${targetLang}) ${text}`;
             addMessage('model', mock);
             speakOffline(text, targetLang);
           }, 500);
        }
      }, 500);
    }
  };

  const speakOffline = (text: string, lang: TargetLanguage) => {
    if ('speechSynthesis' in window) {
      const utterance = new SpeechSynthesisUtterance(text); 
      const langMap: Record<TargetLanguage, string> = {
        [TargetLanguage.ENGLISH]: 'en-US', [TargetLanguage.DUTCH]: 'nl-NL',
        [TargetLanguage.ARABIC]: 'ar-SA', [TargetLanguage.RUSSIAN]: 'ru-RU'
      };
      utterance.lang = langMap[lang];
      window.speechSynthesis.speak(utterance);
    }
  };

  // 7. Play Audio
  const playAudioResponse = async (base64Audio: string) => {
    if (!outputAudioContextRef.current || !outputAnalyserRef.current) return;
    const ctx = outputAudioContextRef.current;
    try {
      const arrayBuffer = base64ToArrayBuffer(base64Audio);
      const float32Data = pcm16ToFloat32(arrayBuffer);
      const audioBuffer = ctx.createBuffer(1, float32Data.length, OUTPUT_SAMPLE_RATE);
      audioBuffer.getChannelData(0).set(float32Data);
      const source = ctx.createBufferSource();
      source.buffer = audioBuffer;
      source.connect(outputAnalyserRef.current);
      source.start(Math.max(nextStartTimeRef.current, ctx.currentTime));
      nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime) + audioBuffer.duration;
      source.onended = () => sourcesRef.current.delete(source);
      sourcesRef.current.add(source);
    } catch (err) {}
  };

  const addMessage = (role: 'user' | 'model', text: string) => {
    setMessages(prev => [...prev, { id: Date.now().toString() + Math.random(), role, text, timestamp: new Date(), isFinal: true }]);
  };

  const chatContainerRef = useRef<HTMLDivElement>(null);
  useEffect(() => {
    if (chatContainerRef.current) chatContainerRef.current.scrollTop = chatContainerRef.current.scrollHeight;
  }, [messages, realtimeInput, realtimeOutput]);

  const downloadPack = (id: string) => {
    setOfflinePacks(prev => prev.map(p => p.id === id ? { ...p, progress: 5 } : p));
    let progress = 5;
    const interval = setInterval(() => {
      progress += 10;
      if (progress >= 100) {
        clearInterval(interval);
        setOfflinePacks(prev => {
          const newPacks = prev.map(p => p.id === id ? { ...p, progress: 100, downloaded: true } : p);
          localStorage.setItem('offlinePacks', JSON.stringify(newPacks));
          return newPacks;
        });
      } else {
        setOfflinePacks(prev => prev.map(p => p.id === id ? { ...p, progress } : p));
      }
    }, 200);
  };

  const deletePack = (id: string) => {
     setOfflinePacks(prev => {
       const newPacks = prev.map(p => p.id === id ? { ...p, progress: 0, downloaded: false } : p);
       localStorage.setItem('offlinePacks', JSON.stringify(newPacks));
       return newPacks;
     });
  };

  return (
    <div className="h-screen w-full bg-slate-950 text-slate-100 flex flex-col font-sans relative overflow-hidden select-none">

      {/* Dynamic Background */}
      <div className="absolute inset-0 z-0 pointer-events-none">
        <div className={`absolute top-[-10%] left-[-20%] w-[150vw] h-[60vh] rounded-full blur-[80px] opacity-20 transition-colors duration-1000 ${isOfflineActive ? 'bg-orange-600' : isConnected ? 'bg-indigo-600' : 'bg-blue-900'}`}></div>
        <div className="absolute bottom-[-10%] right-[-20%] w-[150vw] h-[50vh] bg-purple-900/10 rounded-full blur-[100px]"></div>
      </div>

      {/* Mobile Header */}
      <header className="z-20 h-16 flex items-center justify-between px-5 bg-gradient-to-b from-slate-950/80 to-transparent backdrop-blur-sm sticky top-0">
        <div className="flex items-center gap-2.5">
          <div className={`w-8 h-8 rounded-xl flex items-center justify-center bg-gradient-to-br shadow-lg ${isOfflineActive ? 'from-orange-500 to-red-600' : 'from-blue-500 to-indigo-600'}`}>
            <Sparkles size={16} className="text-white" />
          </div>
          <span className="font-bold text-lg tracking-tight">LinguaFlow</span>
        </div>
        <div className="flex items-center gap-3">
          <div className={`px-2.5 py-1 rounded-full text-[10px] font-bold border ${isOfflineActive ? 'bg-orange-500/10 border-orange-500/20 text-orange-400' : 'bg-blue-500/10 border-blue-500/20 text-blue-400'}`}>
            {isOfflineActive ? 'OFFLINE' : 'ONLINE'}
          </div>
          <button onClick={() => setShowSettings(true)} className="p-2 rounded-full bg-slate-800/50 hover:bg-slate-800 transition-colors">
            <Settings size={20} className="text-slate-400" />
          </button>
        </div>
      </header>

      {/* Main Chat Area */}
      <main className="flex-1 flex flex-col z-10 relative overflow-hidden">

        {/* Messages */}
        <div ref={chatContainerRef} className="flex-1 overflow-y-auto px-4 pt-2 pb-6 space-y-6 scroll-smooth">
          {error && (
            <div className="bg-red-500/10 border border-red-500/20 text-red-200 p-3 rounded-xl text-sm flex justify-between items-center mx-2">
              <span>{error}</span>
              <button onClick={() => setError(null)}><X size={16} /></button>
            </div>
          )}

          {messages.length === 0 && !realtimeInput && (
             <div className="h-full flex flex-col items-center justify-center text-slate-500 opacity-40 space-y-4">
                <Globe size={64} strokeWidth={1} />
                <p className="text-center text-sm px-10">
                  Konuşmaya başlamak için aşağıdaki mikrofona dokunun.
                </p>
             </div>
          )}

          {messages.map((msg) => (
            <div key={msg.id} className={`flex flex-col ${msg.role === 'user' ? 'items-start' : 'items-end'}`}>
              <span className="text-[10px] text-slate-500 mb-1 px-1">{msg.role === 'user' ? 'TR' : targetLang.toUpperCase()}</span>
              <div className={`max-w-[85%] px-5 py-3.5 shadow-sm text-[15px] leading-relaxed ${
                msg.role === 'user' 
                  ? 'bg-slate-800 text-slate-200 rounded-2xl rounded-tl-sm' 
                  : isOfflineActive 
                    ? 'bg-orange-600 text-white rounded-2xl rounded-tr-sm'
                    : 'bg-blue-600 text-white rounded-2xl rounded-tr-sm'
              }`}>
                {msg.text}
              </div>
            </div>
          ))}

          {/* Real-time Bubbles */}
          {(realtimeInput || realtimeOutput) && (
             <div className="space-y-4">
                {realtimeInput && (
                  <div className="flex flex-col items-start opacity-70">
                     <span className="text-[10px] text-blue-400 mb-1 px-1 animate-pulse">DİNLİYOR...</span>
                     <div className="max-w-[85%] px-5 py-3 bg-slate-800/50 border border-slate-700 border-dashed text-slate-300 rounded-2xl rounded-tl-sm">
                       {realtimeInput}
                     </div>
                  </div>
                )}
                {realtimeOutput && (
                  <div className="flex flex-col items-end opacity-70">
                     <span className="text-[10px] text-indigo-400 mb-1 px-1 animate-pulse">ÇEVİRİYOR...</span>
                     <div className="max-w-[85%] px-5 py-3 bg-blue-900/30 border border-blue-500/30 border-dashed text-blue-200 rounded-2xl rounded-tr-sm">
                       {realtimeOutput}
                     </div>
                  </div>
                )}
             </div>
          )}
        </div>

        {/* BOTTOM DOCK (Controls) */}
        <div className="bg-slate-950/80 backdrop-blur-xl border-t border-slate-800/50 px-6 pb-10 pt-4 z-30">

          {/* Visualizer Bar (Above Dock) */}
          <div className="h-10 w-full flex items-center justify-center mb-4">
            {isConnected ? (
              <div className="w-full h-full opacity-80">
                 <AudioVisualizer analyser={inputAnalyserRef.current} isActive={true} color={isOfflineActive ? '#f97316' : '#6366f1'} />
              </div>
            ) : (
              <div className="h-1 w-16 bg-slate-800 rounded-full"></div>
            )}
          </div>

          <div className="flex items-center justify-between max-w-sm mx-auto">

            {/* Left: Language Selector */}
            <div className="w-16 flex flex-col items-center gap-1">
               <div className="relative w-full">
                  <select 
                    value={targetLang}
                    onChange={handleLanguageChange}
                    className="appearance-none w-full h-12 bg-slate-800 border border-slate-700 text-slate-200 text-xs font-semibold rounded-2xl text-center pl-2 pr-6 focus:outline-none focus:ring-1 focus:ring-blue-500 transition-colors hover:border-slate-500"
                  >
                    <option value={TargetLanguage.ENGLISH}>EN</option>
                    <option value={TargetLanguage.DUTCH}>NL</option>
                    <option value={TargetLanguage.ARABIC}>AR</option>
                    <option value={TargetLanguage.RUSSIAN}>RU</option>
                  </select>
                  <ChevronDown size={12} className="absolute right-2 top-1/2 -translate-y-1/2 text-slate-500 pointer-events-none"/>
               </div>
               <span className="text-[10px] text-slate-500 font-medium">Hedef</span>
            </div>

            {/* Center: Main Mic Toggle */}
            <div className="relative -mt-6">
              {/* Ring Animation */}
              {isConnected && (
                <div className="absolute inset-0 rounded-full animate-ping opacity-30 bg-indigo-500"></div>
              )}

              <button
                onClick={handleMicToggle}
                className={`w-20 h-20 rounded-full flex items-center justify-center shadow-2xl transition-all duration-300 transform active:scale-95 ${
                  isConnecting
                    ? 'bg-slate-800 border-4 border-slate-700 cursor-wait'
                    : isConnected
                      ? isOfflineActive 
                        ? 'bg-orange-600 text-white shadow-orange-600/40 ring-4 ring-orange-900/50 scale-105' 
                        : 'bg-indigo-600 text-white shadow-indigo-600/40 ring-4 ring-indigo-900/50 scale-105'
                      : 'bg-slate-100 text-slate-900 hover:bg-white border-4 border-slate-300 shadow-white/10'
                }`}
              >
                {isConnecting ? (
                   <Loader2 size={32} className="animate-spin text-slate-400" />
                ) : isConnected ? (
                   <Square size={28} fill="currentColor" className="rounded-sm" />
                ) : (
                   <Mic size={32} strokeWidth={2.5} />
                )}
              </button>
            </div>

            {/* Right: Clear Button */}
            <div className="w-16 flex flex-col items-center gap-1">
               <button 
                 onClick={() => {
                   setMessages([]);
                   setRealtimeInput('');
                   setRealtimeOutput('');
                 }}
                 className="w-full h-12 flex items-center justify-center rounded-2xl bg-slate-800 border border-slate-700 text-slate-400 hover:text-white hover:bg-slate-700 transition-colors"
               >
                 <RotateCcw size={18} />
               </button>
               <span className="text-[10px] text-slate-500 font-medium">Temizle</span>
            </div>

          </div>
        </div>

      </main>

      {/* Settings Sheet (Bottom Sheet Style) */}
      {showSettings && (
        <div className="fixed inset-0 z-50 flex items-end justify-center bg-black/60 backdrop-blur-sm animate-fade-in" onClick={() => setShowSettings(false)}>
          <div className="bg-slate-900 border-t border-slate-700 w-full max-w-lg rounded-t-3xl shadow-2xl overflow-hidden max-h-[85vh] flex flex-col" onClick={e => e.stopPropagation()}>
             <div className="p-5 flex justify-between items-center bg-slate-800/50">
                <h2 className="text-lg font-bold flex items-center gap-2 text-white">
                  <Settings size={20} className="text-blue-400"/> Ayarlar
                </h2>
                <div className="w-12 h-1 bg-slate-700 rounded-full absolute top-3 left-1/2 -translate-x-1/2"></div>
                <button onClick={() => setShowSettings(false)} className="p-1 bg-slate-800 rounded-full text-slate-400"><X size={20} /></button>
             </div>

             <div className="p-6 overflow-y-auto space-y-6">
               {/* Mode */}
               <div className="bg-slate-800/30 p-4 rounded-2xl border border-slate-800">
                  <div className="flex justify-between items-center mb-2">
                    <span className="font-semibold text-slate-200">Çevrimdışı Mod</span>
                    <button onClick={() => { if(isConnected) stopConnection(); setForceOfflineMode(!forceOfflineMode); }} 
                      className={`w-12 h-7 rounded-full p-1 transition-colors ${forceOfflineMode ? 'bg-orange-500' : 'bg-slate-700'}`}>
                      <div className={`w-5 h-5 rounded-full bg-white transition-transform ${forceOfflineMode ? 'translate-x-5' : ''}`}></div>
                    </button>
                  </div>
                  <p className="text-xs text-slate-500">İnternet bağlantısı olmadan cihaz üzerinde basit çeviri yapın.</p>
               </div>

               {/* Packs */}
               <div>
                 <h3 className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-3 px-1">Dil Paketleri</h3>
                 <div className="space-y-3">
                    {offlinePacks.map(pack => (
                       <div key={pack.id} className="bg-slate-800/50 p-3 rounded-xl border border-slate-700/50 flex items-center justify-between">
                          <div className="flex-1">
                             <div className="flex items-center gap-2">
                               <span className="font-semibold text-sm">{pack.pair}</span>
                               <span className="text-[10px] bg-slate-700 text-slate-300 px-1.5 py-0.5 rounded">{pack.size}</span>
                             </div>
                             <div className="text-xs text-slate-400 mt-1">{pack.name}</div>
                             {pack.progress > 0 && pack.progress < 100 && (
                               <div className="w-full h-1 bg-slate-700 mt-2 rounded-full overflow-hidden">
                                  <div className="h-full bg-blue-500 transition-all" style={{width: `${pack.progress}%`}}></div>
                               </div>
                             )}
                          </div>

                          <div className="ml-4">
                             {pack.downloaded ? (
                               <button onClick={() => deletePack(pack.id)} className="p-2 text-green-400 bg-green-400/10 rounded-full hover:bg-red-500/20 hover:text-red-400 transition-colors">
                                  <Check size={18} />
                               </button>
                             ) : pack.progress > 0 ? (
                               <span className="text-xs font-bold text-blue-400">{pack.progress}%</span>
                             ) : (
                               <button onClick={() => downloadPack(pack.id)} className="p-2 bg-slate-700 hover:bg-blue-600 rounded-full text-white transition-colors">
                                 <Download size={18} />
                               </button>
                             )}
                          </div>
                       </div>
                    ))}
                 </div>
               </div>

               {/* Clear History */}
               <button onClick={() => { setMessages([]); setRealtimeInput(''); setRealtimeOutput(''); setShowSettings(false); }} className="w-full py-4 text-sm text-red-400 font-medium bg-red-500/10 rounded-2xl hover:bg-red-500/20 transition-colors flex items-center justify-center gap-2">
                  <Trash2 size={16} /> Geçmişi Temizle
               </button>
             </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';
import { TargetLanguage, ChatMessage, OfflinePack } from './types';
import { float32To16BitPCM, arrayBufferToBase64, base64ToArrayBuffer, pcm16ToFloat32 } from './utils/audioUtils';
import AudioVisualizer from './components/AudioVisualizer';
import { Mic, Globe, Settings, RotateCcw, Wifi, WifiOff, Download, Check, Trash2, X, Zap, Square, ChevronDown, Sparkles, Loader2 } from 'lucide-react';

// Live API Configuration
const MODEL_NAME = 'gemini-2.5-flash-native-audio-preview-09-2025';
const INPUT_SAMPLE_RATE = 16000;
const OUTPUT_SAMPLE_RATE = 24000;

// Mock Offline Packs
const INITIAL_PACKS: OfflinePack[] = [
  { id: 'tr-en', pair: 'TR ↔ EN', name: 'İngilizce', size: '45 MB', downloaded: false, progress: 0 },
  { id: 'tr-nl', pair: 'TR ↔ NL', name: 'Hollandaca', size: '42 MB', downloaded: false, progress: 0 },
  { id: 'tr-ar', pair: 'TR ↔ AR', name: 'Arapça', size: '50 MB', downloaded: false, progress: 0 },
  { id: 'tr-ru', pair: 'TR ↔ RU', name: 'Rusça', size: '48 MB', downloaded: false, progress: 0 },
];

const App: React.FC = () => {
  const [targetLang, setTargetLang] = useState<TargetLanguage>(TargetLanguage.ENGLISH);
  const [isConnected, setIsConnected] = useState(false);
  const [isConnecting, setIsConnecting] = useState(false);
  const [isTransmitting, setIsTransmitting] = useState(false);

  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [error, setError] = useState<string | null>(null);

  // Real-time Display States
  const [realtimeInput, setRealtimeInput] = useState('');
  const [realtimeOutput, setRealtimeOutput] = useState('');

  // Offline / Network State
  const [isOnline, setIsOnline] = useState(navigator.onLine);
  const [forceOfflineMode, setForceOfflineMode] = useState(false);
  const [showSettings, setShowSettings] = useState(false);
  const [offlinePacks, setOfflinePacks] = useState<OfflinePack[]>(INITIAL_PACKS);

  // Audio Context Refs
  const inputAudioContextRef = useRef<AudioContext | null>(null);
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const inputAnalyserRef = useRef<AnalyserNode | null>(null);
  const outputAnalyserRef = useRef<AnalyserNode | null>(null);
  const mediaStreamRef = useRef<MediaStream | null>(null);
  const scriptProcessorRef = useRef<ScriptProcessorNode | null>(null);

  // Logic Refs
  const aiClientRef = useRef<GoogleGenAI | null>(null);
  const sessionPromiseRef = useRef<Promise<any> | null>(null);
  const activeSessionRef = useRef<any>(null); // To store actual session object for cleanup
  const shouldReconnectRef = useRef(false); // Flag for auto-reconnect logic
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const isTransmittingRef = useRef(false);

  // Transcription Buffers
  const currentInputTranscription = useRef('');
  const currentOutputTranscription = useRef('');
  const recognitionRef = useRef<any>(null);

  // 1. Initialize & Network
  useEffect(() => {
    if (process.env.API_KEY) {
      aiClientRef.current = new GoogleGenAI({ apiKey: process.env.API_KEY });
    } else {
      setError("API Anahtarı bulunamadı.");
    }

    const handleOnline = () => setIsOnline(true);
    const handleOffline = () => {
      setIsOnline(false);
      stopConnection();
    };

    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);

    const savedPacks = localStorage.getItem('offlinePacks');
    if (savedPacks) {
      setOfflinePacks(JSON.parse(savedPacks));
    }

    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
    };
  }, []);

  const isOfflineActive = !isOnline || forceOfflineMode;

  // 2. Audio Processing
  const processAudioInput = useCallback((inputData: Float32Array) => {
    if (!sessionPromiseRef.current || !isTransmittingRef.current) return;

    const pcmData = float32To16BitPCM(inputData);
    const base64Data = arrayBufferToBase64(pcmData);

    sessionPromiseRef.current.then((session) => {
      session.sendRealtimeInput({
        media: {
          mimeType: `audio/pcm;rate=${INPUT_SAMPLE_RATE}`,
          data: base64Data,
        },
      });
    });
  }, []);

  // 3. Stop Connection (Robust Cleanup)
  const stopConnection = useCallback(() => {
    setIsConnecting(false);
    setIsConnected(false);
    setIsTransmitting(false);
    isTransmittingRef.current = false;

    setRealtimeInput(''); setRealtimeOutput('');

    // Clear Media Stream
    if (mediaStreamRef.current) {
        mediaStreamRef.current.getTracks().forEach(track => track.stop());
        mediaStreamRef.current = null;
    }

    // Clear Script Processor
    if (scriptProcessorRef.current) {
        scriptProcessorRef.current.disconnect();
        scriptProcessorRef.current = null;
    }

    // Close Audio Contexts
    if (inputAudioContextRef.current) {
        inputAudioContextRef.current.close();
        inputAudioContextRef.current = null;
    }
    if (outputAudioContextRef.current) {
        outputAudioContextRef.current.close();
        outputAudioContextRef.current = null;
    }

    // Close Active Session Explicitly
    if (activeSessionRef.current) {
        activeSessionRef.current.close();
        activeSessionRef.current = null;
    }
    sessionPromiseRef.current = null;

    if (recognitionRef.current) {
        recognitionRef.current.stop();
        // recognitionRef.current = null;
    }
  }, []);

  // 4. Toggle Handler
  const handleMicToggle = async () => {
    if (isConnecting) return;

    if (isConnected) {
      stopConnection();
      return;
    }

    setIsConnecting(true);
    setError(null);

    // --- Offline Mode ---
    if (isOfflineActive) {
      setTimeout(() => {
        setIsConnected(true);
        setIsTransmitting(true);
        isTransmittingRef.current = true;
        setIsConnecting(false);
        startOfflineRecognition();
      }, 300);
      return;
    }

    // --- Online Mode ---
    if (!aiClientRef.current) {
       setError("API Anahtarı eksik.");
       setIsConnecting(false);
       return;
    }

    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: {
        sampleRate: INPUT_SAMPLE_RATE,
        channelCount: 1,
        echoCancellation: true,
        noiseSuppression: true,
        autoGainControl: true
      }});
      mediaStreamRef.current = stream;

      const audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ 
        sampleRate: INPUT_SAMPLE_RATE 
      });
      inputAudioContextRef.current = audioCtx;

      const source = audioCtx.createMediaStreamSource(stream);
      const analyser = audioCtx.createAnalyser();
      analyser.fftSize = 256;
      inputAnalyserRef.current = analyser;

      const scriptProcessor = audioCtx.createScriptProcessor(4096, 1, 1);
      scriptProcessorRef.current = scriptProcessor;

      scriptProcessor.onaudioprocess = (e) => {
        const inputData = e.inputBuffer.getChannelData(0);
        processAudioInput(inputData);
      };

      source.connect(analyser);
      analyser.connect(scriptProcessor);
      scriptProcessor.connect(audioCtx.destination);

      const outCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ 
        sampleRate: OUTPUT_SAMPLE_RATE 
      });
      outputAudioContextRef.current = outCtx;
      const outAnalyser = outCtx.createAnalyser();
      outAnalyser.fftSize = 256;
      outputAnalyserRef.current = outAnalyser;
      outAnalyser.connect(outCtx.destination);

      // UPDATED STRICT SYSTEM PROMPT
      const systemPrompt = `You are a professional simultaneous interpreter. Your sole task is to translate the spoken Turkish input exactly into ${targetLang}. Do not answer questions, do not provide explanations, and do not engage in conversation. Just translate what is said strictly. Output audio only.`;

      const connectPromise = aiClientRef.current.live.connect({
        model: MODEL_NAME,
        config: {
          systemInstruction: systemPrompt,
          responseModalities: [Modality.AUDIO],
          inputAudioTranscription: {},
          outputAudioTranscription: {},
        },
        callbacks: {
          onopen: () => {
            console.log("Connected");
            setIsConnecting(false);
            setIsConnected(true);
            setIsTransmitting(true);
            isTransmittingRef.current = true;
            nextStartTimeRef.current = 0;
            setRealtimeInput('');
            setRealtimeOutput('');
          },
          onmessage: (msg: LiveServerMessage) => handleServerMessage(msg),
          onclose: () => {
            console.log("Closed");
            stopConnection();
          },
          onerror: (e) => {
            console.error(e);
            setError("Bağlantı hatası.");
            stopConnection();
          }
        }
      });

      sessionPromiseRef.current = connectPromise;
      connectPromise.then(session => {
          activeSessionRef.current = session;
      });

    } catch (e: any) {
      console.error(e);
      setError(`Hata: ${e.message}`);
      stopConnection();
    }
  };

  const handleServerMessage = (msg: LiveServerMessage) => {
    if (msg.serverContent?.inputTranscription) {
       currentInputTranscription.current += msg.serverContent.inputTranscription.text;
       setRealtimeInput(currentInputTranscription.current);
    }
    if (msg.serverContent?.outputTranscription) {
       currentOutputTranscription.current += msg.serverContent.outputTranscription.text;
       setRealtimeOutput(currentOutputTranscription.current);
    }
    if (msg.serverContent?.turnComplete) {
       const inputTx = currentInputTranscription.current.trim();
       const outputTx = currentOutputTranscription.current.trim();
       if (inputTx || outputTx) {
         addMessage('user', inputTx || '...');
         addMessage('model', outputTx || '...');
       }
       currentInputTranscription.current = '';
       currentOutputTranscription.current = '';
       setRealtimeInput('');
       setRealtimeOutput('');
    }
    const audioData = msg.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
    if (audioData) {
       playAudioResponse(audioData);
    }
  };

  // 5. Language Change Logic
  const handleLanguageChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
      const newLang = e.target.value as TargetLanguage;

      // Only restart connection if we are ONLINE (to update system prompt).
      // Offline mode uses dynamic TTS so no restart needed.
      if (isConnected && !isOfflineActive) {
          shouldReconnectRef.current = true;
          stopConnection();
      }
      setTargetLang(newLang);
  };

  // Auto-reconnect effect
  useEffect(() => {
      if (shouldReconnectRef.current) {
          shouldReconnectRef.current = false;
          handleMicToggle();
      }
  }, [targetLang]);

  // 6. Offline Logic
  const startOfflineRecognition = () => {
    if (!('webkitSpeechRecognition' in window)) return;
    try {
      const Recognition = (window as any).webkitSpeechRecognition;
      const recognition = new Recognition();
      recognition.lang = 'tr-TR'; 
      recognition.continuous = true; 
      recognition.interimResults = true; 

      recognition.onstart = () => setRealtimeInput('');
      recognition.onresult = (event: any) => {
        let interim = '';
        let final = '';
        for (let i = event.resultIndex; i < event.results.length; ++i) {
          if (event.results[i].isFinal) final += event.results[i][0].transcript;
          else interim += event.results[i][0].transcript;
        }
        setRealtimeInput(final || interim);
      };
      recognition.onerror = (e: any) => console.log(e);
      recognitionRef.current = recognition;
      recognition.start();
    } catch (e) {}
  };

  const stopOfflineRecognition = () => {
    if (recognitionRef.current) {
      recognitionRef.current.stop();
      setTimeout(() => {
        const text = realtimeInput.trim();
        if (text) {
           addMessage('user', text);
           setRealtimeInput('');
           setTimeout(() => {
             const mock = `(${targetLang}) ${text}`;
             addMessage('model', mock);
             speakOffline(text, targetLang);
           }, 500);
        }
      }, 500);
    }
  };

  const speakOffline = (text: string, lang: TargetLanguage) => {
    if ('speechSynthesis' in window) {
      const utterance = new SpeechSynthesisUtterance(text); 
      const langMap: Record<TargetLanguage, string> = {
        [TargetLanguage.ENGLISH]: 'en-US', [TargetLanguage.DUTCH]: 'nl-NL',
        [TargetLanguage.ARABIC]: 'ar-SA', [TargetLanguage.RUSSIAN]: 'ru-RU'
      };
      utterance.lang = langMap[lang];
      window.speechSynthesis.speak(utterance);
    }
  };

  // 7. Play Audio
  const playAudioResponse = async (base64Audio: string) => {
    if (!outputAudioContextRef.current || !outputAnalyserRef.current) return;
    const ctx = outputAudioContextRef.current;
    try {
      const arrayBuffer = base64ToArrayBuffer(base64Audio);
      const float32Data = pcm16ToFloat32(arrayBuffer);
      const audioBuffer = ctx.createBuffer(1, float32Data.length, OUTPUT_SAMPLE_RATE);
      audioBuffer.getChannelData(0).set(float32Data);
      const source = ctx.createBufferSource();
      source.buffer = audioBuffer;
      source.connect(outputAnalyserRef.current);
      source.start(Math.max(nextStartTimeRef.current, ctx.currentTime));
      nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime) + audioBuffer.duration;
      source.onended = () => sourcesRef.current.delete(source);
      sourcesRef.current.add(source);
    } catch (err) {}
  };

  const addMessage = (role: 'user' | 'model', text: string) => {
    setMessages(prev => [...prev, { id: Date.now().toString() + Math.random(), role, text, timestamp: new Date(), isFinal: true }]);
  };

  const chatContainerRef = useRef<HTMLDivElement>(null);
  useEffect(() => {
    if (chatContainerRef.current) chatContainerRef.current.scrollTop = chatContainerRef.current.scrollHeight;
  }, [messages, realtimeInput, realtimeOutput]);

  const downloadPack = (id: string) => {
    setOfflinePacks(prev => prev.map(p => p.id === id ? { ...p, progress: 5 } : p));
    let progress = 5;
    const interval = setInterval(() => {
      progress += 10;
      if (progress >= 100) {
        clearInterval(interval);
        setOfflinePacks(prev => {
          const newPacks = prev.map(p => p.id === id ? { ...p, progress: 100, downloaded: true } : p);
          localStorage.setItem('offlinePacks', JSON.stringify(newPacks));
          return newPacks;
        });
      } else {
        setOfflinePacks(prev => prev.map(p => p.id === id ? { ...p, progress } : p));
      }
    }, 200);
  };

  const deletePack = (id: string) => {
     setOfflinePacks(prev => {
       const newPacks = prev.map(p => p.id === id ? { ...p, progress: 0, downloaded: false } : p);
       localStorage.setItem('offlinePacks', JSON.stringify(newPacks));
       return newPacks;
     });
  };

  return (
    <div className="h-screen w-full bg-slate-950 text-slate-100 flex flex-col font-sans relative overflow-hidden select-none">

      {/* Dynamic Background */}
      <div className="absolute inset-0 z-0 pointer-events-none">
        <div className={`absolute top-[-10%] left-[-20%] w-[150vw] h-[60vh] rounded-full blur-[80px] opacity-20 transition-colors duration-1000 ${isOfflineActive ? 'bg-orange-600' : isConnected ? 'bg-indigo-600' : 'bg-blue-900'}`}></div>
        <div className="absolute bottom-[-10%] right-[-20%] w-[150vw] h-[50vh] bg-purple-900/10 rounded-full blur-[100px]"></div>
      </div>

      {/* Mobile Header */}
      <header className="z-20 h-16 flex items-center justify-between px-5 bg-gradient-to-b from-slate-950/80 to-transparent backdrop-blur-sm sticky top-0">
        <div className="flex items-center gap-2.5">
          <div className={`w-8 h-8 rounded-xl flex items-center justify-center bg-gradient-to-br shadow-lg ${isOfflineActive ? 'from-orange-500 to-red-600' : 'from-blue-500 to-indigo-600'}`}>
            <Sparkles size={16} className="text-white" />
          </div>
          <span className="font-bold text-lg tracking-tight">LinguaFlow</span>
        </div>
        <div className="flex items-center gap-3">
          <div className={`px-2.5 py-1 rounded-full text-[10px] font-bold border ${isOfflineActive ? 'bg-orange-500/10 border-orange-500/20 text-orange-400' : 'bg-blue-500/10 border-blue-500/20 text-blue-400'}`}>
            {isOfflineActive ? 'OFFLINE' : 'ONLINE'}
          </div>
          <button onClick={() => setShowSettings(true)} className="p-2 rounded-full bg-slate-800/50 hover:bg-slate-800 transition-colors">
            <Settings size={20} className="text-slate-400" />
          </button>
        </div>
      </header>

      {/* Main Chat Area */}
      <main className="flex-1 flex flex-col z-10 relative overflow-hidden">

        {/* Messages */}
        <div ref={chatContainerRef} className="flex-1 overflow-y-auto px-4 pt-2 pb-6 space-y-6 scroll-smooth">
          {error && (
            <div className="bg-red-500/10 border border-red-500/20 text-red-200 p-3 rounded-xl text-sm flex justify-between items-center mx-2">
              <span>{error}</span>
              <button onClick={() => setError(null)}><X size={16} /></button>
            </div>
          )}

          {messages.length === 0 && !realtimeInput && (
             <div className="h-full flex flex-col items-center justify-center text-slate-500 opacity-40 space-y-4">
                <Globe size={64} strokeWidth={1} />
                <p className="text-center text-sm px-10">
                  Konuşmaya başlamak için aşağıdaki mikrofona dokunun.
                </p>
             </div>
          )}

          {messages.map((msg) => (
            <div key={msg.id} className={`flex flex-col ${msg.role === 'user' ? 'items-start' : 'items-end'}`}>
              <span className="text-[10px] text-slate-500 mb-1 px-1">{msg.role === 'user' ? 'TR' : targetLang.toUpperCase()}</span>
              <div className={`max-w-[85%] px-5 py-3.5 shadow-sm text-[15px] leading-relaxed ${
                msg.role === 'user' 
                  ? 'bg-slate-800 text-slate-200 rounded-2xl rounded-tl-sm' 
                  : isOfflineActive 
                    ? 'bg-orange-600 text-white rounded-2xl rounded-tr-sm'
                    : 'bg-blue-600 text-white rounded-2xl rounded-tr-sm'
              }`}>
                {msg.text}
              </div>
            </div>
          ))}

          {/* Real-time Bubbles */}
          {(realtimeInput || realtimeOutput) && (
             <div className="space-y-4">
                {realtimeInput && (
                  <div className="flex flex-col items-start opacity-70">
                     <span className="text-[10px] text-blue-400 mb-1 px-1 animate-pulse">DİNLİYOR...</span>
                     <div className="max-w-[85%] px-5 py-3 bg-slate-800/50 border border-slate-700 border-dashed text-slate-300 rounded-2xl rounded-tl-sm">
                       {realtimeInput}
                     </div>
                  </div>
                )}
                {realtimeOutput && (
                  <div className="flex flex-col items-end opacity-70">
                     <span className="text-[10px] text-indigo-400 mb-1 px-1 animate-pulse">ÇEVİRİYOR...</span>
                     <div className="max-w-[85%] px-5 py-3 bg-blue-900/30 border border-blue-500/30 border-dashed text-blue-200 rounded-2xl rounded-tr-sm">
                       {realtimeOutput}
                     </div>
                  </div>
                )}
             </div>
          )}
        </div>

        {/* BOTTOM DOCK (Controls) */}
        <div className="bg-slate-950/80 backdrop-blur-xl border-t border-slate-800/50 px-6 pb-10 pt-4 z-30">

          {/* Visualizer Bar (Above Dock) */}
          <div className="h-10 w-full flex items-center justify-center mb-4">
            {isConnected ? (
              <div className="w-full h-full opacity-80">
                 <AudioVisualizer analyser={inputAnalyserRef.current} isActive={true} color={isOfflineActive ? '#f97316' : '#6366f1'} />
              </div>
            ) : (
              <div className="h-1 w-16 bg-slate-800 rounded-full"></div>
            )}
          </div>

          <div className="flex items-center justify-between max-w-sm mx-auto">

            {/* Left: Language Selector */}
            <div className="w-16 flex flex-col items-center gap-1">
               <div className="relative w-full">
                  <select 
                    value={targetLang}
                    onChange={handleLanguageChange}
                    className="appearance-none w-full h-12 bg-slate-800 border border-slate-700 text-slate-200 text-xs font-semibold rounded-2xl text-center pl-2 pr-6 focus:outline-none focus:ring-1 focus:ring-blue-500 transition-colors hover:border-slate-500"
                  >
                    <option value={TargetLanguage.ENGLISH}>EN</option>
                    <option value={TargetLanguage.DUTCH}>NL</option>
                    <option value={TargetLanguage.ARABIC}>AR</option>
                    <option value={TargetLanguage.RUSSIAN}>RU</option>
                  </select>
                  <ChevronDown size={12} className="absolute right-2 top-1/2 -translate-y-1/2 text-slate-500 pointer-events-none"/>
               </div>
               <span className="text-[10px] text-slate-500 font-medium">Hedef</span>
            </div>

            {/* Center: Main Mic Toggle */}
            <div className="relative -mt-6">
              {/* Ring Animation */}
              {isConnected && (
                <div className="absolute inset-0 rounded-full animate-ping opacity-30 bg-indigo-500"></div>
              )}

              <button
                onClick={handleMicToggle}
                className={`w-20 h-20 rounded-full flex items-center justify-center shadow-2xl transition-all duration-300 transform active:scale-95 ${
                  isConnecting
                    ? 'bg-slate-800 border-4 border-slate-700 cursor-wait'
                    : isConnected
                      ? isOfflineActive 
                        ? 'bg-orange-600 text-white shadow-orange-600/40 ring-4 ring-orange-900/50 scale-105' 
                        : 'bg-indigo-600 text-white shadow-indigo-600/40 ring-4 ring-indigo-900/50 scale-105'
                      : 'bg-slate-100 text-slate-900 hover:bg-white border-4 border-slate-300 shadow-white/10'
                }`}
              >
                {isConnecting ? (
                   <Loader2 size={32} className="animate-spin text-slate-400" />
                ) : isConnected ? (
                   <Square size={28} fill="currentColor" className="rounded-sm" />
                ) : (
                   <Mic size={32} strokeWidth={2.5} />
                )}
              </button>
            </div>

            {/* Right: Clear Button */}
            <div className="w-16 flex flex-col items-center gap-1">
               <button 
                 onClick={() => {
                   setMessages([]);
                   setRealtimeInput('');
                   setRealtimeOutput('');
                 }}
                 className="w-full h-12 flex items-center justify-center rounded-2xl bg-slate-800 border border-slate-700 text-slate-400 hover:text-white hover:bg-slate-700 transition-colors"
               >
                 <RotateCcw size={18} />
               </button>
               <span className="text-[10px] text-slate-500 font-medium">Temizle</span>
            </div>

          </div>
        </div>

      </main>

      {/* Settings Sheet (Bottom Sheet Style) */}
      {showSettings && (
        <div className="fixed inset-0 z-50 flex items-end justify-center bg-black/60 backdrop-blur-sm animate-fade-in" onClick={() => setShowSettings(false)}>
          <div className="bg-slate-900 border-t border-slate-700 w-full max-w-lg rounded-t-3xl shadow-2xl overflow-hidden max-h-[85vh] flex flex-col" onClick={e => e.stopPropagation()}>
             <div className="p-5 flex justify-between items-center bg-slate-800/50">
                <h2 className="text-lg font-bold flex items-center gap-2 text-white">
                  <Settings size={20} className="text-blue-400"/> Ayarlar
                </h2>
                <div className="w-12 h-1 bg-slate-700 rounded-full absolute top-3 left-1/2 -translate-x-1/2"></div>
                <button onClick={() => setShowSettings(false)} className="p-1 bg-slate-800 rounded-full text-slate-400"><X size={20} /></button>
             </div>

             <div className="p-6 overflow-y-auto space-y-6">
               {/* Mode */}
               <div className="bg-slate-800/30 p-4 rounded-2xl border border-slate-800">
                  <div className="flex justify-between items-center mb-2">
                    <span className="font-semibold text-slate-200">Çevrimdışı Mod</span>
                    <button onClick={() => { if(isConnected) stopConnection(); setForceOfflineMode(!forceOfflineMode); }} 
                      className={`w-12 h-7 rounded-full p-1 transition-colors ${forceOfflineMode ? 'bg-orange-500' : 'bg-slate-700'}`}>
                      <div className={`w-5 h-5 rounded-full bg-white transition-transform ${forceOfflineMode ? 'translate-x-5' : ''}`}></div>
                    </button>
                  </div>
                  <p className="text-xs text-slate-500">İnternet bağlantısı olmadan cihaz üzerinde basit çeviri yapın.</p>
               </div>

               {/* Packs */}
               <div>
                 <h3 className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-3 px-1">Dil Paketleri</h3>
                 <div className="space-y-3">
                    {offlinePacks.map(pack => (
                       <div key={pack.id} className="bg-slate-800/50 p-3 rounded-xl border border-slate-700/50 flex items-center justify-between">
                          <div className="flex-1">
                             <div className="flex items-center gap-2">
                               <span className="font-semibold text-sm">{pack.pair}</span>
                               <span className="text-[10px] bg-slate-700 text-slate-300 px-1.5 py-0.5 rounded">{pack.size}</span>
                             </div>
                             <div className="text-xs text-slate-400 mt-1">{pack.name}</div>
                             {pack.progress > 0 && pack.progress < 100 && (
                               <div className="w-full h-1 bg-slate-700 mt-2 rounded-full overflow-hidden">
                                  <div className="h-full bg-blue-500 transition-all" style={{width: `${pack.progress}%`}}></div>
                               </div>
                             )}
                          </div>

                          <div className="ml-4">
                             {pack.downloaded ? (
                               <button onClick={() => deletePack(pack.id)} className="p-2 text-green-400 bg-green-400/10 rounded-full hover:bg-red-500/20 hover:text-red-400 transition-colors">
                                  <Check size={18} />
                               </button>
                             ) : pack.progress > 0 ? (
                               <span className="text-xs font-bold text-blue-400">{pack.progress}%</span>
                             ) : (
                               <button onClick={() => downloadPack(pack.id)} className="p-2 bg-slate-700 hover:bg-blue-600 rounded-full text-white transition-colors">
                                 <Download size={18} />
                               </button>
                             )}
                          </div>
                       </div>
                    ))}
                 </div>
               </div>

               {/* Clear History */}
               <button onClick={() => { setMessages([]); setRealtimeInput(''); setRealtimeOutput(''); setShowSettings(false); }} className="w-full py-4 text-sm text-red-400 font-medium bg-red-500/10 rounded-2xl hover:bg-red-500/20 transition-colors flex items-center justify-center gap-2">
                  <Trash2 size={16} /> Geçmişi Temizle
               </button>
             </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';
import { TargetLanguage, ChatMessage, OfflinePack } from './types';
import { float32To16BitPCM, arrayBufferToBase64, base64ToArrayBuffer, pcm16ToFloat32 } from './utils/audioUtils';
import AudioVisualizer from './components/AudioVisualizer';
import { Mic, Globe, Settings, RotateCcw, Wifi, WifiOff, Download, Check, Trash2, X, Zap, Square, ChevronDown, Sparkles, Loader2 } from 'lucide-react';

// Live API Configuration
const MODEL_NAME = 'gemini-2.5-flash-native-audio-preview-09-2025';
const INPUT_SAMPLE_RATE = 16000;
const OUTPUT_SAMPLE_RATE = 24000;

// Mock Offline Packs
const INITIAL_PACKS: OfflinePack[] = [
  { id: 'tr-en', pair: 'TR ↔ EN', name: 'İngilizce', size: '45 MB', downloaded: false, progress: 0 },
  { id: 'tr-nl', pair: 'TR ↔ NL', name: 'Hollandaca', size: '42 MB', downloaded: false, progress: 0 },
  { id: 'tr-ar', pair: 'TR ↔ AR', name: 'Arapça', size: '50 MB', downloaded: false, progress: 0 },
  { id: 'tr-ru', pair: 'TR ↔ RU', name: 'Rusça', size: '48 MB', downloaded: false, progress: 0 },
];

const App: React.FC = () => {
  const [targetLang, setTargetLang] = useState<TargetLanguage>(TargetLanguage.ENGLISH);
  const [isConnected, setIsConnected] = useState(false);
  const [isConnecting, setIsConnecting] = useState(false);
  const [isTransmitting, setIsTransmitting] = useState(false);

  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [error, setError] = useState<string | null>(null);

  // Real-time Display States
  const [realtimeInput, setRealtimeInput] = useState('');
  const [realtimeOutput, setRealtimeOutput] = useState('');

  // Offline / Network State
  const [isOnline, setIsOnline] = useState(navigator.onLine);
  const [forceOfflineMode, setForceOfflineMode] = useState(false);
  const [showSettings, setShowSettings] = useState(false);
  const [offlinePacks, setOfflinePacks] = useState<OfflinePack[]>(INITIAL_PACKS);

  // Audio Context Refs
  const inputAudioContextRef = useRef<AudioContext | null>(null);
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const inputAnalyserRef = useRef<AnalyserNode | null>(null);
  const outputAnalyserRef = useRef<AnalyserNode | null>(null);
  const mediaStreamRef = useRef<MediaStream | null>(null);
  const scriptProcessorRef = useRef<ScriptProcessorNode | null>(null);

  // Logic Refs
  const aiClientRef = useRef<GoogleGenAI | null>(null);
  const sessionPromiseRef = useRef<Promise<any> | null>(null);
  const activeSessionRef = useRef<any>(null); // To store actual session object for cleanup
  const shouldReconnectRef = useRef(false); // Flag for auto-reconnect logic
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const isTransmittingRef = useRef(false);

  // Transcription Buffers
  const currentInputTranscription = useRef('');
  const currentOutputTranscription = useRef('');
  const recognitionRef = useRef<any>(null);

  // 1. Initialize & Network
  useEffect(() => {
    if (process.env.API_KEY) {
      aiClientRef.current = new GoogleGenAI({ apiKey: process.env.API_KEY });
    } else {
      setError("API Anahtarı bulunamadı.");
    }

    const handleOnline = () => setIsOnline(true);
    const handleOffline = () => {
      setIsOnline(false);
      stopConnection();
    };

    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);

    const savedPacks = localStorage.getItem('offlinePacks');
    if (savedPacks) {
      setOfflinePacks(JSON.parse(savedPacks));
    }

    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
    };
  }, []);

  const isOfflineActive = !isOnline || forceOfflineMode;

  // 2. Audio Processing
  const processAudioInput = useCallback((inputData: Float32Array) => {
    if (!sessionPromiseRef.current || !isTransmittingRef.current) return;

    const pcmData = float32To16BitPCM(inputData);
    const base64Data = arrayBufferToBase64(pcmData);

    sessionPromiseRef.current.then((session) => {
      session.sendRealtimeInput({
        media: {
          mimeType: `audio/pcm;rate=${INPUT_SAMPLE_RATE}`,
          data: base64Data,
        },
      });
    });
  }, []);

  // 3. Stop Connection (Robust Cleanup)
  const stopConnection = useCallback(() => {
    setIsConnecting(false);
    setIsConnected(false);
    setIsTransmitting(false);
    isTransmittingRef.current = false;

    setRealtimeInput(''); setRealtimeOutput('');

    // Clear Media Stream
    if (mediaStreamRef.current) {
        mediaStreamRef.current.getTracks().forEach(track => track.stop());
        mediaStreamRef.current = null;
    }

    // Clear Script Processor
    if (scriptProcessorRef.current) {
        scriptProcessorRef.current.disconnect();
        scriptProcessorRef.current = null;
    }

    // Close Audio Contexts
    if (inputAudioContextRef.current) {
        inputAudioContextRef.current.close();
        inputAudioContextRef.current = null;
    }
    if (outputAudioContextRef.current) {
        outputAudioContextRef.current.close();
        outputAudioContextRef.current = null;
    }

    // Close Active Session Explicitly
    if (activeSessionRef.current) {
        activeSessionRef.current.close();
        activeSessionRef.current = null;
    }
    sessionPromiseRef.current = null;

    if (recognitionRef.current) {
        recognitionRef.current.stop();
        // recognitionRef.current = null;
    }
  }, []);

  // 4. Toggle Handler
  const handleMicToggle = async () => {
    if (isConnecting) return;

    if (isConnected) {
      stopConnection();
      return;
    }

    setIsConnecting(true);
    setError(null);

    // --- Offline Mode ---
    if (isOfflineActive) {
      setTimeout(() => {
        setIsConnected(true);
        setIsTransmitting(true);
        isTransmittingRef.current = true;
        setIsConnecting(false);
        startOfflineRecognition();
      }, 300);
      return;
    }

    // --- Online Mode ---
    if (!aiClientRef.current) {
       setError("API Anahtarı eksik.");
       setIsConnecting(false);
       return;
    }

    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: {
        sampleRate: INPUT_SAMPLE_RATE,
        channelCount: 1,
        echoCancellation: true,
        noiseSuppression: true,
        autoGainControl: true
      }});
      mediaStreamRef.current = stream;

      const audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ 
        sampleRate: INPUT_SAMPLE_RATE 
      });
      inputAudioContextRef.current = audioCtx;

      const source = audioCtx.createMediaStreamSource(stream);
      const analyser = audioCtx.createAnalyser();
      analyser.fftSize = 256;
      inputAnalyserRef.current = analyser;

      const scriptProcessor = audioCtx.createScriptProcessor(4096, 1, 1);
      scriptProcessorRef.current = scriptProcessor;

      scriptProcessor.onaudioprocess = (e) => {
        const inputData = e.inputBuffer.getChannelData(0);
        processAudioInput(inputData);
      };

      source.connect(analyser);
      analyser.connect(scriptProcessor);
      scriptProcessor.connect(audioCtx.destination);

      const outCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ 
        sampleRate: OUTPUT_SAMPLE_RATE 
      });
      outputAudioContextRef.current = outCtx;
      const outAnalyser = outCtx.createAnalyser();
      outAnalyser.fftSize = 256;
      outputAnalyserRef.current = outAnalyser;
      outAnalyser.connect(outCtx.destination);

      // UPDATED STRICT SYSTEM PROMPT FOR SEMANTIC INTEGRITY
      const systemPrompt = `You are an expert simultaneous interpreter. Your task is to translate spoken Turkish into ${targetLang} accurately and naturally.

Guidelines:
1. Semantic Integrity: Ensure the translation captures the full meaning and context of the sentence. Avoid robotic or word-for-word literal translations that lose the intended meaning.
2. Natural Flow: The output should sound fluent and natural to a native speaker of ${targetLang}.
3. Strict Translation Only: Do NOT answer questions, do NOT engage in conversation, and do NOT add explanations. Only output the translation.
4. Input Handling: Translate what is heard. If the input is silence or noise, wait for speech.

Output strictly audio of the translation.`;

      const connectPromise = aiClientRef.current.live.connect({
        model: MODEL_NAME,
        config: {
          systemInstruction: systemPrompt,
          responseModalities: [Modality.AUDIO],
          inputAudioTranscription: {},
          outputAudioTranscription: {},
        },
        callbacks: {
          onopen: () => {
            console.log("Connected");
            setIsConnecting(false);
            setIsConnected(true);
            setIsTransmitting(true);
            isTransmittingRef.current = true;
            nextStartTimeRef.current = 0;
            setRealtimeInput('');
            setRealtimeOutput('');
          },
          onmessage: (msg: LiveServerMessage) => handleServerMessage(msg),
          onclose: () => {
            console.log("Closed");
            stopConnection();
          },
          onerror: (e) => {
            console.error(e);
            setError("Bağlantı hatası.");
            stopConnection();
          }
        }
      });

      sessionPromiseRef.current = connectPromise;
      connectPromise.then(session => {
          activeSessionRef.current = session;
      });

    } catch (e: any) {
      console.error(e);
      setError(`Hata: ${e.message}`);
      stopConnection();
    }
  };

  const handleServerMessage = (msg: LiveServerMessage) => {
    if (msg.serverContent?.inputTranscription) {
       currentInputTranscription.current += msg.serverContent.inputTranscription.text;
       setRealtimeInput(currentInputTranscription.current);
    }
    if (msg.serverContent?.outputTranscription) {
       currentOutputTranscription.current += msg.serverContent.outputTranscription.text;
       setRealtimeOutput(currentOutputTranscription.current);
    }
    if (msg.serverContent?.turnComplete) {
       const inputTx = currentInputTranscription.current.trim();
       const outputTx = currentOutputTranscription.current.trim();
       if (inputTx || outputTx) {
         addMessage('user', inputTx || '...');
         addMessage('model', outputTx || '...');
       }
       currentInputTranscription.current = '';
       currentOutputTranscription.current = '';
       setRealtimeInput('');
       setRealtimeOutput('');
    }
    const audioData = msg.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
    if (audioData) {
       playAudioResponse(audioData);
    }
  };

  // 5. Language Change Logic
  const handleLanguageChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
      const newLang = e.target.value as TargetLanguage;

      // Only restart connection if we are ONLINE (to update system prompt).
      // Offline mode uses dynamic TTS so no restart needed.
      if (isConnected && !isOfflineActive) {
          shouldReconnectRef.current = true;
          stopConnection();
      }
      setTargetLang(newLang);
  };

  // Auto-reconnect effect
  useEffect(() => {
      if (shouldReconnectRef.current) {
          shouldReconnectRef.current = false;
          handleMicToggle();
      }
  }, [targetLang]);

  // 6. Offline Logic
  const startOfflineRecognition = () => {
    if (!('webkitSpeechRecognition' in window)) return;
    try {
      const Recognition = (window as any).webkitSpeechRecognition;
      const recognition = new Recognition();
      recognition.lang = 'tr-TR'; 
      recognition.continuous = true; 
      recognition.interimResults = true; 

      recognition.onstart = () => setRealtimeInput('');
      recognition.onresult = (event: any) => {
        let interim = '';
        let final = '';
        for (let i = event.resultIndex; i < event.results.length; ++i) {
          if (event.results[i].isFinal) final += event.results[i][0].transcript;
          else interim += event.results[i][0].transcript;
        }
        setRealtimeInput(final || interim);
      };
      recognition.onerror = (e: any) => console.log(e);
      recognitionRef.current = recognition;
      recognition.start();
    } catch (e) {}
  };

  const stopOfflineRecognition = () => {
    if (recognitionRef.current) {
      recognitionRef.current.stop();
      setTimeout(() => {
        const text = realtimeInput.trim();
        if (text) {
           addMessage('user', text);
           setRealtimeInput('');
           setTimeout(() => {
             const mock = `(${targetLang}) ${text}`;
             addMessage('model', mock);
             speakOffline(text, targetLang);
           }, 500);
        }
      }, 500);
    }
  };

  const speakOffline = (text: string, lang: TargetLanguage) => {
    if ('speechSynthesis' in window) {
      const utterance = new SpeechSynthesisUtterance(text); 
      const langMap: Record<TargetLanguage, string> = {
        [TargetLanguage.ENGLISH]: 'en-US', [TargetLanguage.DUTCH]: 'nl-NL',
        [TargetLanguage.ARABIC]: 'ar-SA', [TargetLanguage.RUSSIAN]: 'ru-RU'
      };
      utterance.lang = langMap[lang];
      window.speechSynthesis.speak(utterance);
    }
  };

  // 7. Play Audio
  const playAudioResponse = async (base64Audio: string) => {
    if (!outputAudioContextRef.current || !outputAnalyserRef.current) return;
    const ctx = outputAudioContextRef.current;
    try {
      const arrayBuffer = base64ToArrayBuffer(base64Audio);
      const float32Data = pcm16ToFloat32(arrayBuffer);
      const audioBuffer = ctx.createBuffer(1, float32Data.length, OUTPUT_SAMPLE_RATE);
      audioBuffer.getChannelData(0).set(float32Data);
      const source = ctx.createBufferSource();
      source.buffer = audioBuffer;
      source.connect(outputAnalyserRef.current);
      source.start(Math.max(nextStartTimeRef.current, ctx.currentTime));
      nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime) + audioBuffer.duration;
      source.onended = () => sourcesRef.current.delete(source);
      sourcesRef.current.add(source);
    } catch (err) {}
  };

  const addMessage = (role: 'user' | 'model', text: string) => {
    setMessages(prev => [...prev, { id: Date.now().toString() + Math.random(), role, text, timestamp: new Date(), isFinal: true }]);
  };

  const chatContainerRef = useRef<HTMLDivElement>(null);
  useEffect(() => {
    if (chatContainerRef.current) chatContainerRef.current.scrollTop = chatContainerRef.current.scrollHeight;
  }, [messages, realtimeInput, realtimeOutput]);

  const downloadPack = (id: string) => {
    setOfflinePacks(prev => prev.map(p => p.id === id ? { ...p, progress: 5 } : p));
    let progress = 5;
    const interval = setInterval(() => {
      progress += 10;
      if (progress >= 100) {
        clearInterval(interval);
        setOfflinePacks(prev => {
          const newPacks = prev.map(p => p.id === id ? { ...p, progress: 100, downloaded: true } : p);
          localStorage.setItem('offlinePacks', JSON.stringify(newPacks));
          return newPacks;
        });
      } else {
        setOfflinePacks(prev => prev.map(p => p.id === id ? { ...p, progress } : p));
      }
    }, 200);
  };

  const deletePack = (id: string) => {
     setOfflinePacks(prev => {
       const newPacks = prev.map(p => p.id === id ? { ...p, progress: 0, downloaded: false } : p);
       localStorage.setItem('offlinePacks', JSON.stringify(newPacks));
       return newPacks;
     });
  };

  return (
    <div className="h-screen w-full bg-slate-950 text-slate-100 flex flex-col font-sans relative overflow-hidden select-none">

      {/* Dynamic Background */}
      <div className="absolute inset-0 z-0 pointer-events-none">
        <div className={`absolute top-[-10%] left-[-20%] w-[150vw] h-[60vh] rounded-full blur-[80px] opacity-20 transition-colors duration-1000 ${isOfflineActive ? 'bg-orange-600' : isConnected ? 'bg-indigo-600' : 'bg-blue-900'}`}></div>
        <div className="absolute bottom-[-10%] right-[-20%] w-[150vw] h-[50vh] bg-purple-900/10 rounded-full blur-[100px]"></div>
      </div>

      {/* Mobile Header */}
      <header className="z-20 h-16 flex items-center justify-between px-5 bg-gradient-to-b from-slate-950/80 to-transparent backdrop-blur-sm sticky top-0">
        <div className="flex items-center gap-2.5">
          <div className={`w-8 h-8 rounded-xl flex items-center justify-center bg-gradient-to-br shadow-lg ${isOfflineActive ? 'from-orange-500 to-red-600' : 'from-blue-500 to-indigo-600'}`}>
            <Sparkles size={16} className="text-white" />
          </div>
          <span className="font-bold text-lg tracking-tight">LinguaFlow</span>
        </div>
        <div className="flex items-center gap-3">
          <div className={`px-2.5 py-1 rounded-full text-[10px] font-bold border ${isOfflineActive ? 'bg-orange-500/10 border-orange-500/20 text-orange-400' : 'bg-blue-500/10 border-blue-500/20 text-blue-400'}`}>
            {isOfflineActive ? 'OFFLINE' : 'ONLINE'}
          </div>
          <button onClick={() => setShowSettings(true)} className="p-2 rounded-full bg-slate-800/50 hover:bg-slate-800 transition-colors">
            <Settings size={20} className="text-slate-400" />
          </button>
        </div>
      </header>

      {/* Main Chat Area */}
      <main className="flex-1 flex flex-col z-10 relative overflow-hidden">

        {/* Messages */}
        <div ref={chatContainerRef} className="flex-1 overflow-y-auto px-4 pt-2 pb-6 space-y-6 scroll-smooth">
          {error && (
            <div className="bg-red-500/10 border border-red-500/20 text-red-200 p-3 rounded-xl text-sm flex justify-between items-center mx-2">
              <span>{error}</span>
              <button onClick={() => setError(null)}><X size={16} /></button>
            </div>
          )}

          {messages.length === 0 && !realtimeInput && (
             <div className="h-full flex flex-col items-center justify-center text-slate-500 opacity-40 space-y-4">
                <Globe size={64} strokeWidth={1} />
                <p className="text-center text-sm px-10">
                  Konuşmaya başlamak için aşağıdaki mikrofona dokunun.
                </p>
             </div>
          )}

          {messages.map((msg) => (
            <div key={msg.id} className={`flex flex-col ${msg.role === 'user' ? 'items-start' : 'items-end'}`}>
              <span className="text-[10px] text-slate-500 mb-1 px-1">{msg.role === 'user' ? 'TR' : targetLang.toUpperCase()}</span>
              <div className={`max-w-[85%] px-5 py-3.5 shadow-sm text-[15px] leading-relaxed ${
                msg.role === 'user' 
                  ? 'bg-slate-800 text-slate-200 rounded-2xl rounded-tl-sm' 
                  : isOfflineActive 
                    ? 'bg-orange-600 text-white rounded-2xl rounded-tr-sm'
                    : 'bg-blue-600 text-white rounded-2xl rounded-tr-sm'
              }`}>
                {msg.text}
              </div>
            </div>
          ))}

          {/* Real-time Bubbles */}
          {(realtimeInput || realtimeOutput) && (
             <div className="space-y-4">
                {realtimeInput && (
                  <div className="flex flex-col items-start opacity-70">
                     <span className="text-[10px] text-blue-400 mb-1 px-1 animate-pulse">DİNLİYOR...</span>
                     <div className="max-w-[85%] px-5 py-3 bg-slate-800/50 border border-slate-700 border-dashed text-slate-300 rounded-2xl rounded-tl-sm">
                       {realtimeInput}
                     </div>
                  </div>
                )}
                {realtimeOutput && (
                  <div className="flex flex-col items-end opacity-70">
                     <span className="text-[10px] text-indigo-400 mb-1 px-1 animate-pulse">ÇEVİRİYOR...</span>
                     <div className="max-w-[85%] px-5 py-3 bg-blue-900/30 border border-blue-500/30 border-dashed text-blue-200 rounded-2xl rounded-tr-sm">
                       {realtimeOutput}
                     </div>
                  </div>
                )}
             </div>
          )}
        </div>

        {/* BOTTOM DOCK (Controls) */}
        <div className="bg-slate-950/80 backdrop-blur-xl border-t border-slate-800/50 px-6 pb-10 pt-4 z-30">

          {/* Visualizer Bar (Above Dock) */}
          <div className="h-10 w-full flex items-center justify-center mb-4">
            {isConnected ? (
              <div className="w-full h-full opacity-80">
                 <AudioVisualizer analyser={inputAnalyserRef.current} isActive={true} color={isOfflineActive ? '#f97316' : '#6366f1'} />
              </div>
            ) : (
              <div className="h-1 w-16 bg-slate-800 rounded-full"></div>
            )}
          </div>

          <div className="flex items-center justify-between max-w-sm mx-auto">

            {/* Left: Language Selector */}
            <div className="w-16 flex flex-col items-center gap-1">
               <div className="relative w-full">
                  <select 
                    value={targetLang}
                    onChange={handleLanguageChange}
                    className="appearance-none w-full h-12 bg-slate-800 border border-slate-700 text-slate-200 text-xs font-semibold rounded-2xl text-center pl-2 pr-6 focus:outline-none focus:ring-1 focus:ring-blue-500 transition-colors hover:border-slate-500"
                  >
                    <option value={TargetLanguage.ENGLISH}>EN</option>
                    <option value={TargetLanguage.DUTCH}>NL</option>
                    <option value={TargetLanguage.ARABIC}>AR</option>
                    <option value={TargetLanguage.RUSSIAN}>RU</option>
                  </select>
                  <ChevronDown size={12} className="absolute right-2 top-1/2 -translate-y-1/2 text-slate-500 pointer-events-none"/>
               </div>
               <span className="text-[10px] text-slate-500 font-medium">Hedef</span>
            </div>

            {/* Center: Main Mic Toggle */}
            <div className="relative -mt-6">
              {/* Ring Animation */}
              {isConnected && (
                <div className="absolute inset-0 rounded-full animate-ping opacity-30 bg-indigo-500"></div>
              )}

              <button
                onClick={handleMicToggle}
                className={`w-20 h-20 rounded-full flex items-center justify-center shadow-2xl transition-all duration-300 transform active:scale-95 ${
                  isConnecting
                    ? 'bg-slate-800 border-4 border-slate-700 cursor-wait'
                    : isConnected
                      ? isOfflineActive 
                        ? 'bg-orange-600 text-white shadow-orange-600/40 ring-4 ring-orange-900/50 scale-105' 
                        : 'bg-indigo-600 text-white shadow-indigo-600/40 ring-4 ring-indigo-900/50 scale-105'
                      : 'bg-slate-100 text-slate-900 hover:bg-white border-4 border-slate-300 shadow-white/10'
                }`}
              >
                {isConnecting ? (
                   <Loader2 size={32} className="animate-spin text-slate-400" />
                ) : isConnected ? (
                   <Square size={28} fill="currentColor" className="rounded-sm" />
                ) : (
                   <Mic size={32} strokeWidth={2.5} />
                )}
              </button>
            </div>

            {/* Right: Clear Button */}
            <div className="w-16 flex flex-col items-center gap-1">
               <button 
                 onClick={() => {
                   setMessages([]);
                   setRealtimeInput('');
                   setRealtimeOutput('');
                 }}
                 className="w-full h-12 flex items-center justify-center rounded-2xl bg-slate-800 border border-slate-700 text-slate-400 hover:text-white hover:bg-slate-700 transition-colors"
               >
                 <RotateCcw size={18} />
               </button>
               <span className="text-[10px] text-slate-500 font-medium">Temizle</span>
            </div>

          </div>
        </div>

      </main>

      {/* Settings Sheet (Bottom Sheet Style) */}
      {showSettings && (
        <div className="fixed inset-0 z-50 flex items-end justify-center bg-black/60 backdrop-blur-sm animate-fade-in" onClick={() => setShowSettings(false)}>
          <div className="bg-slate-900 border-t border-slate-700 w-full max-w-lg rounded-t-3xl shadow-2xl overflow-hidden max-h-[85vh] flex flex-col" onClick={e => e.stopPropagation()}>
             <div className="p-5 flex justify-between items-center bg-slate-800/50">
                <h2 className="text-lg font-bold flex items-center gap-2 text-white">
                  <Settings size={20} className="text-blue-400"/> Ayarlar
                </h2>
                <div className="w-12 h-1 bg-slate-700 rounded-full absolute top-3 left-1/2 -translate-x-1/2"></div>
                <button onClick={() => setShowSettings(false)} className="p-1 bg-slate-800 rounded-full text-slate-400"><X size={20} /></button>
             </div>

             <div className="p-6 overflow-y-auto space-y-6">
               {/* Mode */}
               <div className="bg-slate-800/30 p-4 rounded-2xl border border-slate-800">
                  <div className="flex justify-between items-center mb-2">
                    <span className="font-semibold text-slate-200">Çevrimdışı Mod</span>
                    <button onClick={() => { if(isConnected) stopConnection(); setForceOfflineMode(!forceOfflineMode); }} 
                      className={`w-12 h-7 rounded-full p-1 transition-colors ${forceOfflineMode ? 'bg-orange-500' : 'bg-slate-700'}`}>
                      <div className={`w-5 h-5 rounded-full bg-white transition-transform ${forceOfflineMode ? 'translate-x-5' : ''}`}></div>
                    </button>
                  </div>
                  <p className="text-xs text-slate-500">İnternet bağlantısı olmadan cihaz üzerinde basit çeviri yapın.</p>
               </div>

               {/* Packs */}
               <div>
                 <h3 className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-3 px-1">Dil Paketleri</h3>
                 <div className="space-y-3">
                    {offlinePacks.map(pack => (
                       <div key={pack.id} className="bg-slate-800/50 p-3 rounded-xl border border-slate-700/50 flex items-center justify-between">
                          <div className="flex-1">
                             <div className="flex items-center gap-2">
                               <span className="font-semibold text-sm">{pack.pair}</span>
                               <span className="text-[10px] bg-slate-700 text-slate-300 px-1.5 py-0.5 rounded">{pack.size}</span>
                             </div>
                             <div className="text-xs text-slate-400 mt-1">{pack.name}</div>
                             {pack.progress > 0 && pack.progress < 100 && (
                               <div className="w-full h-1 bg-slate-700 mt-2 rounded-full overflow-hidden">
                                  <div className="h-full bg-blue-500 transition-all" style={{width: `${pack.progress}%`}}></div>
                               </div>
                             )}
                          </div>

                          <div className="ml-4">
                             {pack.downloaded ? (
                               <button onClick={() => deletePack(pack.id)} className="p-2 text-green-400 bg-green-400/10 rounded-full hover:bg-red-500/20 hover:text-red-400 transition-colors">
                                  <Check size={18} />
                               </button>
                             ) : pack.progress > 0 ? (
                               <span className="text-xs font-bold text-blue-400">{pack.progress}%</span>
                             ) : (
                               <button onClick={() => downloadPack(pack.id)} className="p-2 bg-slate-700 hover:bg-blue-600 rounded-full text-white transition-colors">
                                 <Download size={18} />
                               </button>
                             )}
                          </div>
                       </div>
                    ))}
                 </div>
               </div>

               {/* Clear History */}
               <button onClick={() => { setMessages([]); setRealtimeInput(''); setRealtimeOutput(''); setShowSettings(false); }} className="w-full py-4 text-sm text-red-400 font-medium bg-red-500/10 rounded-2xl hover:bg-red-500/20 transition-colors flex items-center justify-center gap-2">
                  <Trash2 size={16} /> Geçmişi Temizle
               </button>
             </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';
import { TargetLanguage, ChatMessage, OfflinePack } from './types';
import { float32To16BitPCM, arrayBufferToBase64, base64ToArrayBuffer, pcm16ToFloat32 } from './utils/audioUtils';
import AudioVisualizer from './components/AudioVisualizer';
import { Mic, Globe, Settings, RotateCcw, Wifi, WifiOff, Download, Check, Trash2, X, Zap, Square, ChevronDown, Sparkles, Loader2, Languages } from 'lucide-react';

// Live API Configuration
const MODEL_NAME = 'gemini-2.5-flash-native-audio-preview-09-2025';
const INPUT_SAMPLE_RATE = 16000;
const OUTPUT_SAMPLE_RATE = 24000;

// Language Metadata with Flags
const LANGUAGE_META = [
  { code: TargetLanguage.ENGLISH, name: 'İngilizce', flag: '🇬🇧', short: 'EN' },
  { code: TargetLanguage.DUTCH, name: 'Hollandaca', flag: '🇳🇱', short: 'NL' },
  { code: TargetLanguage.ARABIC, name: 'Arapça', flag: '🇸🇦', short: 'AR' },
  { code: TargetLanguage.RUSSIAN, name: 'Rusça', flag: '🇷🇺', short: 'RU' },
];

const getLangDetails = (lang: TargetLanguage) => LANGUAGE_META.find(l => l.code === lang) || LANGUAGE_META[0];

// Mock Offline Packs
const INITIAL_PACKS: OfflinePack[] = [
  { id: 'tr-en', pair: 'TR ↔ EN', name: 'İngilizce', size: '45 MB', downloaded: false, progress: 0 },
  { id: 'tr-nl', pair: 'TR ↔ NL', name: 'Hollandaca', size: '42 MB', downloaded: false, progress: 0 },
  { id: 'tr-ar', pair: 'TR ↔ AR', name: 'Arapça', size: '50 MB', downloaded: false, progress: 0 },
  { id: 'tr-ru', pair: 'TR ↔ RU', name: 'Rusça', size: '48 MB', downloaded: false, progress: 0 },
];

const App: React.FC = () => {
  const [targetLang, setTargetLang] = useState<TargetLanguage>(TargetLanguage.ENGLISH);
  const [isConnected, setIsConnected] = useState(false);
  const [isConnecting, setIsConnecting] = useState(false);
  const [isTransmitting, setIsTransmitting] = useState(false);

  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [error, setError] = useState<string | null>(null);

  // Real-time Display States
  const [realtimeInput, setRealtimeInput] = useState('');
  const [realtimeOutput, setRealtimeOutput] = useState('');

  // Offline / Network State
  const [isOnline, setIsOnline] = useState(navigator.onLine);
  const [forceOfflineMode, setForceOfflineMode] = useState(false);
  const [showSettings, setShowSettings] = useState(false);
  const [showLanguageSelector, setShowLanguageSelector] = useState(false);
  const [offlinePacks, setOfflinePacks] = useState<OfflinePack[]>(INITIAL_PACKS);

  // Audio Context Refs
  const inputAudioContextRef = useRef<AudioContext | null>(null);
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const inputAnalyserRef = useRef<AnalyserNode | null>(null);
  const outputAnalyserRef = useRef<AnalyserNode | null>(null);
  const mediaStreamRef = useRef<MediaStream | null>(null);
  const scriptProcessorRef = useRef<ScriptProcessorNode | null>(null);

  // Logic Refs
  const aiClientRef = useRef<GoogleGenAI | null>(null);
  const sessionPromiseRef = useRef<Promise<any> | null>(null);
  const activeSessionRef = useRef<any>(null); // To store actual session object for cleanup
  const shouldReconnectRef = useRef(false); // Flag for auto-reconnect logic
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const isTransmittingRef = useRef(false);

  // Transcription Buffers
  const currentInputTranscription = useRef('');
  const currentOutputTranscription = useRef('');
  const recognitionRef = useRef<any>(null);

  // 1. Initialize & Network
  useEffect(() => {
    if (process.env.API_KEY) {
      aiClientRef.current = new GoogleGenAI({ apiKey: process.env.API_KEY });
    } else {
      setError("API Anahtarı bulunamadı.");
    }

    const handleOnline = () => setIsOnline(true);
    const handleOffline = () => {
      setIsOnline(false);
      stopConnection();
    };

    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);

    const savedPacks = localStorage.getItem('offlinePacks');
    if (savedPacks) {
      setOfflinePacks(JSON.parse(savedPacks));
    }

    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
    };
  }, []);

  const isOfflineActive = !isOnline || forceOfflineMode;

  // 2. Audio Processing
  const processAudioInput = useCallback((inputData: Float32Array) => {
    if (!sessionPromiseRef.current || !isTransmittingRef.current) return;

    const pcmData = float32To16BitPCM(inputData);
    const base64Data = arrayBufferToBase64(pcmData);

    sessionPromiseRef.current.then((session) => {
      session.sendRealtimeInput({
        media: {
          mimeType: `audio/pcm;rate=${INPUT_SAMPLE_RATE}`,
          data: base64Data,
        },
      });
    });
  }, []);

  // 3. Stop Connection (Robust Cleanup)
  const stopConnection = useCallback(() => {
    setIsConnecting(false);
    setIsConnected(false);
    setIsTransmitting(false);
    isTransmittingRef.current = false;

    setRealtimeInput(''); setRealtimeOutput('');

    // Clear Media Stream
    if (mediaStreamRef.current) {
        mediaStreamRef.current.getTracks().forEach(track => track.stop());
        mediaStreamRef.current = null;
    }

    // Clear Script Processor
    if (scriptProcessorRef.current) {
        scriptProcessorRef.current.disconnect();
        scriptProcessorRef.current = null;
    }

    // Close Audio Contexts
    if (inputAudioContextRef.current) {
        inputAudioContextRef.current.close();
        inputAudioContextRef.current = null;
    }
    if (outputAudioContextRef.current) {
        outputAudioContextRef.current.close();
        outputAudioContextRef.current = null;
    }

    // Close Active Session Explicitly
    if (activeSessionRef.current) {
        activeSessionRef.current.close();
        activeSessionRef.current = null;
    }
    sessionPromiseRef.current = null;

    if (recognitionRef.current) {
        recognitionRef.current.stop();
        // recognitionRef.current = null;
    }
  }, []);

  // 4. Toggle Handler
  const handleMicToggle = async () => {
    if (isConnecting) return;

    if (isConnected) {
      stopConnection();
      return;
    }

    setIsConnecting(true);
    setError(null);

    // --- Offline Mode ---
    if (isOfflineActive) {
      setTimeout(() => {
        setIsConnected(true);
        setIsTransmitting(true);
        isTransmittingRef.current = true;
        setIsConnecting(false);
        startOfflineRecognition();
      }, 300);
      return;
    }

    // --- Online Mode ---
    if (!aiClientRef.current) {
       setError("API Anahtarı eksik.");
       setIsConnecting(false);
       return;
    }

    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: {
        sampleRate: INPUT_SAMPLE_RATE,
        channelCount: 1,
        echoCancellation: true,
        noiseSuppression: true,
        autoGainControl: true
      }});
      mediaStreamRef.current = stream;

      const audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ 
        sampleRate: INPUT_SAMPLE_RATE 
      });
      inputAudioContextRef.current = audioCtx;

      const source = audioCtx.createMediaStreamSource(stream);
      const analyser = audioCtx.createAnalyser();
      analyser.fftSize = 256;
      inputAnalyserRef.current = analyser;

      const scriptProcessor = audioCtx.createScriptProcessor(4096, 1, 1);
      scriptProcessorRef.current = scriptProcessor;

      scriptProcessor.onaudioprocess = (e) => {
        const inputData = e.inputBuffer.getChannelData(0);
        processAudioInput(inputData);
      };

      source.connect(analyser);
      analyser.connect(scriptProcessor);
      scriptProcessor.connect(audioCtx.destination);

      const outCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ 
        sampleRate: OUTPUT_SAMPLE_RATE 
      });
      outputAudioContextRef.current = outCtx;
      const outAnalyser = outCtx.createAnalyser();
      outAnalyser.fftSize = 256;
      outputAnalyserRef.current = outAnalyser;
      outAnalyser.connect(outCtx.destination);

      // UPDATED STRICT SYSTEM PROMPT FOR SEMANTIC INTEGRITY
      const systemPrompt = `You are an expert simultaneous interpreter. Your task is to translate spoken Turkish into ${targetLang} accurately and naturally.

Guidelines:
1. Semantic Integrity: Ensure the translation captures the full meaning and context of the sentence. Avoid robotic or word-for-word literal translations that lose the intended meaning.
2. Natural Flow: The output should sound fluent and natural to a native speaker of ${targetLang}.
3. Strict Translation Only: Do NOT answer questions, do NOT engage in conversation, and do NOT add explanations. Only output the translation.
4. Input Handling: Translate what is heard. If the input is silence or noise, wait for speech.

Output strictly audio of the translation.`;

      const connectPromise = aiClientRef.current.live.connect({
        model: MODEL_NAME,
        config: {
          systemInstruction: systemPrompt,
          responseModalities: [Modality.AUDIO],
          inputAudioTranscription: {},
          outputAudioTranscription: {},
        },
        callbacks: {
          onopen: () => {
            console.log("Connected");
            setIsConnecting(false);
            setIsConnected(true);
            setIsTransmitting(true);
            isTransmittingRef.current = true;
            nextStartTimeRef.current = 0;
            setRealtimeInput('');
            setRealtimeOutput('');
          },
          onmessage: (msg: LiveServerMessage) => handleServerMessage(msg),
          onclose: () => {
            console.log("Closed");
            stopConnection();
          },
          onerror: (e) => {
            console.error(e);
            setError("Bağlantı hatası.");
            stopConnection();
          }
        }
      });

      sessionPromiseRef.current = connectPromise;
      connectPromise.then(session => {
          activeSessionRef.current = session;
      });

    } catch (e: any) {
      console.error(e);
      setError(`Hata: ${e.message}`);
      stopConnection();
    }
  };

  const handleServerMessage = (msg: LiveServerMessage) => {
    if (msg.serverContent?.inputTranscription) {
       currentInputTranscription.current += msg.serverContent.inputTranscription.text;
       setRealtimeInput(currentInputTranscription.current);
    }
    if (msg.serverContent?.outputTranscription) {
       currentOutputTranscription.current += msg.serverContent.outputTranscription.text;
       setRealtimeOutput(currentOutputTranscription.current);
    }
    if (msg.serverContent?.turnComplete) {
       const inputTx = currentInputTranscription.current.trim();
       const outputTx = currentOutputTranscription.current.trim();
       if (inputTx || outputTx) {
         addMessage('user', inputTx || '...');
         addMessage('model', outputTx || '...');
       }
       currentInputTranscription.current = '';
       currentOutputTranscription.current = '';
       setRealtimeInput('');
       setRealtimeOutput('');
    }
    const audioData = msg.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
    if (audioData) {
       playAudioResponse(audioData);
    }
  };

  // 5. Language Change Logic
  const handleLanguageChange = (newLang: TargetLanguage) => {
      // Only restart connection if we are ONLINE (to update system prompt).
      // Offline mode uses dynamic TTS so no restart needed.
      if (isConnected && !isOfflineActive) {
          shouldReconnectRef.current = true;
          stopConnection();
      }
      setTargetLang(newLang);
  };

  // Auto-reconnect effect
  useEffect(() => {
      if (shouldReconnectRef.current) {
          shouldReconnectRef.current = false;
          handleMicToggle();
      }
  }, [targetLang]);

  // 6. Offline Logic
  const startOfflineRecognition = () => {
    if (!('webkitSpeechRecognition' in window)) return;
    try {
      const Recognition = (window as any).webkitSpeechRecognition;
      const recognition = new Recognition();
      recognition.lang = 'tr-TR'; 
      recognition.continuous = true; 
      recognition.interimResults = true; 

      recognition.onstart = () => setRealtimeInput('');
      recognition.onresult = (event: any) => {
        let interim = '';
        let final = '';
        for (let i = event.resultIndex; i < event.results.length; ++i) {
          if (event.results[i].isFinal) final += event.results[i][0].transcript;
          else interim += event.results[i][0].transcript;
        }
        setRealtimeInput(final || interim);
      };
      recognition.onerror = (e: any) => console.log(e);
      recognitionRef.current = recognition;
      recognition.start();
    } catch (e) {}
  };

  const stopOfflineRecognition = () => {
    if (recognitionRef.current) {
      recognitionRef.current.stop();
      setTimeout(() => {
        const text = realtimeInput.trim();
        if (text) {
           addMessage('user', text);
           setRealtimeInput('');
           setTimeout(() => {
             const mock = `(${targetLang}) ${text}`;
             addMessage('model', mock);
             speakOffline(text, targetLang);
           }, 500);
        }
      }, 500);
    }
  };

  const speakOffline = (text: string, lang: TargetLanguage) => {
    if ('speechSynthesis' in window) {
      const utterance = new SpeechSynthesisUtterance(text); 
      const langMap: Record<TargetLanguage, string> = {
        [TargetLanguage.ENGLISH]: 'en-US', [TargetLanguage.DUTCH]: 'nl-NL',
        [TargetLanguage.ARABIC]: 'ar-SA', [TargetLanguage.RUSSIAN]: 'ru-RU'
      };
      utterance.lang = langMap[lang];
      window.speechSynthesis.speak(utterance);
    }
  };

  // 7. Play Audio
  const playAudioResponse = async (base64Audio: string) => {
    if (!outputAudioContextRef.current || !outputAnalyserRef.current) return;
    const ctx = outputAudioContextRef.current;
    try {
      const arrayBuffer = base64ToArrayBuffer(base64Audio);
      const float32Data = pcm16ToFloat32(arrayBuffer);
      const audioBuffer = ctx.createBuffer(1, float32Data.length, OUTPUT_SAMPLE_RATE);
      audioBuffer.getChannelData(0).set(float32Data);
      const source = ctx.createBufferSource();
      source.buffer = audioBuffer;
      source.connect(outputAnalyserRef.current);
      source.start(Math.max(nextStartTimeRef.current, ctx.currentTime));
      nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime) + audioBuffer.duration;
      source.onended = () => sourcesRef.current.delete(source);
      sourcesRef.current.add(source);
    } catch (err) {}
  };

  const addMessage = (role: 'user' | 'model', text: string) => {
    setMessages(prev => [...prev, { id: Date.now().toString() + Math.random(), role, text, timestamp: new Date(), isFinal: true }]);
  };

  const chatContainerRef = useRef<HTMLDivElement>(null);
  useEffect(() => {
    if (chatContainerRef.current) chatContainerRef.current.scrollTop = chatContainerRef.current.scrollHeight;
  }, [messages, realtimeInput, realtimeOutput]);

  const downloadPack = (id: string) => {
    setOfflinePacks(prev => prev.map(p => p.id === id ? { ...p, progress: 5 } : p));
    let progress = 5;
    const interval = setInterval(() => {
      progress += 10;
      if (progress >= 100) {
        clearInterval(interval);
        setOfflinePacks(prev => {
          const newPacks = prev.map(p => p.id === id ? { ...p, progress: 100, downloaded: true } : p);
          localStorage.setItem('offlinePacks', JSON.stringify(newPacks));
          return newPacks;
        });
      } else {
        setOfflinePacks(prev => prev.map(p => p.id === id ? { ...p, progress } : p));
      }
    }, 200);
  };

  const deletePack = (id: string) => {
     setOfflinePacks(prev => {
       const newPacks = prev.map(p => p.id === id ? { ...p, progress: 0, downloaded: false } : p);
       localStorage.setItem('offlinePacks', JSON.stringify(newPacks));
       return newPacks;
     });
  };

  return (
    <div className="h-screen w-full bg-slate-950 text-slate-100 flex flex-col font-sans relative overflow-hidden select-none">

      {/* Dynamic Background */}
      <div className="absolute inset-0 z-0 pointer-events-none">
        <div className={`absolute top-[-10%] left-[-20%] w-[150vw] h-[60vh] rounded-full blur-[80px] opacity-20 transition-colors duration-1000 ${isOfflineActive ? 'bg-orange-600' : isConnected ? 'bg-indigo-600' : 'bg-blue-900'}`}></div>
        <div className="absolute bottom-[-10%] right-[-20%] w-[150vw] h-[50vh] bg-purple-900/10 rounded-full blur-[100px]"></div>
      </div>

      {/* Mobile Header */}
      <header className="z-20 h-16 flex items-center justify-between px-5 bg-gradient-to-b from-slate-950/80 to-transparent backdrop-blur-sm sticky top-0">
        <div className="flex items-center gap-2.5">
          <div className={`w-8 h-8 rounded-xl flex items-center justify-center bg-gradient-to-br shadow-lg ${isOfflineActive ? 'from-orange-500 to-red-600' : 'from-blue-500 to-indigo-600'}`}>
            <Sparkles size={16} className="text-white" />
          </div>
          <span className="font-bold text-lg tracking-tight">LinguaFlow</span>
        </div>
        <div className="flex items-center gap-3">
          <div className={`px-2.5 py-1 rounded-full text-[10px] font-bold border ${isOfflineActive ? 'bg-orange-500/10 border-orange-500/20 text-orange-400' : 'bg-blue-500/10 border-blue-500/20 text-blue-400'}`}>
            {isOfflineActive ? 'OFFLINE' : 'ONLINE'}
          </div>
          <button onClick={() => setShowSettings(true)} className="p-2 rounded-full bg-slate-800/50 hover:bg-slate-800 transition-colors">
            <Settings size={20} className="text-slate-400" />
          </button>
        </div>
      </header>

      {/* Main Chat Area */}
      <main className="flex-1 flex flex-col z-10 relative overflow-hidden">

        {/* Messages */}
        <div ref={chatContainerRef} className="flex-1 overflow-y-auto px-4 pt-2 pb-6 space-y-6 scroll-smooth">
          {error && (
            <div className="bg-red-500/10 border border-red-500/20 text-red-200 p-3 rounded-xl text-sm flex justify-between items-center mx-2">
              <span>{error}</span>
              <button onClick={() => setError(null)}><X size={16} /></button>
            </div>
          )}

          {messages.length === 0 && !realtimeInput && (
             <div className="h-full flex flex-col items-center justify-center text-slate-500 opacity-40 space-y-4">
                <Globe size={64} strokeWidth={1} />
                <p className="text-center text-sm px-10">
                  Konuşmaya başlamak için aşağıdaki mikrofona dokunun.
                </p>
             </div>
          )}

          {messages.map((msg) => (
            <div key={msg.id} className={`flex flex-col ${msg.role === 'user' ? 'items-start' : 'items-end'}`}>
              <span className="text-[10px] text-slate-500 mb-1 px-1 flex items-center gap-1.5">
                  {msg.role === 'user' ? (
                      <><span>🇹🇷</span><span>TR</span></>
                  ) : (
                      <>
                        <span>{getLangDetails(targetLang).flag}</span>
                        <span>{getLangDetails(targetLang).short}</span>
                      </>
                  )}
              </span>
              <div className={`max-w-[85%] px-5 py-3.5 shadow-sm text-[15px] leading-relaxed ${
                msg.role === 'user' 
                  ? 'bg-slate-800 text-slate-200 rounded-2xl rounded-tl-sm' 
                  : isOfflineActive 
                    ? 'bg-orange-600 text-white rounded-2xl rounded-tr-sm'
                    : 'bg-blue-600 text-white rounded-2xl rounded-tr-sm'
              }`}>
                {msg.text}
              </div>
            </div>
          ))}

          {/* Real-time Bubbles */}
          {(realtimeInput || realtimeOutput) && (
             <div className="space-y-4">
                {realtimeInput && (
                  <div className="flex flex-col items-start opacity-70">
                     <span className="text-[10px] text-blue-400 mb-1 px-1 animate-pulse flex items-center gap-1"><span>🇹🇷</span> DİNLİYOR...</span>
                     <div className="max-w-[85%] px-5 py-3 bg-slate-800/50 border border-slate-700 border-dashed text-slate-300 rounded-2xl rounded-tl-sm">
                       {realtimeInput}
                     </div>
                  </div>
                )}
                {realtimeOutput && (
                  <div className="flex flex-col items-end opacity-70">
                     <span className="text-[10px] text-indigo-400 mb-1 px-1 animate-pulse flex items-center gap-1"><span>{getLangDetails(targetLang).flag}</span> ÇEVİRİYOR...</span>
                     <div className="max-w-[85%] px-5 py-3 bg-blue-900/30 border border-blue-500/30 border-dashed text-blue-200 rounded-2xl rounded-tr-sm">
                       {realtimeOutput}
                     </div>
                  </div>
                )}
             </div>
          )}
        </div>

        {/* BOTTOM DOCK (Controls) */}
        <div className="bg-slate-950/80 backdrop-blur-xl border-t border-slate-800/50 px-6 pb-10 pt-4 z-30">

          {/* Visualizer Bar (Above Dock) */}
          <div className="h-10 w-full flex items-center justify-center mb-4">
            {isConnected ? (
              <div className="w-full h-full opacity-80">
                 <AudioVisualizer analyser={inputAnalyserRef.current} isActive={true} color={isOfflineActive ? '#f97316' : '#6366f1'} />
              </div>
            ) : (
              <div className="h-1 w-16 bg-slate-800 rounded-full"></div>
            )}
          </div>

          <div className="flex items-center justify-between max-w-sm mx-auto">

            {/* Left: Language Selector Button */}
            <div className="w-16 flex flex-col items-center gap-1">
               <button 
                 onClick={() => setShowLanguageSelector(true)}
                 className="w-full h-12 bg-slate-800 border border-slate-700 text-slate-200 rounded-2xl flex flex-col items-center justify-center gap-0.5 hover:border-slate-500 transition-colors active:scale-95"
               >
                  <span className="text-xl leading-none filter drop-shadow-sm">{getLangDetails(targetLang).flag}</span>
                  <span className="text-[10px] font-bold">{getLangDetails(targetLang).short}</span>
               </button>
               <span className="text-[10px] text-slate-500 font-medium">Hedef</span>
            </div>

            {/* Center: Main Mic Toggle */}
            <div className="relative -mt-6">
              {/* Ring Animation */}
              {isConnected && (
                <div className="absolute inset-0 rounded-full animate-ping opacity-30 bg-indigo-500"></div>
              )}

              <button
                onClick={handleMicToggle}
                className={`w-20 h-20 rounded-full flex items-center justify-center shadow-2xl transition-all duration-300 transform active:scale-95 ${
                  isConnecting
                    ? 'bg-slate-800 border-4 border-slate-700 cursor-wait'
                    : isConnected
                      ? isOfflineActive 
                        ? 'bg-orange-600 text-white shadow-orange-600/40 ring-4 ring-orange-900/50 scale-105' 
                        : 'bg-indigo-600 text-white shadow-indigo-600/40 ring-4 ring-indigo-900/50 scale-105'
                      : 'bg-slate-100 text-slate-900 hover:bg-white border-4 border-slate-300 shadow-white/10'
                }`}
              >
                {isConnecting ? (
                   <Loader2 size={32} className="animate-spin text-slate-400" />
                ) : isConnected ? (
                   <Square size={28} fill="currentColor" className="rounded-sm" />
                ) : (
                   <Mic size={32} strokeWidth={2.5} />
                )}
              </button>
            </div>

            {/* Right: Clear Button */}
            <div className="w-16 flex flex-col items-center gap-1">
               <button 
                 onClick={() => {
                   setMessages([]);
                   setRealtimeInput('');
                   setRealtimeOutput('');
                 }}
                 className="w-full h-12 flex items-center justify-center rounded-2xl bg-slate-800 border border-slate-700 text-slate-400 hover:text-white hover:bg-slate-700 transition-colors active:scale-95"
               >
                 <RotateCcw size={18} />
               </button>
               <span className="text-[10px] text-slate-500 font-medium">Temizle</span>
            </div>

          </div>
        </div>

      </main>

      {/* Language Selector Sheet */}
      {showLanguageSelector && (
          <div className="fixed inset-0 z-50 flex items-end justify-center bg-black/60 backdrop-blur-sm animate-fade-in" onClick={() => setShowLanguageSelector(false)}>
              <div className="bg-slate-900 border-t border-slate-700 w-full max-w-lg rounded-t-3xl shadow-2xl overflow-hidden" onClick={e => e.stopPropagation()}>
                  <div className="p-4 flex items-center justify-center relative border-b border-slate-800">
                      <div className="w-12 h-1 bg-slate-700 rounded-full absolute top-3"></div>
                      <h3 className="text-white font-semibold mt-2 flex items-center gap-2">
                        <Globe size={18} className="text-blue-400" />
                        Hedef Dil Seçin
                      </h3>
                  </div>
                  <div className="p-6 grid grid-cols-2 gap-3 pb-8">
                      {LANGUAGE_META.map((lang) => (
                          <button
                              key={lang.code}
                              onClick={() => {
                                  handleLanguageChange(lang.code);
                                  setShowLanguageSelector(false);
                              }}
                              className={`p-4 rounded-xl border flex flex-col items-center gap-2 transition-all ${
                                  targetLang === lang.code 
                                  ? 'bg-blue-600/20 border-blue-500 text-white shadow-lg shadow-blue-900/20' 
                                  : 'bg-slate-800 border-slate-700 text-slate-400 hover:bg-slate-750 hover:border-slate-600'
                              }`}
                          >
                              <span className="text-4xl filter drop-shadow-md">{lang.flag}</span>
                              <span className="font-medium text-sm">{lang.name}</span>
                          </button>
                      ))}
                  </div>
              </div>
          </div>
      )}

      {/* Settings Sheet */}
      {showSettings && (
        <div className="fixed inset-0 z-50 flex items-end justify-center bg-black/60 backdrop-blur-sm animate-fade-in" onClick={() => setShowSettings(false)}>
          <div className="bg-slate-900 border-t border-slate-700 w-full max-w-lg rounded-t-3xl shadow-2xl overflow-hidden max-h-[85vh] flex flex-col" onClick={e => e.stopPropagation()}>
             <div className="p-5 flex justify-between items-center bg-slate-800/50">
                <h2 className="text-lg font-bold flex items-center gap-2 text-white">
                  <Settings size={20} className="text-blue-400"/> Ayarlar
                </h2>
                <div className="w-12 h-1 bg-slate-700 rounded-full absolute top-3 left-1/2 -translate-x-1/2"></div>
                <button onClick={() => setShowSettings(false)} className="p-1 bg-slate-800 rounded-full text-slate-400"><X size={20} /></button>
             </div>

             <div className="p-6 overflow-y-auto space-y-6">
               {/* Mode */}
               <div className="bg-slate-800/30 p-4 rounded-2xl border border-slate-800">
                  <div className="flex justify-between items-center mb-2">
                    <span className="font-semibold text-slate-200">Çevrimdışı Mod</span>
                    <button onClick={() => { if(isConnected) stopConnection(); setForceOfflineMode(!forceOfflineMode); }} 
                      className={`w-12 h-7 rounded-full p-1 transition-colors ${forceOfflineMode ? 'bg-orange-500' : 'bg-slate-700'}`}>
                      <div className={`w-5 h-5 rounded-full bg-white transition-transform ${forceOfflineMode ? 'translate-x-5' : ''}`}></div>
                    </button>
                  </div>
                  <p className="text-xs text-slate-500">İnternet bağlantısı olmadan cihaz üzerinde basit çeviri yapın.</p>
               </div>

               {/* Packs */}
               <div>
                 <h3 className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-3 px-1">Dil Paketleri</h3>
                 <div className="space-y-3">
                    {offlinePacks.map(pack => {
                       // Find flag based on pack ID content (simple heuristic for demo)
                       let flag = '🏳️';
                       if (pack.id.includes('en')) flag = '🇬🇧';
                       if (pack.id.includes('nl')) flag = '🇳🇱';
                       if (pack.id.includes('ar')) flag = '🇸🇦';
                       if (pack.id.includes('ru')) flag = '🇷🇺';

                       return (
                       <div key={pack.id} className="bg-slate-800/50 p-3 rounded-xl border border-slate-700/50 flex items-center justify-between">
                          <div className="flex-1">
                             <div className="flex items-center gap-2">
                               <span className="text-lg">{flag}</span>
                               <span className="font-semibold text-sm">{pack.pair}</span>
                               <span className="text-[10px] bg-slate-700 text-slate-300 px-1.5 py-0.5 rounded">{pack.size}</span>
                             </div>
                             <div className="text-xs text-slate-400 mt-1">{pack.name}</div>
                             {pack.progress > 0 && pack.progress < 100 && (
                               <div className="w-full h-1 bg-slate-700 mt-2 rounded-full overflow-hidden">
                                  <div className="h-full bg-blue-500 transition-all" style={{width: `${pack.progress}%`}}></div>
                               </div>
                             )}
                          </div>

                          <div className="ml-4">
                             {pack.downloaded ? (
                               <button onClick={() => deletePack(pack.id)} className="p-2 text-green-400 bg-green-400/10 rounded-full hover:bg-red-500/20 hover:text-red-400 transition-colors">
                                  <Check size={18} />
                               </button>
                             ) : pack.progress > 0 ? (
                               <span className="text-xs font-bold text-blue-400">{pack.progress}%</span>
                             ) : (
                               <button onClick={() => downloadPack(pack.id)} className="p-2 bg-slate-700 hover:bg-blue-600 rounded-full text-white transition-colors">
                                 <Download size={18} />
                               </button>
                             )}
                          </div>
                       </div>
                    )})}
                 </div>
               </div>

               {/* Clear History */}
               <button onClick={() => { setMessages([]); setRealtimeInput(''); setRealtimeOutput(''); setShowSettings(false); }} className="w-full py-4 text-sm text-red-400 font-medium bg-red-500/10 rounded-2xl hover:bg-red-500/20 transition-colors flex items-center justify-center gap-2">
                  <Trash2 size={16} /> Geçmişi Temizle
               </button>
             </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';
import { TargetLanguage, ChatMessage, OfflinePack } from './types';
import { float32To16BitPCM, arrayBufferToBase64, base64ToArrayBuffer, pcm16ToFloat32 } from './utils/audioUtils';
import AudioVisualizer from './components/AudioVisualizer';
import { Mic, Globe, Settings, RotateCcw, Wifi, WifiOff, Download, Check, Trash2, X, Zap, Square, ChevronDown, Sparkles, Loader2, Languages, ArrowRightLeft } from 'lucide-react';

// Live API Configuration
const MODEL_NAME = 'gemini-2.5-flash-native-audio-preview-09-2025';
const INPUT_SAMPLE_RATE = 16000;
const OUTPUT_SAMPLE_RATE = 24000;

// Language Metadata with Flags
const LANGUAGE_META = [
  { code: TargetLanguage.ENGLISH, name: 'İngilizce', flag: '🇬🇧', short: 'EN' },
  { code: TargetLanguage.DUTCH, name: 'Hollandaca', flag: '🇳🇱', short: 'NL' },
  { code: TargetLanguage.ARABIC, name: 'Arapça', flag: '🇸🇦', short: 'AR' },
  { code: TargetLanguage.RUSSIAN, name: 'Rusça', flag: '🇷🇺', short: 'RU' },
];

const getLangDetails = (lang: TargetLanguage) => LANGUAGE_META.find(l => l.code === lang) || LANGUAGE_META[0];

// Mock Offline Packs
const INITIAL_PACKS: OfflinePack[] = [
  { id: 'tr-en', pair: 'TR ↔ EN', name: 'İngilizce', size: '45 MB', downloaded: false, progress: 0 },
  { id: 'tr-nl', pair: 'TR ↔ NL', name: 'Hollandaca', size: '42 MB', downloaded: false, progress: 0 },
  { id: 'tr-ar', pair: 'TR ↔ AR', name: 'Arapça', size: '50 MB', downloaded: false, progress: 0 },
  { id: 'tr-ru', pair: 'TR ↔ RU', name: 'Rusça', size: '48 MB', downloaded: false, progress: 0 },
];

const App: React.FC = () => {
  const [targetLang, setTargetLang] = useState<TargetLanguage>(TargetLanguage.ENGLISH);
  const [isConnected, setIsConnected] = useState(false);
  const [isConnecting, setIsConnecting] = useState(false);
  const [isTransmitting, setIsTransmitting] = useState(false);

  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [error, setError] = useState<string | null>(null);

  // Real-time Display States
  const [realtimeInput, setRealtimeInput] = useState('');
  const [realtimeOutput, setRealtimeOutput] = useState('');

  // Offline / Network State
  const [isOnline, setIsOnline] = useState(navigator.onLine);
  const [forceOfflineMode, setForceOfflineMode] = useState(false);
  const [showSettings, setShowSettings] = useState(false);
  const [showLanguageSelector, setShowLanguageSelector] = useState(false);
  const [offlinePacks, setOfflinePacks] = useState<OfflinePack[]>(INITIAL_PACKS);

  // Audio Context Refs
  const inputAudioContextRef = useRef<AudioContext | null>(null);
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const inputAnalyserRef = useRef<AnalyserNode | null>(null);
  const outputAnalyserRef = useRef<AnalyserNode | null>(null);
  const mediaStreamRef = useRef<MediaStream | null>(null);
  const scriptProcessorRef = useRef<ScriptProcessorNode | null>(null);

  // Logic Refs
  const aiClientRef = useRef<GoogleGenAI | null>(null);
  const sessionPromiseRef = useRef<Promise<any> | null>(null);
  const activeSessionRef = useRef<any>(null); // To store actual session object for cleanup
  const shouldReconnectRef = useRef(false); // Flag for auto-reconnect logic
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const isTransmittingRef = useRef(false);

  // Transcription Buffers
  const currentInputTranscription = useRef('');
  const currentOutputTranscription = useRef('');
  const recognitionRef = useRef<any>(null);

  // 1. Initialize & Network
  useEffect(() => {
    if (process.env.API_KEY) {
      aiClientRef.current = new GoogleGenAI({ apiKey: process.env.API_KEY });
    } else {
      setError("API Anahtarı bulunamadı.");
    }

    const handleOnline = () => setIsOnline(true);
    const handleOffline = () => {
      setIsOnline(false);
      stopConnection();
    };

    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);

    const savedPacks = localStorage.getItem('offlinePacks');
    if (savedPacks) {
      setOfflinePacks(JSON.parse(savedPacks));
    }

    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
    };
  }, []);

  const isOfflineActive = !isOnline || forceOfflineMode;

  // 2. Audio Processing
  const processAudioInput = useCallback((inputData: Float32Array) => {
    if (!sessionPromiseRef.current || !isTransmittingRef.current) return;

    const pcmData = float32To16BitPCM(inputData);
    const base64Data = arrayBufferToBase64(pcmData);

    sessionPromiseRef.current.then((session) => {
      session.sendRealtimeInput({
        media: {
          mimeType: `audio/pcm;rate=${INPUT_SAMPLE_RATE}`,
          data: base64Data,
        },
      });
    });
  }, []);

  // 3. Stop Connection (Robust Cleanup)
  const stopConnection = useCallback(() => {
    setIsConnecting(false);
    setIsConnected(false);
    setIsTransmitting(false);
    isTransmittingRef.current = false;

    setRealtimeInput(''); setRealtimeOutput('');

    // Clear Media Stream
    if (mediaStreamRef.current) {
        mediaStreamRef.current.getTracks().forEach(track => track.stop());
        mediaStreamRef.current = null;
    }

    // Clear Script Processor
    if (scriptProcessorRef.current) {
        scriptProcessorRef.current.disconnect();
        scriptProcessorRef.current = null;
    }

    // Close Audio Contexts
    if (inputAudioContextRef.current) {
        inputAudioContextRef.current.close();
        inputAudioContextRef.current = null;
    }
    if (outputAudioContextRef.current) {
        outputAudioContextRef.current.close();
        outputAudioContextRef.current = null;
    }

    // Close Active Session Explicitly
    if (activeSessionRef.current) {
        activeSessionRef.current.close();
        activeSessionRef.current = null;
    }
    sessionPromiseRef.current = null;

    if (recognitionRef.current) {
        recognitionRef.current.stop();
        // recognitionRef.current = null;
    }
  }, []);

  // 4. Toggle Handler
  const handleMicToggle = async () => {
    if (isConnecting) return;

    if (isConnected) {
      stopConnection();
      return;
    }

    setIsConnecting(true);
    setError(null);

    // --- Offline Mode ---
    if (isOfflineActive) {
      setTimeout(() => {
        setIsConnected(true);
        setIsTransmitting(true);
        isTransmittingRef.current = true;
        setIsConnecting(false);
        startOfflineRecognition();
      }, 300);
      return;
    }

    // --- Online Mode ---
    if (!aiClientRef.current) {
       setError("API Anahtarı eksik.");
       setIsConnecting(false);
       return;
    }

    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: {
        sampleRate: INPUT_SAMPLE_RATE,
        channelCount: 1,
        echoCancellation: true,
        noiseSuppression: true,
        autoGainControl: true
      }});
      mediaStreamRef.current = stream;

      const audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ 
        sampleRate: INPUT_SAMPLE_RATE 
      });
      inputAudioContextRef.current = audioCtx;

      const source = audioCtx.createMediaStreamSource(stream);
      const analyser = audioCtx.createAnalyser();
      analyser.fftSize = 256;
      inputAnalyserRef.current = analyser;

      const scriptProcessor = audioCtx.createScriptProcessor(4096, 1, 1);
      scriptProcessorRef.current = scriptProcessor;

      scriptProcessor.onaudioprocess = (e) => {
        const inputData = e.inputBuffer.getChannelData(0);
        processAudioInput(inputData);
      };

      source.connect(analyser);
      analyser.connect(scriptProcessor);
      scriptProcessor.connect(audioCtx.destination);

      const outCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ 
        sampleRate: OUTPUT_SAMPLE_RATE 
      });
      outputAudioContextRef.current = outCtx;
      const outAnalyser = outCtx.createAnalyser();
      outAnalyser.fftSize = 256;
      outputAnalyserRef.current = outAnalyser;
      outAnalyser.connect(outCtx.destination);

      const currentTargetName = getLangDetails(targetLang).name;

      // UPDATED BIDIRECTIONAL SYSTEM PROMPT
      const systemPrompt = `You are an expert bidirectional simultaneous interpreter.
Your task is to facilitate a real-time conversation between a Turkish speaker and a ${currentTargetName} speaker.

STRICT INSTRUCTIONS:
1. Bidirectional Translation:
   - If you hear Turkish, translate it immediately and accurately into ${currentTargetName}.
   - If you hear ${currentTargetName}, translate it immediately and accurately into Turkish.

2. Tone & Context:
   - Maintain the original tone, emotion, and intent of the speaker.
   - Ensure the translation flows naturally for a native speaker of the target language.

3. Professional Conduct:
   - Do NOT engage in conversation.
   - Do NOT answer questions yourself.
   - Do NOT explain your translations.
   - Simply output the translated audio.

4. Silence:
   - If there is no speech, stay silent.

Output strictly audio of the translation.`;

      const connectPromise = aiClientRef.current.live.connect({
        model: MODEL_NAME,
        config: {
          systemInstruction: systemPrompt,
          responseModalities: [Modality.AUDIO],
          inputAudioTranscription: {},
          outputAudioTranscription: {},
        },
        callbacks: {
          onopen: () => {
            console.log("Connected");
            setIsConnecting(false);
            setIsConnected(true);
            setIsTransmitting(true);
            isTransmittingRef.current = true;
            nextStartTimeRef.current = 0;
            setRealtimeInput('');
            setRealtimeOutput('');
          },
          onmessage: (msg: LiveServerMessage) => handleServerMessage(msg),
          onclose: () => {
            console.log("Closed");
            stopConnection();
          },
          onerror: (e) => {
            console.error(e);
            setError("Bağlantı hatası.");
            stopConnection();
          }
        }
      });

      sessionPromiseRef.current = connectPromise;
      connectPromise.then(session => {
          activeSessionRef.current = session;
      });

    } catch (e: any) {
      console.error(e);
      setError(`Hata: ${e.message}`);
      stopConnection();
    }
  };

  const handleServerMessage = (msg: LiveServerMessage) => {
    if (msg.serverContent?.inputTranscription) {
       currentInputTranscription.current += msg.serverContent.inputTranscription.text;
       setRealtimeInput(currentInputTranscription.current);
    }
    if (msg.serverContent?.outputTranscription) {
       currentOutputTranscription.current += msg.serverContent.outputTranscription.text;
       setRealtimeOutput(currentOutputTranscription.current);
    }
    if (msg.serverContent?.turnComplete) {
       const inputTx = currentInputTranscription.current.trim();
       const outputTx = currentOutputTranscription.current.trim();
       if (inputTx || outputTx) {
         addMessage('user', inputTx || '...');
         addMessage('model', outputTx || '...');
       }
       currentInputTranscription.current = '';
       currentOutputTranscription.current = '';
       setRealtimeInput('');
       setRealtimeOutput('');
    }
    const audioData = msg.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
    if (audioData) {
       playAudioResponse(audioData);
    }
  };

  // 5. Language Change Logic
  const handleLanguageChange = (newLang: TargetLanguage) => {
      // Only restart connection if we are ONLINE (to update system prompt).
      // Offline mode uses dynamic TTS so no restart needed.
      if (isConnected && !isOfflineActive) {
          shouldReconnectRef.current = true;
          stopConnection();
      }
      setTargetLang(newLang);
  };

  // Auto-reconnect effect
  useEffect(() => {
      if (shouldReconnectRef.current) {
          shouldReconnectRef.current = false;
          handleMicToggle();
      }
  }, [targetLang]);

  // 6. Offline Logic
  const startOfflineRecognition = () => {
    if (!('webkitSpeechRecognition' in window)) return;
    try {
      const Recognition = (window as any).webkitSpeechRecognition;
      const recognition = new Recognition();
      recognition.lang = 'tr-TR'; 
      recognition.continuous = true; 
      recognition.interimResults = true; 

      recognition.onstart = () => setRealtimeInput('');
      recognition.onresult = (event: any) => {
        let interim = '';
        let final = '';
        for (let i = event.resultIndex; i < event.results.length; ++i) {
          if (event.results[i].isFinal) final += event.results[i][0].transcript;
          else interim += event.results[i][0].transcript;
        }
        setRealtimeInput(final || interim);
      };
      recognition.onerror = (e: any) => console.log(e);
      recognitionRef.current = recognition;
      recognition.start();
    } catch (e) {}
  };

  const stopOfflineRecognition = () => {
    if (recognitionRef.current) {
      recognitionRef.current.stop();
      setTimeout(() => {
        const text = realtimeInput.trim();
        if (text) {
           addMessage('user', text);
           setRealtimeInput('');
           setTimeout(() => {
             const mock = `(${targetLang}) ${text}`;
             addMessage('model', mock);
             speakOffline(text, targetLang);
           }, 500);
        }
      }, 500);
    }
  };

  const speakOffline = (text: string, lang: TargetLanguage) => {
    if ('speechSynthesis' in window) {
      const utterance = new SpeechSynthesisUtterance(text); 
      const langMap: Record<TargetLanguage, string> = {
        [TargetLanguage.ENGLISH]: 'en-US', [TargetLanguage.DUTCH]: 'nl-NL',
        [TargetLanguage.ARABIC]: 'ar-SA', [TargetLanguage.RUSSIAN]: 'ru-RU'
      };
      utterance.lang = langMap[lang];
      window.speechSynthesis.speak(utterance);
    }
  };

  // 7. Play Audio
  const playAudioResponse = async (base64Audio: string) => {
    if (!outputAudioContextRef.current || !outputAnalyserRef.current) return;
    const ctx = outputAudioContextRef.current;
    try {
      const arrayBuffer = base64ToArrayBuffer(base64Audio);
      const float32Data = pcm16ToFloat32(arrayBuffer);
      const audioBuffer = ctx.createBuffer(1, float32Data.length, OUTPUT_SAMPLE_RATE);
      audioBuffer.getChannelData(0).set(float32Data);
      const source = ctx.createBufferSource();
      source.buffer = audioBuffer;
      source.connect(outputAnalyserRef.current);
      source.start(Math.max(nextStartTimeRef.current, ctx.currentTime));
      nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime) + audioBuffer.duration;
      source.onended = () => sourcesRef.current.delete(source);
      sourcesRef.current.add(source);
    } catch (err) {}
  };

  const addMessage = (role: 'user' | 'model', text: string) => {
    setMessages(prev => [...prev, { id: Date.now().toString() + Math.random(), role, text, timestamp: new Date(), isFinal: true }]);
  };

  const chatContainerRef = useRef<HTMLDivElement>(null);
  useEffect(() => {
    if (chatContainerRef.current) chatContainerRef.current.scrollTop = chatContainerRef.current.scrollHeight;
  }, [messages, realtimeInput, realtimeOutput]);

  const downloadPack = (id: string) => {
    setOfflinePacks(prev => prev.map(p => p.id === id ? { ...p, progress: 5 } : p));
    let progress = 5;
    const interval = setInterval(() => {
      progress += 10;
      if (progress >= 100) {
        clearInterval(interval);
        setOfflinePacks(prev => {
          const newPacks = prev.map(p => p.id === id ? { ...p, progress: 100, downloaded: true } : p);
          localStorage.setItem('offlinePacks', JSON.stringify(newPacks));
          return newPacks;
        });
      } else {
        setOfflinePacks(prev => prev.map(p => p.id === id ? { ...p, progress } : p));
      }
    }, 200);
  };

  const deletePack = (id: string) => {
     setOfflinePacks(prev => {
       const newPacks = prev.map(p => p.id === id ? { ...p, progress: 0, downloaded: false } : p);
       localStorage.setItem('offlinePacks', JSON.stringify(newPacks));
       return newPacks;
     });
  };

  return (
    <div className="h-screen w-full bg-slate-950 text-slate-100 flex flex-col font-sans relative overflow-hidden select-none">

      {/* Dynamic Background */}
      <div className="absolute inset-0 z-0 pointer-events-none">
        <div className={`absolute top-[-10%] left-[-20%] w-[150vw] h-[60vh] rounded-full blur-[80px] opacity-20 transition-colors duration-1000 ${isOfflineActive ? 'bg-orange-600' : isConnected ? 'bg-indigo-600' : 'bg-blue-900'}`}></div>
        <div className="absolute bottom-[-10%] right-[-20%] w-[150vw] h-[50vh] bg-purple-900/10 rounded-full blur-[100px]"></div>
      </div>

      {/* Mobile Header */}
      <header className="z-20 h-16 flex items-center justify-between px-5 bg-gradient-to-b from-slate-950/80 to-transparent backdrop-blur-sm sticky top-0">
        <div className="flex items-center gap-2.5">
          <div className={`w-8 h-8 rounded-xl flex items-center justify-center bg-gradient-to-br shadow-lg ${isOfflineActive ? 'from-orange-500 to-red-600' : 'from-blue-500 to-indigo-600'}`}>
            <Sparkles size={16} className="text-white" />
          </div>
          <span className="font-bold text-lg tracking-tight">LinguaFlow</span>
        </div>
        <div className="flex items-center gap-3">
          <div className={`px-2.5 py-1 rounded-full text-[10px] font-bold border ${isOfflineActive ? 'bg-orange-500/10 border-orange-500/20 text-orange-400' : 'bg-blue-500/10 border-blue-500/20 text-blue-400'}`}>
            {isOfflineActive ? 'OFFLINE' : 'ONLINE'}
          </div>
          <button onClick={() => setShowSettings(true)} className="p-2 rounded-full bg-slate-800/50 hover:bg-slate-800 transition-colors">
            <Settings size={20} className="text-slate-400" />
          </button>
        </div>
      </header>

      {/* Direction Indicator */}
      {isConnected && !isOfflineActive && (
          <div className="absolute top-16 left-0 right-0 z-10 flex justify-center mt-2 pointer-events-none animate-fade-in-down">
              <div className="bg-slate-800/80 backdrop-blur-md px-3 py-1 rounded-full border border-slate-700 flex items-center gap-2 text-[10px] font-medium text-slate-300 shadow-xl">
                  <span>🇹🇷 Türkçe</span>
                  <ArrowRightLeft size={12} className="text-blue-400" />
                  <span>{getLangDetails(targetLang).name}</span>
              </div>
          </div>
      )}

      {/* Main Chat Area */}
      <main className="flex-1 flex flex-col z-10 relative overflow-hidden">

        {/* Messages */}
        <div ref={chatContainerRef} className="flex-1 overflow-y-auto px-4 pt-2 pb-6 space-y-6 scroll-smooth">
          {error && (
            <div className="bg-red-500/10 border border-red-500/20 text-red-200 p-3 rounded-xl text-sm flex justify-between items-center mx-2">
              <span>{error}</span>
              <button onClick={() => setError(null)}><X size={16} /></button>
            </div>
          )}

          {messages.length === 0 && !realtimeInput && (
             <div className="h-full flex flex-col items-center justify-center text-slate-500 opacity-40 space-y-4">
                <Globe size={64} strokeWidth={1} />
                <p className="text-center text-sm px-10">
                  Konuşmaya başlamak için aşağıdaki mikrofona dokunun.
                </p>
             </div>
          )}

          {messages.map((msg) => (
            <div key={msg.id} className={`flex flex-col ${msg.role === 'user' ? 'items-start' : 'items-end'}`}>
              <span className="text-[10px] text-slate-500 mb-1 px-1 flex items-center gap-1.5">
                  {msg.role === 'user' ? (
                      <>
                        <Mic size={10} />
                        <span>Konuşmacı</span>
                      </>
                  ) : (
                      <>
                        <Sparkles size={10} />
                        <span>Çevirmen</span>
                      </>
                  )}
              </span>
              <div className={`max-w-[85%] px-5 py-3.5 shadow-sm text-[15px] leading-relaxed ${
                msg.role === 'user' 
                  ? 'bg-slate-800 text-slate-200 rounded-2xl rounded-tl-sm' 
                  : isOfflineActive 
                    ? 'bg-orange-600 text-white rounded-2xl rounded-tr-sm'
                    : 'bg-blue-600 text-white rounded-2xl rounded-tr-sm'
              }`}>
                {msg.text}
              </div>
            </div>
          ))}

          {/* Real-time Bubbles */}
          {(realtimeInput || realtimeOutput) && (
             <div className="space-y-4">
                {realtimeInput && (
                  <div className="flex flex-col items-start opacity-70">
                     <span className="text-[10px] text-blue-400 mb-1 px-1 animate-pulse flex items-center gap-1"><Mic size={10}/> GİRİŞ...</span>
                     <div className="max-w-[85%] px-5 py-3 bg-slate-800/50 border border-slate-700 border-dashed text-slate-300 rounded-2xl rounded-tl-sm">
                       {realtimeInput}
                     </div>
                  </div>
                )}
                {realtimeOutput && (
                  <div className="flex flex-col items-end opacity-70">
                     <span className="text-[10px] text-indigo-400 mb-1 px-1 animate-pulse flex items-center gap-1"><Sparkles size={10}/> ÇEVİRİYOR...</span>
                     <div className="max-w-[85%] px-5 py-3 bg-blue-900/30 border border-blue-500/30 border-dashed text-blue-200 rounded-2xl rounded-tr-sm">
                       {realtimeOutput}
                     </div>
                  </div>
                )}
             </div>
          )}
        </div>

        {/* BOTTOM DOCK (Controls) */}
        <div className="bg-slate-950/80 backdrop-blur-xl border-t border-slate-800/50 px-6 pb-10 pt-4 z-30">

          {/* Visualizer Bar (Above Dock) */}
          <div className="h-10 w-full flex items-center justify-center mb-4">
            {isConnected ? (
              <div className="w-full h-full opacity-80">
                 <AudioVisualizer analyser={inputAnalyserRef.current} isActive={true} color={isOfflineActive ? '#f97316' : '#6366f1'} />
              </div>
            ) : (
              <div className="h-1 w-16 bg-slate-800 rounded-full"></div>
            )}
          </div>

          <div className="flex items-center justify-between max-w-sm mx-auto">

            {/* Left: Language Selector Button */}
            <div className="w-16 flex flex-col items-center gap-1">
               <button 
                 onClick={() => setShowLanguageSelector(true)}
                 className="w-full h-12 bg-slate-800 border border-slate-700 text-slate-200 rounded-2xl flex flex-col items-center justify-center gap-0.5 hover:border-slate-500 transition-colors active:scale-95"
               >
                  <span className="text-xl leading-none filter drop-shadow-sm">{getLangDetails(targetLang).flag}</span>
                  <span className="text-[10px] font-bold">{getLangDetails(targetLang).short}</span>
               </button>
               <span className="text-[10px] text-slate-500 font-medium">Hedef</span>
            </div>

            {/* Center: Main Mic Toggle */}
            <div className="relative -mt-6">
              {/* Ring Animation */}
              {isConnected && (
                <div className="absolute inset-0 rounded-full animate-ping opacity-30 bg-indigo-500"></div>
              )}

              <button
                onClick={handleMicToggle}
                className={`w-20 h-20 rounded-full flex items-center justify-center shadow-2xl transition-all duration-300 transform active:scale-95 ${
                  isConnecting
                    ? 'bg-slate-800 border-4 border-slate-700 cursor-wait'
                    : isConnected
                      ? isOfflineActive 
                        ? 'bg-orange-600 text-white shadow-orange-600/40 ring-4 ring-orange-900/50 scale-105' 
                        : 'bg-indigo-600 text-white shadow-indigo-600/40 ring-4 ring-indigo-900/50 scale-105'
                      : 'bg-slate-100 text-slate-900 hover:bg-white border-4 border-slate-300 shadow-white/10'
                }`}
              >
                {isConnecting ? (
                   <Loader2 size={32} className="animate-spin text-slate-400" />
                ) : isConnected ? (
                   <Square size={28} fill="currentColor" className="rounded-sm" />
                ) : (
                   <Mic size={32} strokeWidth={2.5} />
                )}
              </button>
            </div>

            {/* Right: Clear Button */}
            <div className="w-16 flex flex-col items-center gap-1">
               <button 
                 onClick={() => {
                   setMessages([]);
                   setRealtimeInput('');
                   setRealtimeOutput('');
                 }}
                 className="w-full h-12 flex items-center justify-center rounded-2xl bg-slate-800 border border-slate-700 text-slate-400 hover:text-white hover:bg-slate-700 transition-colors active:scale-95"
               >
                 <RotateCcw size={18} />
               </button>
               <span className="text-[10px] text-slate-500 font-medium">Temizle</span>
            </div>

          </div>
        </div>

      </main>

      {/* Language Selector Sheet */}
      {showLanguageSelector && (
          <div className="fixed inset-0 z-50 flex items-end justify-center bg-black/60 backdrop-blur-sm animate-fade-in" onClick={() => setShowLanguageSelector(false)}>
              <div className="bg-slate-900 border-t border-slate-700 w-full max-w-lg rounded-t-3xl shadow-2xl overflow-hidden" onClick={e => e.stopPropagation()}>
                  <div className="p-4 flex items-center justify-center relative border-b border-slate-800">
                      <div className="w-12 h-1 bg-slate-700 rounded-full absolute top-3"></div>
                      <h3 className="text-white font-semibold mt-2 flex items-center gap-2">
                        <Globe size={18} className="text-blue-400" />
                        Hedef Dil Seçin
                      </h3>
                  </div>
                  <div className="p-6 grid grid-cols-2 gap-3 pb-8">
                      {LANGUAGE_META.map((lang) => (
                          <button
                              key={lang.code}
                              onClick={() => {
                                  handleLanguageChange(lang.code);
                                  setShowLanguageSelector(false);
                              }}
                              className={`p-4 rounded-xl border flex flex-col items-center gap-2 transition-all ${
                                  targetLang === lang.code 
                                  ? 'bg-blue-600/20 border-blue-500 text-white shadow-lg shadow-blue-900/20' 
                                  : 'bg-slate-800 border-slate-700 text-slate-400 hover:bg-slate-750 hover:border-slate-600'
                              }`}
                          >
                              <span className="text-4xl filter drop-shadow-md">{lang.flag}</span>
                              <span className="font-medium text-sm">{lang.name}</span>
                          </button>
                      ))}
                  </div>
              </div>
          </div>
      )}

      {/* Settings Sheet */}
      {showSettings && (
        <div className="fixed inset-0 z-50 flex items-end justify-center bg-black/60 backdrop-blur-sm animate-fade-in" onClick={() => setShowSettings(false)}>
          <div className="bg-slate-900 border-t border-slate-700 w-full max-w-lg rounded-t-3xl shadow-2xl overflow-hidden max-h-[85vh] flex flex-col" onClick={e => e.stopPropagation()}>
             <div className="p-5 flex justify-between items-center bg-slate-800/50">
                <h2 className="text-lg font-bold flex items-center gap-2 text-white">
                  <Settings size={20} className="text-blue-400"/> Ayarlar
                </h2>
                <div className="w-12 h-1 bg-slate-700 rounded-full absolute top-3 left-1/2 -translate-x-1/2"></div>
                <button onClick={() => setShowSettings(false)} className="p-1 bg-slate-800 rounded-full text-slate-400"><X size={20} /></button>
             </div>

             <div className="p-6 overflow-y-auto space-y-6">
               {/* Mode */}
               <div className="bg-slate-800/30 p-4 rounded-2xl border border-slate-800">
                  <div className="flex justify-between items-center mb-2">
                    <span className="font-semibold text-slate-200">Çevrimdışı Mod</span>
                    <button onClick={() => { if(isConnected) stopConnection(); setForceOfflineMode(!forceOfflineMode); }} 
                      className={`w-12 h-7 rounded-full p-1 transition-colors ${forceOfflineMode ? 'bg-orange-500' : 'bg-slate-700'}`}>
                      <div className={`w-5 h-5 rounded-full bg-white transition-transform ${forceOfflineMode ? 'translate-x-5' : ''}`}></div>
                    </button>
                  </div>
                  <p className="text-xs text-slate-500">İnternet bağlantısı olmadan cihaz üzerinde basit çeviri yapın.</p>
               </div>

               {/* Packs */}
               <div>
                 <h3 className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-3 px-1">Dil Paketleri</h3>
                 <div className="space-y-3">
                    {offlinePacks.map(pack => {
                       // Find flag based on pack ID content (simple heuristic for demo)
                       let flag = '🏳️';
                       if (pack.id.includes('en')) flag = '🇬🇧';
                       if (pack.id.includes('nl')) flag = '🇳🇱';
                       if (pack.id.includes('ar')) flag = '🇸🇦';
                       if (pack.id.includes('ru')) flag = '🇷🇺';

                       return (
                       <div key={pack.id} className="bg-slate-800/50 p-3 rounded-xl border border-slate-700/50 flex items-center justify-between">
                          <div className="flex-1">
                             <div className="flex items-center gap-2">
                               <span className="text-lg">{flag}</span>
                               <span className="font-semibold text-sm">{pack.pair}</span>
                               <span className="text-[10px] bg-slate-700 text-slate-300 px-1.5 py-0.5 rounded">{pack.size}</span>
                             </div>
                             <div className="text-xs text-slate-400 mt-1">{pack.name}</div>
                             {pack.progress > 0 && pack.progress < 100 && (
                               <div className="w-full h-1 bg-slate-700 mt-2 rounded-full overflow-hidden">
                                  <div className="h-full bg-blue-500 transition-all" style={{width: `${pack.progress}%`}}></div>
                               </div>
                             )}
                          </div>

                          <div className="ml-4">
                             {pack.downloaded ? (
                               <button onClick={() => deletePack(pack.id)} className="p-2 text-green-400 bg-green-400/10 rounded-full hover:bg-red-500/20 hover:text-red-400 transition-colors">
                                  <Check size={18} />
                               </button>
                             ) : pack.progress > 0 ? (
                               <span className="text-xs font-bold text-blue-400">{pack.progress}%</span>
                             ) : (
                               <button onClick={() => downloadPack(pack.id)} className="p-2 bg-slate-700 hover:bg-blue-600 rounded-full text-white transition-colors">
                                 <Download size={18} />
                               </button>
                             )}
                          </div>
                       </div>
                    )})}
                 </div>
               </div>

               {/* Clear History */}
               <button onClick={() => { setMessages([]); setRealtimeInput(''); setRealtimeOutput(''); setShowSettings(false); }} className="w-full py-4 text-sm text-red-400 font-medium bg-red-500/10 rounded-2xl hover:bg-red-500/20 transition-colors flex items-center justify-center gap-2">
                  <Trash2 size={16} /> Geçmişi Temizle
               </button>
             </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';
import { TargetLanguage, ChatMessage, OfflinePack } from './types';
import { float32To16BitPCM, arrayBufferToBase64, base64ToArrayBuffer, pcm16ToFloat32 } from './utils/audioUtils';
import AudioVisualizer from './components/AudioVisualizer';
import { Mic, Globe, Settings, RotateCcw, Wifi, WifiOff, Download, Check, Trash2, X, Zap, Square, ChevronDown, Sparkles, Loader2, Languages, ArrowRightLeft } from 'lucide-react';

// Live API Configuration
const MODEL_NAME = 'gemini-2.5-flash-native-audio-preview-09-2025';
const INPUT_SAMPLE_RATE = 16000;
const OUTPUT_SAMPLE_RATE = 24000;

// Language Metadata with Flags
const LANGUAGE_META = [
  { code: TargetLanguage.ENGLISH, name: 'İngilizce', flag: '🇬🇧', short: 'EN' },
  { code: TargetLanguage.DUTCH, name: 'Hollandaca', flag: '🇳🇱', short: 'NL' },
  { code: TargetLanguage.ARABIC, name: 'Arapça', flag: '🇸🇦', short: 'AR' },
  { code: TargetLanguage.RUSSIAN, name: 'Rusça', flag: '🇷🇺', short: 'RU' },
];

const getLangDetails = (lang: TargetLanguage) => LANGUAGE_META.find(l => l.code === lang) || LANGUAGE_META[0];

// Mock Offline Packs
const INITIAL_PACKS: OfflinePack[] = [
  { id: 'tr-en', pair: 'TR ↔ EN', name: 'İngilizce', size: '45 MB', downloaded: false, progress: 0 },
  { id: 'tr-nl', pair: 'TR ↔ NL', name: 'Hollandaca', size: '42 MB', downloaded: false, progress: 0 },
  { id: 'tr-ar', pair: 'TR ↔ AR', name: 'Arapça', size: '50 MB', downloaded: false, progress: 0 },
  { id: 'tr-ru', pair: 'TR ↔ RU', name: 'Rusça', size: '48 MB', downloaded: false, progress: 0 },
];

const App: React.FC = () => {
  const [targetLang, setTargetLang] = useState<TargetLanguage>(TargetLanguage.ENGLISH);
  const [isConnected, setIsConnected] = useState(false);
  const [isConnecting, setIsConnecting] = useState(false);
  const [isTransmitting, setIsTransmitting] = useState(false);

  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [error, setError] = useState<string | null>(null);

  // Real-time Display States
  const [realtimeInput, setRealtimeInput] = useState('');
  const [realtimeOutput, setRealtimeOutput] = useState('');

  // Offline / Network State
  const [isOnline, setIsOnline] = useState(navigator.onLine);
  const [forceOfflineMode, setForceOfflineMode] = useState(false);
  const [showSettings, setShowSettings] = useState(false);
  const [showLanguageSelector, setShowLanguageSelector] = useState(false);
  const [offlinePacks, setOfflinePacks] = useState<OfflinePack[]>(INITIAL_PACKS);

  // Audio Context Refs
  const inputAudioContextRef = useRef<AudioContext | null>(null);
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const inputAnalyserRef = useRef<AnalyserNode | null>(null);
  const outputAnalyserRef = useRef<AnalyserNode | null>(null);
  const mediaStreamRef = useRef<MediaStream | null>(null);
  const scriptProcessorRef = useRef<ScriptProcessorNode | null>(null);

  // Logic Refs
  const aiClientRef = useRef<GoogleGenAI | null>(null);
  const sessionPromiseRef = useRef<Promise<any> | null>(null);
  const activeSessionRef = useRef<any>(null); // To store actual session object for cleanup
  const shouldReconnectRef = useRef(false); // Flag for auto-reconnect logic
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const isTransmittingRef = useRef(false);

  // Transcription Buffers
  const currentInputTranscription = useRef('');
  const currentOutputTranscription = useRef('');
  const recognitionRef = useRef<any>(null);

  // 1. Initialize & Network
  useEffect(() => {
    if (process.env.API_KEY) {
      aiClientRef.current = new GoogleGenAI({ apiKey: process.env.API_KEY });
    } else {
      setError("API Anahtarı bulunamadı.");
    }

    const handleOnline = () => setIsOnline(true);
    const handleOffline = () => {
      setIsOnline(false);
      stopConnection();
    };

    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);

    const savedPacks = localStorage.getItem('offlinePacks');
    if (savedPacks) {
      setOfflinePacks(JSON.parse(savedPacks));
    }

    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
    };
  }, []);

  const isOfflineActive = !isOnline || forceOfflineMode;

  // 2. Audio Processing
  const processAudioInput = useCallback((inputData: Float32Array) => {
    if (!sessionPromiseRef.current || !isTransmittingRef.current) return;

    const pcmData = float32To16BitPCM(inputData);
    const base64Data = arrayBufferToBase64(pcmData);

    sessionPromiseRef.current.then((session) => {
      session.sendRealtimeInput({
        media: {
          mimeType: `audio/pcm;rate=${INPUT_SAMPLE_RATE}`,
          data: base64Data,
        },
      });
    });
  }, []);

  // 3. Stop Connection (Robust Cleanup)
  const stopConnection = useCallback(() => {
    setIsConnecting(false);
    setIsConnected(false);
    setIsTransmitting(false);
    isTransmittingRef.current = false;

    setRealtimeInput(''); setRealtimeOutput('');

    // Clear Media Stream
    if (mediaStreamRef.current) {
        mediaStreamRef.current.getTracks().forEach(track => track.stop());
        mediaStreamRef.current = null;
    }

    // Clear Script Processor
    if (scriptProcessorRef.current) {
        scriptProcessorRef.current.disconnect();
        scriptProcessorRef.current = null;
    }

    // Close Audio Contexts
    if (inputAudioContextRef.current) {
        inputAudioContextRef.current.close();
        inputAudioContextRef.current = null;
    }
    if (outputAudioContextRef.current) {
        outputAudioContextRef.current.close();
        outputAudioContextRef.current = null;
    }

    // Close Active Session Explicitly
    if (activeSessionRef.current) {
        activeSessionRef.current.close();
        activeSessionRef.current = null;
    }
    sessionPromiseRef.current = null;

    if (recognitionRef.current) {
        recognitionRef.current.stop();
        // recognitionRef.current = null;
    }
  }, []);

  // 4. Toggle Handler
  const handleMicToggle = async () => {
    if (isConnecting) return;

    if (isConnected) {
      stopConnection();
      return;
    }

    setIsConnecting(true);
    setError(null);

    // --- Offline Mode ---
    if (isOfflineActive) {
      setTimeout(() => {
        setIsConnected(true);
        setIsTransmitting(true);
        isTransmittingRef.current = true;
        setIsConnecting(false);
        startOfflineRecognition();
      }, 300);
      return;
    }

    // --- Online Mode ---
    if (!aiClientRef.current) {
       setError("API Anahtarı eksik.");
       setIsConnecting(false);
       return;
    }

    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: {
        sampleRate: INPUT_SAMPLE_RATE,
        channelCount: 1,
        echoCancellation: true,
        noiseSuppression: true,
        autoGainControl: true
      }});
      mediaStreamRef.current = stream;

      const audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ 
        sampleRate: INPUT_SAMPLE_RATE 
      });
      inputAudioContextRef.current = audioCtx;

      const source = audioCtx.createMediaStreamSource(stream);
      const analyser = audioCtx.createAnalyser();
      analyser.fftSize = 256;
      inputAnalyserRef.current = analyser;

      const scriptProcessor = audioCtx.createScriptProcessor(4096, 1, 1);
      scriptProcessorRef.current = scriptProcessor;

      scriptProcessor.onaudioprocess = (e) => {
        const inputData = e.inputBuffer.getChannelData(0);
        processAudioInput(inputData);
      };

      source.connect(analyser);
      analyser.connect(scriptProcessor);
      scriptProcessor.connect(audioCtx.destination);

      const outCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ 
        sampleRate: OUTPUT_SAMPLE_RATE 
      });
      outputAudioContextRef.current = outCtx;
      const outAnalyser = outCtx.createAnalyser();
      outAnalyser.fftSize = 256;
      outputAnalyserRef.current = outAnalyser;
      outAnalyser.connect(outCtx.destination);

      const currentTargetName = getLangDetails(targetLang).name;

      // UPDATED BIDIRECTIONAL SYSTEM PROMPT
      const systemPrompt = `You are an expert bidirectional simultaneous interpreter.
Your task is to facilitate a real-time conversation between a Turkish speaker and a ${currentTargetName} speaker.

STRICT INSTRUCTIONS:
1. Bidirectional Translation:
   - If you hear Turkish, translate it immediately and accurately into ${currentTargetName}.
   - If you hear ${currentTargetName}, translate it immediately and accurately into Turkish.

2. Tone & Context:
   - Maintain the original tone, emotion, and intent of the speaker.
   - Ensure the translation flows naturally for a native speaker of the target language.

3. Professional Conduct:
   - Do NOT engage in conversation.
   - Do NOT answer questions yourself.
   - Do NOT explain your translations.
   - Simply output the translated audio.

4. Silence:
   - If there is no speech, stay silent.

Output strictly audio of the translation.`;

      const connectPromise = aiClientRef.current.live.connect({
        model: MODEL_NAME,
        config: {
          systemInstruction: systemPrompt,
          responseModalities: [Modality.AUDIO],
          inputAudioTranscription: {},
          outputAudioTranscription: {},
        },
        callbacks: {
          onopen: () => {
            console.log("Connected");
            setIsConnecting(false);
            setIsConnected(true);
            setIsTransmitting(true);
            isTransmittingRef.current = true;
            nextStartTimeRef.current = 0;
            setRealtimeInput('');
            setRealtimeOutput('');
          },
          onmessage: (msg: LiveServerMessage) => handleServerMessage(msg),
          onclose: () => {
            console.log("Closed");
            stopConnection();
          },
          onerror: (e) => {
            console.error(e);
            setError("Bağlantı hatası.");
            stopConnection();
          }
        }
      });

      sessionPromiseRef.current = connectPromise;
      connectPromise.then(session => {
          activeSessionRef.current = session;
      });

    } catch (e: any) {
      console.error(e);
      setError(`Hata: ${e.message}`);
      stopConnection();
    }
  };

  const handleServerMessage = (msg: LiveServerMessage) => {
    if (msg.serverContent?.inputTranscription) {
       currentInputTranscription.current += msg.serverContent.inputTranscription.text;
       setRealtimeInput(currentInputTranscription.current);
    }
    if (msg.serverContent?.outputTranscription) {
       currentOutputTranscription.current += msg.serverContent.outputTranscription.text;
       setRealtimeOutput(currentOutputTranscription.current);
    }
    if (msg.serverContent?.turnComplete) {
       const inputTx = currentInputTranscription.current.trim();
       const outputTx = currentOutputTranscription.current.trim();
       if (inputTx || outputTx) {
         addMessage('user', inputTx || '...');
         addMessage('model', outputTx || '...');
       }
       currentInputTranscription.current = '';
       currentOutputTranscription.current = '';
       setRealtimeInput('');
       setRealtimeOutput('');
    }
    const audioData = msg.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
    if (audioData) {
       playAudioResponse(audioData);
    }
  };

  // 5. Language Change Logic
  const handleLanguageChange = (newLang: TargetLanguage) => {
      // Only restart connection if we are ONLINE (to update system prompt).
      // Offline mode uses dynamic TTS so no restart needed.
      if (isConnected && !isOfflineActive) {
          shouldReconnectRef.current = true;
          stopConnection();
      }
      setTargetLang(newLang);
  };

  // Auto-reconnect effect
  useEffect(() => {
      if (shouldReconnectRef.current) {
          shouldReconnectRef.current = false;
          handleMicToggle();
      }
  }, [targetLang]);

  // 6. Offline Logic
  const startOfflineRecognition = () => {
    if (!('webkitSpeechRecognition' in window)) return;
    try {
      const Recognition = (window as any).webkitSpeechRecognition;
      const recognition = new Recognition();
      recognition.lang = 'tr-TR'; 
      recognition.continuous = true; 
      recognition.interimResults = true; 

      recognition.onstart = () => setRealtimeInput('');
      recognition.onresult = (event: any) => {
        let interim = '';
        let final = '';
        for (let i = event.resultIndex; i < event.results.length; ++i) {
          if (event.results[i].isFinal) final += event.results[i][0].transcript;
          else interim += event.results[i][0].transcript;
        }
        setRealtimeInput(final || interim);
      };
      recognition.onerror = (e: any) => console.log(e);
      recognitionRef.current = recognition;
      recognition.start();
    } catch (e) {}
  };

  const stopOfflineRecognition = () => {
    if (recognitionRef.current) {
      recognitionRef.current.stop();
      setTimeout(() => {
        const text = realtimeInput.trim();
        if (text) {
           addMessage('user', text);
           setRealtimeInput('');
           setTimeout(() => {
             const mock = `(${targetLang}) ${text}`;
             addMessage('model', mock);
             speakOffline(text, targetLang);
           }, 500);
        }
      }, 500);
    }
  };

  const speakOffline = (text: string, lang: TargetLanguage) => {
    if ('speechSynthesis' in window) {
      const utterance = new SpeechSynthesisUtterance(text); 
      const langMap: Record<TargetLanguage, string> = {
        [TargetLanguage.ENGLISH]: 'en-US', [TargetLanguage.DUTCH]: 'nl-NL',
        [TargetLanguage.ARABIC]: 'ar-SA', [TargetLanguage.RUSSIAN]: 'ru-RU'
      };
      utterance.lang = langMap[lang];
      window.speechSynthesis.speak(utterance);
    }
  };

  // 7. Play Audio
  const playAudioResponse = async (base64Audio: string) => {
    if (!outputAudioContextRef.current || !outputAnalyserRef.current) return;
    const ctx = outputAudioContextRef.current;
    try {
      const arrayBuffer = base64ToArrayBuffer(base64Audio);
      const float32Data = pcm16ToFloat32(arrayBuffer);
      const audioBuffer = ctx.createBuffer(1, float32Data.length, OUTPUT_SAMPLE_RATE);
      audioBuffer.getChannelData(0).set(float32Data);
      const source = ctx.createBufferSource();
      source.buffer = audioBuffer;
      source.connect(outputAnalyserRef.current);
      source.start(Math.max(nextStartTimeRef.current, ctx.currentTime));
      nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime) + audioBuffer.duration;
      source.onended = () => sourcesRef.current.delete(source);
      sourcesRef.current.add(source);
    } catch (err) {}
  };

  const addMessage = (role: 'user' | 'model', text: string) => {
    setMessages(prev => [...prev, { id: Date.now().toString() + Math.random(), role, text, timestamp: new Date(), isFinal: true }]);
  };

  const chatContainerRef = useRef<HTMLDivElement>(null);
  useEffect(() => {
    if (chatContainerRef.current) chatContainerRef.current.scrollTop = chatContainerRef.current.scrollHeight;
  }, [messages, realtimeInput, realtimeOutput]);

  const downloadPack = (id: string) => {
    setOfflinePacks(prev => prev.map(p => p.id === id ? { ...p, progress: 5 } : p));
    let progress = 5;
    const interval = setInterval(() => {
      progress += 10;
      if (progress >= 100) {
        clearInterval(interval);
        setOfflinePacks(prev => {
          const newPacks = prev.map(p => p.id === id ? { ...p, progress: 100, downloaded: true } : p);
          localStorage.setItem('offlinePacks', JSON.stringify(newPacks));
          return newPacks;
        });
      } else {
        setOfflinePacks(prev => prev.map(p => p.id === id ? { ...p, progress } : p));
      }
    }, 200);
  };

  const deletePack = (id: string) => {
     setOfflinePacks(prev => {
       const newPacks = prev.map(p => p.id === id ? { ...p, progress: 0, downloaded: false } : p);
       localStorage.setItem('offlinePacks', JSON.stringify(newPacks));
       return newPacks;
     });
  };

