                  {msg.role === 'user' ? (
                      <> <Mic size={10} /> <span>Konuşmacı</span> </>
                  ) : (
                      <> 
                        {/* Use Ear icon if it was a listen mode message (implied by context usually, simplified here) */}
                        <Sparkles size={10} /> <span>Çevirmen</span> 
