                       <button 
                         onClick={() => handleVoiceChange('male')}
                         className={`py-3 px-4 rounded-xl flex items-center justify-center gap-2 transition-all ${voiceType === 'male' ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/30' : 'bg-slate-800 text-slate-400 border border-slate-700'}`}
                       >
                           <span className="text-lg">👨</span>
                           <span className="font-medium text-sm">Erkek</span>
                       </button>
                   </div>
                   <p className="text-xs text-slate-500 mt-2">Çevirmen sesi (Sadece Online modda geçerlidir).</p>
               </div>

               {/* Packs */}
               <div>
                 <h3 className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-3 px-1">Dil Paketleri</h3>
                 <div className="space-y-3">
                    {offlinePacks.map(pack => {
                       let flag = '🏳️';
                       if (pack.id.includes('en')) flag = '🇬🇧';
                       if (pack.id.includes('nl')) flag = '🇳🇱';
                       if (pack.id.includes('ar')) flag = '🇸🇦';
                       if (pack.id.includes('ru')) flag = '🇷🇺';
                       if (pack.id.includes('de')) flag = '🇩🇪';
                       if (pack.id.includes('it')) flag = '🇮🇹';
                       if (pack.id.includes('fr')) flag = '🇫🇷';
                       if (pack.id.includes('ua')) flag = '🇺🇦';

                       return (
                       <div key={pack.id} className="bg-slate-800/50 p-3 rounded-xl border border-slate-700/50 flex items-center justify-between">
                          <div className="flex-1">
                             <div className="flex items-center gap-2">
                               <span className="text-lg">{flag}</span>
                               <span className="font-semibold text-sm">{pack.pair}</span>
                               <span className="text-[10px] bg-slate-700 text-slate-300 px-1.5 py-0.5 rounded">{pack.size}</span>
                             </div>
                             <div className="text-xs text-slate-400 mt-1">{pack.name}</div>
                             {pack.progress > 0 && pack.progress < 100 && (
                               <div className="w-full h-1 bg-slate-700 mt-2 rounded-full overflow-hidden">
                                  <div className="h-full bg-blue-500 transition-all" style={{width: `${pack.progress}%`}}></div>
                               </div>
                             )}
                          </div>

                          <div className="ml-4">
                             {pack.downloaded ? (
                               <button onClick={() => deletePack(pack.id)} className="p-2 text-green-400 bg-green-400/10 rounded-full hover:bg-red-500/20 hover:text-red-400 transition-colors">
                                  <Check size={18} />
                               </button>
                             ) : pack.progress > 0 ? (
                               <span className="text-xs font-bold text-blue-400">{pack.progress}%</span>
                             ) : (
                               <button onClick={() => downloadPack(pack.id)} className="p-2 bg-slate-700 hover:bg-blue-600 rounded-full text-white transition-colors">
                                 <Download size={18} />
                               </button>
                             )}
                          </div>
                       </div>
                    )})}
                 </div>
               </div>

               {/* Clear History */}
               <button onClick={() => { setMessages([]); setRealtimeInput(''); setRealtimeOutput(''); setShowSettings(false); }} className="w-full py-4 text-sm text-red-400 font-medium bg-red-500/10 rounded-2xl hover:bg-red-500/20 transition-colors flex items-center justify-center gap-2 active:scale-95 touch-manipulation">
                  <Trash2 size={16} /> Geçmişi Temizle
               </button>
             </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

export enum TargetLanguage {
  TURKISH = 'Turkish',
  ENGLISH = 'English',
  DUTCH = 'Dutch',
  ARABIC = 'Arabic',
  RUSSIAN = 'Russian',
  GERMAN = 'German',
  ITALIAN = 'Italian',
  FRENCH = 'French',
  UKRAINIAN = 'Ukrainian'
}

export interface ChatMessage {
  id: string;
  role: 'user' | 'model';
  text: string;
  timestamp: Date;
  isFinal: boolean;
  langCode?: TargetLanguage;
}

export interface Contact {
  id: string;
  name: string;
  language: TargetLanguage;
  avatarColor: string;
  lastCall?: string;
}

export interface AudioConfig {
  inputSampleRate: number;
  outputSampleRate: number;
}

export interface OfflinePack {
  id: string;
  pair: string;
  name: string;
  size: string;
  downloaded: boolean;
  progress: number;
}

export interface ArchivedSession {
  id: string;
  date: string;
  targetLang: TargetLanguage;
  preview: string;
  messages: ChatMessage[];
}

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';
import { TargetLanguage, ChatMessage, OfflinePack, ArchivedSession, Contact } from './types';
import { float32To16BitPCM, arrayBufferToBase64, base64ToArrayBuffer, pcm16ToFloat32 } from './utils/audioUtils';
import AudioVisualizer from './components/AudioVisualizer';
import { Mic, Globe, Settings, RotateCcw, Wifi, WifiOff, Download, Check, Trash2, X, Zap, Square, ChevronDown, Sparkles, Loader2, Languages, ArrowRightLeft, ArrowRight, User, SplitSquareVertical, Maximize2, Minimize2, MessageSquare, Ear, ScrollText, Save, FolderOpen, Calendar, ChevronRight, FileText, Waves, Key, LogOut, ExternalLink, Phone, PhoneCall, PhoneOff, UserPlus, Search } from 'lucide-react';

const MODEL_NAME = 'gemini-2.5-flash-native-audio-preview-09-2025';
const INPUT_SAMPLE_RATE = 16000;
const OUTPUT_SAMPLE_RATE = 24000;

const LANGUAGE_META = [
  { code: TargetLanguage.TURKISH, name: 'Türkçe', flag: '🇹🇷', short: 'TR', locale: 'tr-TR' },
  { code: TargetLanguage.ENGLISH, name: 'İngilizce', flag: '🇬🇧', short: 'EN', locale: 'en-US' },
  { code: TargetLanguage.DUTCH, name: 'Hollandaca', flag: '🇳🇱', short: 'NL', locale: 'nl-NL' },
  { code: TargetLanguage.ARABIC, name: 'Arapça', flag: '🇸🇦', short: 'AR', locale: 'ar-SA' },
  { code: TargetLanguage.RUSSIAN, name: 'Rusça', flag: '🇷🇺', short: 'RU', locale: 'ru-RU' },
  { code: TargetLanguage.GERMAN, name: 'Almanca', flag: '🇩🇪', short: 'DE', locale: 'de-DE' },
  { code: TargetLanguage.ITALIAN, name: 'İtalyanca', flag: '🇮🇹', short: 'IT', locale: 'it-IT' },
  { code: TargetLanguage.FRENCH, name: 'Fransızca', flag: '🇫🇷', short: 'FR', locale: 'fr-FR' },
  { code: TargetLanguage.UKRAINIAN, name: 'Ukraynaca', flag: '🇺🇦', short: 'UA', locale: 'uk-UA' },
];

const INITIAL_CONTACTS: Contact[] = [
  { id: '1', name: 'John Doe', language: TargetLanguage.ENGLISH, avatarColor: 'bg-blue-500' },
  { id: '2', name: 'Hans Müller', language: TargetLanguage.GERMAN, avatarColor: 'bg-orange-500' },
  { id: '3', name: 'Svetlana', language: TargetLanguage.RUSSIAN, avatarColor: 'bg-red-500' },
  { id: '4', name: 'Ahmed', language: TargetLanguage.ARABIC, avatarColor: 'bg-emerald-500' },
];

const getLangDetails = (lang?: TargetLanguage) => {
    if (!lang) return LANGUAGE_META[0];
    return LANGUAGE_META.find(l => l.code === lang) || LANGUAGE_META[0];
};

const detectLanguage = (text: string, langA: TargetLanguage, langB: TargetLanguage): TargetLanguage => {
  if (!text || text.length < 2) return langA; 
  const t = text.toLowerCase().trim();
  if (/[\u0600-\u06FF]/.test(text)) return TargetLanguage.ARABIC;
  if (/[\u0400-\u04FF]/.test(text)) return TargetLanguage.RUSSIAN;
  if (/[ğıİşŞ]/.test(text)) return TargetLanguage.TURKISH;
  return langA;
};

const App: React.FC = () => {
  const [sourceLang, setSourceLang] = useState<TargetLanguage>(TargetLanguage.TURKISH);
  const [targetLang, setTargetLang] = useState<TargetLanguage>(TargetLanguage.ENGLISH);
  const [apiKey, setApiKey] = useState<string>('');
  const [tempApiKeyInput, setTempApiKeyInput] = useState('');
  const [viewMode, setViewMode] = useState<'chat' | 'split' | 'listen' | 'archive' | 'contacts'>('chat');
  const [activeCall, setActiveCall] = useState<Contact | null>(null);
  const [contacts, setContacts] = useState<Contact[]>(INITIAL_CONTACTS);

  const [isConnected, setIsConnected] = useState(false);
  const [isConnecting, setIsConnecting] = useState(false);
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [error, setError] = useState<string | null>(null);
  const [realtimeInput, setRealtimeInput] = useState('');
  const [realtimeOutput, setRealtimeOutput] = useState('');
  const [isNoiseMode, setIsNoiseMode] = useState(false);
  const [isHoldingMic, setIsHoldingMic] = useState(false);
  const [showSettings, setShowSettings] = useState(false);

  const inputAudioContextRef = useRef<AudioContext | null>(null);
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const inputAnalyserRef = useRef<AnalyserNode | null>(null);
  const outputAnalyserRef = useRef<AnalyserNode | null>(null);
  const mediaStreamRef = useRef<MediaStream | null>(null);
  const scriptProcessorRef = useRef<ScriptProcessorNode | null>(null);
  const aiClientRef = useRef<GoogleGenAI | null>(null);
  const sessionPromiseRef = useRef<Promise<any> | null>(null);
  const activeSessionRef = useRef<any>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const isTransmittingRef = useRef(false);
  const currentInputTranscription = useRef('');
  const currentOutputTranscription = useRef('');

  useEffect(() => {
    const storedKey = localStorage.getItem('gemini_api_key');
    if (storedKey) {
        setApiKey(storedKey);
        aiClientRef.current = new GoogleGenAI({ apiKey: storedKey });
    }
    const savedNoiseMode = localStorage.getItem('isNoiseMode');
    if (savedNoiseMode) setIsNoiseMode(JSON.parse(savedNoiseMode));
  }, []);

  const triggerHaptic = () => { if (navigator.vibrate) navigator.vibrate(50); };

  const stopConnection = useCallback(() => {
    setIsConnecting(false); setIsConnected(false); isTransmittingRef.current = false;
    setRealtimeInput(''); setRealtimeOutput(''); setActiveCall(null);
    if (mediaStreamRef.current) mediaStreamRef.current.getTracks().forEach(t => t.stop());
    if (scriptProcessorRef.current) scriptProcessorRef.current.disconnect();
    if (inputAudioContextRef.current) inputAudioContextRef.current.close();
    if (outputAudioContextRef.current) outputAudioContextRef.current.close();
    if (activeSessionRef.current) activeSessionRef.current.close();
    sessionPromiseRef.current = null;
  }, []);

  const startCall = async (contact: Contact) => {
      triggerHaptic();
      setActiveCall(contact);
      setTargetLang(contact.language);
      // Wait a bit for state to settle then start session
      setTimeout(() => startLiveSession('bidirectional', contact.language), 100);
  };

  const startLiveSession = async (mode: 'bidirectional' | 'listen', forcedTarget?: TargetLanguage) => {
      if (isConnecting || isConnected) return;
      setIsConnecting(true); setError(null);
      const target = forcedTarget || targetLang;

      try {
        const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
        mediaStreamRef.current = stream;
        const audioCtx = new AudioContext({ sampleRate: INPUT_SAMPLE_RATE });
        inputAudioContextRef.current = audioCtx;
        const source = audioCtx.createMediaStreamSource(stream);
        const analyser = audioCtx.createAnalyser();
        inputAnalyserRef.current = analyser;
        const scriptProcessor = audioCtx.createScriptProcessor(4096, 1, 1);
        scriptProcessorRef.current = scriptProcessor;
        scriptProcessor.onaudioprocess = (e) => {
            if (!isTransmittingRef.current) return;
            const pcmData = float32To16BitPCM(e.inputBuffer.getChannelData(0));
            sessionPromiseRef.current?.then(s => s.sendRealtimeInput({ media: { mimeType: 'audio/pcm;rate=16000', data: arrayBufferToBase64(pcmData) } }));
        };
        source.connect(analyser); analyser.connect(scriptProcessor); scriptProcessor.connect(audioCtx.destination);

        const outCtx = new AudioContext({ sampleRate: OUTPUT_SAMPLE_RATE });
        outputAudioContextRef.current = outCtx;
        const outAnalyser = outCtx.createAnalyser();
        outputAnalyserRef.current = outAnalyser;
        outAnalyser.connect(outCtx.destination);

        const sessionPromise = aiClientRef.current!.live.connect({
          model: MODEL_NAME,
          config: {
            systemInstruction: `You are a real-time call interpreter between Turkish and ${forcedTarget || targetLang}.`,
            responseModalities: [Modality.AUDIO],
            inputAudioTranscription: {}, outputAudioTranscription: {},
            speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } } }
          },
          callbacks: {
            onopen: () => { setIsConnecting(false); setIsConnected(true); isTransmittingRef.current = true; },
            onmessage: (msg: LiveServerMessage) => handleServerMessage(msg),
            onclose: stopConnection,
            onerror: () => { setError("Bağlantı Hatası"); stopConnection(); }
          }
        });
        sessionPromiseRef.current = sessionPromise;
        sessionPromise.then(s => activeSessionRef.current = s);
      } catch (e: any) { setError(e.message); stopConnection(); }
  };

  const handleServerMessage = (msg: LiveServerMessage) => {
    if (msg.serverContent?.inputTranscription) {
        currentInputTranscription.current += msg.serverContent.inputTranscription.text;
        setRealtimeInput(currentInputTranscription.current);
    }
    if (msg.serverContent?.outputTranscription) {
        currentOutputTranscription.current += msg.serverContent.outputTranscription.text;
        setRealtimeOutput(currentOutputTranscription.current);
    }
    const audio = msg.serverContent?.modelTurn?.parts?.find(p => p.inlineData)?.inlineData?.data;
    if (audio) playAudio(audio);
    if (msg.serverContent?.turnComplete) {
        const input = currentInputTranscription.current.trim();
        const output = currentOutputTranscription.current.trim();
        if (input || output) {
            setMessages(prev => [...prev, { id: Date.now().toString(), role: 'user', text: input, timestamp: new Date(), isFinal: true }, { id: Date.now().toString()+'m', role: 'model', text: output, timestamp: new Date(), isFinal: true }]);
        }
        currentInputTranscription.current = ''; currentOutputTranscription.current = '';
        setRealtimeInput(''); setRealtimeOutput('');
    }
  };

  const playAudio = async (base64: string) => {
    const ctx = outputAudioContextRef.current;
    if (!ctx) return;
    const arrayBuffer = base64ToArrayBuffer(base64);
    const float32Data = pcm16ToFloat32(arrayBuffer);
    const buffer = ctx.createBuffer(1, float32Data.length, OUTPUT_SAMPLE_RATE);
    buffer.getChannelData(0).set(float32Data);
    const source = ctx.createBufferSource();
    source.buffer = buffer;
    source.connect(outputAnalyserRef.current!);
    source.start(Math.max(nextStartTimeRef.current, ctx.currentTime));
    nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime) + buffer.duration;
  };

  return (
    <div className={`h-[100dvh] w-full flex flex-col font-sans relative overflow-hidden bg-slate-950 text-slate-100`}>

      {/* HEADER */}
      <header className="z-20 h-16 flex items-center justify-between px-5 backdrop-blur-md bg-black/40">
        <div className="flex items-center gap-3">
          <div className="w-8 h-8 rounded-lg bg-blue-600 flex items-center justify-center">
            <Languages size={18} className="text-white" />
          </div>
          <span className="font-bold text-lg">Hizmet Dili</span>
        </div>
        <div className="flex gap-2">
            <button onClick={() => setViewMode('contacts')} className={`p-2 rounded-full ${viewMode === 'contacts' ? 'bg-blue-600' : 'bg-slate-800'}`}>
                <User size={20} />
            </button>
            <button onClick={() => setViewMode('chat')} className={`p-2 rounded-full ${viewMode === 'chat' ? 'bg-blue-600' : 'bg-slate-800'}`}>
                <MessageSquare size={20} />
            </button>
            <button onClick={() => setShowSettings(true)} className="p-2 rounded-full bg-slate-800">
                <Settings size={20} />
            </button>
        </div>
      </header>

      {/* VIEW MODES */}
      <main className="flex-1 overflow-hidden relative">

        {/* CALL SCREEN (OVERLAY) */}
        {activeCall && (
            <div className="fixed inset-0 z-[60] bg-slate-950 animate-fade-in flex flex-col items-center justify-between py-20 px-6">
                <div className="text-center">
                    <div className={`w-32 h-32 ${activeCall.avatarColor} rounded-full mx-auto mb-6 flex items-center justify-center text-4xl font-bold shadow-2xl ring-4 ring-blue-500/20`}>
                        {activeCall.name.charAt(0)}
                    </div>
                    <h2 className="text-3xl font-bold text-white mb-2">{activeCall.name}</h2>
                    <p className="text-blue-400 font-medium flex items-center justify-center gap-2">
                        <Globe size={16} /> {getLangDetails(activeCall.language).name} ile görüşülüyor
                    </p>
                </div>

                {/* Transcription View during Call */}
                <div className="w-full max-w-md bg-white/5 backdrop-blur-xl rounded-3xl p-6 border border-white/10 space-y-6">
                    <div className="min-h-[60px]">
                        <span className="text-[10px] uppercase tracking-widest text-slate-500 font-bold block mb-2">Karşı Taraf Söylüyor (Türkçe)</span>
                        <p className="text-xl text-emerald-400 font-medium">{realtimeOutput || "Dinleniyor..."}</p>
                    </div>
                    <div className="h-px bg-white/5"></div>
                    <div className="min-h-[60px]">
                        <span className="text-[10px] uppercase tracking-widest text-slate-500 font-bold block mb-2">Siz Söylüyorsunuz</span>
                        <p className="text-xl text-white/80">{realtimeInput || "Konuşun..."}</p>
                    </div>
                </div>

                <div className="flex flex-col items-center gap-10">
                    <div className="w-full h-12">
                        <AudioVisualizer analyser={inputAnalyserRef.current} isActive={isConnected} color="#3b82f6" />
                    </div>
                    <button 
                        onClick={stopConnection}
                        className="w-20 h-20 bg-red-600 rounded-full flex items-center justify-center shadow-2xl shadow-red-900/40 active:scale-90 transition-transform"
                    >
                        <PhoneOff size={32} className="text-white" />
                    </button>
                </div>
            </div>
        )}

        {/* CONTACTS VIEW */}
        {viewMode === 'contacts' && (
            <div className="h-full overflow-y-auto p-6 space-y-6">
                <div className="flex items-center justify-between mb-4">
                    <h2 className="text-2xl font-bold">Kişiler</h2>
                    <button className="p-2 bg-blue-600/20 text-blue-400 rounded-xl"><UserPlus size={20}/></button>
                </div>
                <div className="relative mb-6">
                    <Search className="absolute left-4 top-3.5 text-slate-500" size={18}/>
                    <input className="w-full bg-slate-900 border border-slate-800 rounded-2xl py-3.5 pl-12 pr-4 text-sm" placeholder="Kişi ara..."/>
                </div>
                <div className="space-y-4">
                    {contacts.map(c => (
                        <div key={c.id} className="bg-slate-900/50 p-4 rounded-2xl border border-slate-800 flex items-center justify-between group hover:bg-slate-900 transition-colors">
                            <div className="flex items-center gap-4">
                                <div className={`w-12 h-12 ${c.avatarColor} rounded-full flex items-center justify-center font-bold text-white`}>
                                    {c.name.charAt(0)}
                                </div>
                                <div>
                                    <h3 className="font-bold">{c.name}</h3>
                                    <div className="flex items-center gap-2 text-xs text-slate-500">
                                        <span>{getLangDetails(c.language).flag}</span>
                                        <span>{getLangDetails(c.language).name}</span>
                                    </div>
                                </div>
                            </div>
                            <button 
                                onClick={() => startCall(c)}
                                className="w-10 h-10 bg-emerald-600/20 text-emerald-400 rounded-full flex items-center justify-center hover:bg-emerald-600 hover:text-white transition-all"
                            >
                                <Phone size={18} />
                            </button>
                        </div>
                    ))}
                </div>
            </div>
        )}

        {/* CHAT VIEW */}
        {viewMode === 'chat' && (
            <div className="h-full flex flex-col p-4">
                <div className="flex-1 overflow-y-auto space-y-4 no-scrollbar">
                    {messages.length === 0 && (
                        <div className="h-full flex flex-col items-center justify-center opacity-20">
                            <MessageSquare size={64} />
                            <p className="mt-4">Henüz mesaj yok</p>
                        </div>
                    )}
                    {messages.map((m, i) => (
                        <div key={i} className={`flex ${m.role === 'user' ? 'justify-start' : 'justify-end'}`}>
                            <div className={`max-w-[80%] p-3 rounded-2xl ${m.role === 'user' ? 'bg-slate-800' : 'bg-blue-600'}`}>
                                {m.text}
                            </div>
                        </div>
                    ))}
                </div>
                <div className="h-24 flex items-center justify-center">
                    <button 
                        onClick={() => isConnected ? stopConnection() : startLiveSession('bidirectional')}
                        className={`w-16 h-16 rounded-full flex items-center justify-center shadow-xl transition-all ${isConnected ? 'bg-red-600 animate-pulse' : 'bg-blue-600'}`}
                    >
                        {isConnected ? <Square size={24} fill="white"/> : <Mic size={28}/>}
                    </button>
                </div>
            </div>
        )}
      </main>

