const App: React.FC = () => {
  const [sourceLang, setSourceLang] = useState<TargetLanguage>(TargetLanguage.TURKISH);
  const [targetLang, setTargetLang] = useState<TargetLanguage>(TargetLanguage.ENGLISH);
  const [apiKey, setApiKey] = useState<string>('');
  const [tempApiKeyInput, setTempApiKeyInput] = useState('');
  const [viewMode, setViewMode] = useState<'chat' | 'split' | 'listen' | 'archive'>('chat');

  const [isConnected, setIsConnected] = useState(false);
  const [isConnecting, setIsConnecting] = useState(false);
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [error, setError] = useState<string | null>(null);
  const [realtimeInput, setRealtimeInput] = useState('');
  const [realtimeOutput, setRealtimeOutput] = useState('');
  const [isNoiseMode, setIsNoiseMode] = useState(false);
  const [showSettings, setShowSettings] = useState(false);
  const [isListenModeActive, setIsListenModeActive] = useState(false);
  const [showSaveModal, setShowSaveModal] = useState(false);
  const [savedSessions, setSavedSessions] = useState<ArchivedSession[]>([]);
  const [openedArchive, setOpenedArchive] = useState<ArchivedSession | null>(null);
  const [offlinePacks, setOfflinePacks] = useState<OfflinePack[]>(INITIAL_PACKS);

  const inputAudioContextRef = useRef<AudioContext | null>(null);
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const inputAnalyserRef = useRef<AnalyserNode | null>(null);
  const outputAnalyserRef = useRef<AnalyserNode | null>(null);
  const mediaStreamRef = useRef<MediaStream | null>(null);
  const scriptProcessorRef = useRef<ScriptProcessorNode | null>(null);
  const aiClientRef = useRef<GoogleGenAI | null>(null);
  const sessionPromiseRef = useRef<Promise<any> | null>(null);
  const activeSessionRef = useRef<any>(null);
  const nextStartTimeRef = useRef<number>(0);
  const currentInputTranscription = useRef('');
  const currentOutputTranscription = useRef('');

  useEffect(() => {
    const storedKey = localStorage.getItem('gemini_api_key');
    if (storedKey) {
      setApiKey(storedKey);
      aiClientRef.current = new GoogleGenAI({ apiKey: storedKey });
    } else {
      const envKey = (typeof process !== 'undefined' && process.env) ? process.env.API_KEY : undefined;
      if (envKey) {
        setApiKey(envKey);
        aiClientRef.current = new GoogleGenAI({ apiKey: envKey });
      }
    }
    const savedSessions = localStorage.getItem('archivedSessions');
    if (savedSessions) setSavedSessions(JSON.parse(savedSessions));
  }, []);

  const triggerHaptic = () => { if (navigator.vibrate) navigator.vibrate(50); };

  const stopConnection = useCallback(() => {
    setIsConnecting(false); setIsConnected(false); setIsListenModeActive(false);
    setRealtimeInput(''); setRealtimeOutput('');
    if (mediaStreamRef.current) mediaStreamRef.current.getTracks().forEach(t => t.stop());
    if (scriptProcessorRef.current) scriptProcessorRef.current.disconnect();
    if (inputAudioContextRef.current) inputAudioContextRef.current.close();
    if (outputAudioContextRef.current) outputAudioContextRef.current.close();
    if (activeSessionRef.current) activeSessionRef.current.close();
    sessionPromiseRef.current = null;
  }, []);

  const startLiveSession = async (mode: 'bidirectional' | 'listen') => {
    if (isConnecting || isConnected) {
      if (isConnected) stopConnection();
      return;
    }
    setIsConnecting(true); setError(null);
    const isListen = mode === 'listen';
    if (isListen) { setViewMode('listen'); setIsListenModeActive(true); }

    try {
      if (!aiClientRef.current) throw new Error("API Anahtarı bulunamadı.");
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      mediaStreamRef.current = stream;
      const audioCtx = new AudioContext({ sampleRate: INPUT_SAMPLE_RATE });
      inputAudioContextRef.current = audioCtx;
      const source = audioCtx.createMediaStreamSource(stream);
      const analyser = audioCtx.createAnalyser();
      inputAnalyserRef.current = analyser;
      const scriptProcessor = audioCtx.createScriptProcessor(4096, 1, 1);
      scriptProcessorRef.current = scriptProcessor;
      scriptProcessor.onaudioprocess = (e) => {
        const pcmData = float32To16BitPCM(e.inputBuffer.getChannelData(0));
        sessionPromiseRef.current?.then(s => s.sendRealtimeInput({ media: { mimeType: 'audio/pcm;rate=16000', data: arrayBufferToBase64(pcmData) } }));
      };
      source.connect(analyser); analyser.connect(scriptProcessor); scriptProcessor.connect(audioCtx.destination);

      const outCtx = new AudioContext({ sampleRate: OUTPUT_SAMPLE_RATE });
      outputAudioContextRef.current = outCtx;
      const outAnalyser = outCtx.createAnalyser();
      outputAnalyserRef.current = outAnalyser;
      outAnalyser.connect(outCtx.destination);

      const sessionPromise = aiClientRef.current.live.connect({
        model: MODEL_NAME,
        config: {
          systemInstruction: isListen ? `Simultane tercüman ol. ${getLangDetails(targetLang).name} dilini dinle ve hemen Türkçe'ye çevir.` : `Profesyonel bir tercüman ol. Türkçe ile ${getLangDetails(targetLang).name} arasında çeviri yap.`,
          responseModalities: [Modality.AUDIO],
          inputAudioTranscription: {}, outputAudioTranscription: {},
          speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } } }
        },
        callbacks: {
          onopen: () => { setIsConnecting(false); setIsConnected(true); },
          onmessage: (msg: LiveServerMessage) => handleServerMessage(msg, isListen),
          onclose: stopConnection,
          onerror: (e) => { console.error(e); setError("Bağlantı Hatası"); stopConnection(); }
        }
      });
      sessionPromiseRef.current = sessionPromise;
      sessionPromise.then(s => activeSessionRef.current = s);
    } catch (e: any) { setError(e.message); stopConnection(); }
  };

  const handleServerMessage = (msg: LiveServerMessage, isListen: boolean) => {
    if (msg.serverContent?.inputTranscription) {
      currentInputTranscription.current += msg.serverContent.inputTranscription.text;
      setRealtimeInput(currentInputTranscription.current);
    }
    if (msg.serverContent?.outputTranscription) {
      currentOutputTranscription.current += msg.serverContent.outputTranscription.text;
      setRealtimeOutput(currentOutputTranscription.current);
    }
    const audio = msg.serverContent?.modelTurn?.parts?.find(p => p.inlineData)?.inlineData?.data;
    if (audio) playAudio(audio);
    if (msg.serverContent?.turnComplete) {
      const input = currentInputTranscription.current.trim();
      const output = currentOutputTranscription.current.trim();
      if (input || output) {
        setMessages(prev => [...prev, { id: Date.now().toString(), role: 'user', text: input || '...', timestamp: new Date(), isFinal: true }, { id: Date.now().toString() + 'm', role: 'model', text: output || '...', timestamp: new Date(), isFinal: true }]);
      }
      currentInputTranscription.current = ''; currentOutputTranscription.current = '';
      setRealtimeInput(''); setRealtimeOutput('');
    }
  };

  const playAudio = async (base64: string) => {
    const ctx = outputAudioContextRef.current;
    if (!ctx) return;
    const arrayBuffer = base64ToArrayBuffer(base64);
    const float32Data = pcm16ToFloat32(arrayBuffer);
    const buffer = ctx.createBuffer(1, float32Data.length, OUTPUT_SAMPLE_RATE);
    buffer.getChannelData(0).set(float32Data);
    const source = ctx.createBufferSource();
    source.buffer = buffer;
    source.connect(outputAnalyserRef.current!);
    source.start(Math.max(nextStartTimeRef.current, ctx.currentTime));
    nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime) + buffer.duration;
  };

  const deleteArchivedSession = (id: string) => {
    const updated = savedSessions.filter(s => s.id !== id);
    setSavedSessions(updated);
    localStorage.setItem('archivedSessions', JSON.stringify(updated));
    if (openedArchive?.id === id) setOpenedArchive(null);
  };

  const sourceDetails = getLangDetails(sourceLang);
  const targetDetails = getLangDetails(targetLang);

  return (
    <div className={`h-[100dvh] w-full flex flex-col font-sans relative overflow-hidden bg-slate-950 text-slate-100 ${isListenModeActive ? 'bg-orange-950 text-orange-50' : ''}`}>

      {/* HEADER */}
      <header className="z-20 h-16 flex items-center justify-between px-5 backdrop-blur-md bg-black/40 pt-[env(safe-area-inset-top)]">
        <div className="flex items-center gap-3">
          <div className={`w-8 h-8 rounded-lg flex items-center justify-center ${isListenModeActive ? 'bg-orange-500' : 'bg-emerald-600'}`}>
            {isListenModeActive ? <Ear size={18} /> : <Sparkles size={18} />}
          </div>
          <div className="flex flex-col">
            <span className="font-bold text-lg leading-none">Hizmet Dili</span>
            <span className="text-[10px] text-slate-400 mt-1">Ali Tellioğlu</span>
          </div>
        </div>
        <div className="flex items-center gap-2">
          {!isListenModeActive && viewMode !== 'archive' && (
            <button onClick={() => setViewMode(viewMode === 'chat' ? 'split' : 'chat')} className={`p-2 rounded-full ${viewMode === 'split' ? 'bg-blue-600' : 'bg-slate-800'}`}>
              {viewMode === 'chat' ? <SplitSquareVertical size={18} /> : <MessageSquare size={18} />}
            </button>
          )}
          <button onClick={() => setShowSettings(true)} className="p-2 rounded-full bg-slate-800">
            <Settings size={20} />
          </button>
        </div>
      </header>

      {/* MAIN CONTENT */}
      <main className="flex-1 overflow-hidden relative flex flex-col">
        {viewMode === 'archive' ? (
          <div className="flex-1 overflow-y-auto p-4 space-y-4">
            {openedArchive ? (
              <div className="space-y-4">
                <button onClick={() => setOpenedArchive(null)} className="text-blue-400 text-sm flex items-center gap-1"><ChevronRight className="rotate-180" size={16}/> Geri</button>
                <div className="bg-slate-900 p-4 rounded-xl border border-slate-800 flex justify-between">
                   <div>
                     <h3 className="font-bold">{new Date(openedArchive.date).toLocaleString()}</h3>
                     <p className="text-xs text-slate-500">{getLangDetails(openedArchive.targetLang).name}</p>
                   </div>
                   <button onClick={() => deleteArchivedSession(openedArchive.id)} className="text-red-400"><Trash2 size={18}/></button>
                </div>
                {openedArchive.messages.map((m, i) => (
                  <div key={i} className={`p-3 rounded-xl ${m.role === 'user' ? 'bg-slate-800' : 'bg-blue-600'}`}>
                    <p className="text-sm">{m.text}</p>
                  </div>
                ))}
              </div>
            ) : (
              savedSessions.map(s => (
                <div key={s.id} onClick={() => setOpenedArchive(s)} className="bg-slate-900 p-4 rounded-xl border border-slate-800 cursor-pointer hover:bg-slate-800">
                  <h4 className="font-bold text-sm">{new Date(s.date).toLocaleDateString()}</h4>
                  <p className="text-xs text-slate-500 line-clamp-1">{s.preview}</p>
                </div>
              ))
            )}
          </div>
        ) : viewMode === 'listen' ? (
          <div className="flex-1 overflow-y-auto px-6 py-10 space-y-8 no-scrollbar">
             {realtimeInput && <p className="text-2xl text-orange-200/40 italic">{realtimeInput}...</p>}
             {messages.filter(m => m.role === 'model').map(m => (
               <p key={m.id} className="text-3xl font-bold leading-tight animate-fade-in">{m.text}</p>
             ))}
             {realtimeOutput && <p className="text-3xl font-bold text-orange-200">{realtimeOutput}</p>}
          </div>
        ) : viewMode === 'split' ? (
          <div className="flex-1 flex flex-col pb-24">
            <div className="flex-1 bg-slate-900 flex items-center justify-center p-8 rotate-180">
               <p className="text-3xl font-bold text-center text-emerald-400">{realtimeOutput || messages.filter(m => m.role === 'model').pop()?.text || '...'}</p>
            </div>
            <div className="flex-1 bg-slate-950 flex items-center justify-center p-8">
               <p className="text-3xl font-bold text-center">{realtimeInput || messages.filter(m => m.role === 'user').pop()?.text || '...'}</p>
            </div>
          </div>
        ) : (
          <div className="flex-1 overflow-y-auto px-4 py-6 space-y-6 no-scrollbar pb-24">
            {messages.map(m => (
              <div key={m.id} className={`flex flex-col ${m.role === 'user' ? 'items-start' : 'items-end'}`}>
                <div className={`max-w-[85%] p-3 rounded-2xl ${m.role === 'user' ? 'bg-slate-800' : 'bg-emerald-600'}`}>
                  <p className="text-sm">{m.text}</p>
                </div>
              </div>
            ))}
            {realtimeInput && <div className="p-3 bg-slate-800/40 rounded-xl text-sm border border-slate-700 border-dashed">{realtimeInput}</div>}
            {realtimeOutput && <div className="p-3 bg-emerald-900/40 rounded-xl text-sm border border-emerald-500/40 border-dashed self-end">{realtimeOutput}</div>}
          </div>
        )}

        {/* CONTROLS */}
        <div className={`absolute bottom-0 w-full p-6 backdrop-blur-xl border-t border-white/5 pb-[calc(1.5rem+env(safe-area-inset-bottom,20px))] ${isListenModeActive ? 'bg-orange-950/80' : 'bg-slate-950/80'}`}>
          <div className="max-w-md mx-auto flex items-center justify-between">
            <button className="w-14 h-14 bg-slate-800 rounded-2xl flex items-center justify-center text-2xl">{sourceDetails.flag}</button>
            <div className="flex gap-4 items-end -mt-8">
              <button onClick={() => startLiveSession('listen')} className={`w-14 h-14 rounded-full flex items-center justify-center shadow-lg transition-all ${isListenModeActive ? 'bg-orange-500 scale-110' : 'bg-slate-800 text-slate-400'}`}>
                 {isConnecting && isListenModeActive ? <Loader2 className="animate-spin" /> : <Ear size={24} />}
              </button>
              <button onClick={() => startLiveSession('bidirectional')} className={`w-16 h-16 rounded-full flex items-center justify-center shadow-2xl transition-all ${isConnected && !isListenModeActive ? 'bg-red-600 scale-110' : 'bg-emerald-600'}`}>
                 {isConnecting && !isListenModeActive ? <Loader2 className="animate-spin" /> : isConnected && !isListenModeActive ? <Square size={24} fill="white" /> : <Mic size={28} />}
              </button>
            </div>
            <button className="w-14 h-14 bg-slate-800 rounded-2xl flex items-center justify-center text-2xl">{targetDetails.flag}</button>
          </div>
        </div>
      </main>

      {/* API KEY MODAL */}
      {!apiKey && (
        <div className="fixed inset-0 z-[100] bg-slate-950 flex items-center justify-center p-8 animate-fade-in">
           <div className="w-full max-w-sm">
              <Key size={48} className="text-blue-500 mx-auto mb-6" />
              <h1 className="text-2xl font-bold text-center mb-8">API Anahtarı Gerekli</h1>
              <input type="password" value={tempApiKeyInput} onChange={e => setTempApiKeyInput(e.target.value)} placeholder="API Key..." className="w-full bg-slate-900 border border-slate-700 rounded-xl p-4 mb-4" />
              <button onClick={() => { localStorage.setItem('gemini_api_key', tempApiKeyInput); window.location.reload(); }} className="w-full bg-blue-600 py-4 rounded-xl font-bold">Kaydet ve Başlat</button>
              <a href="https://aistudio.google.com/app/apikey" target="_blank" className="block text-center text-xs text-slate-500 mt-4 flex items-center justify-center gap-1">Anahtar Al <ExternalLink size={12}/></a>
           </div>
        </div>
      )}

      {/* SETTINGS SHEET */}
      {showSettings && (
        <div className="fixed inset-0 z-50 bg-black/60 flex items-end justify-center animate-fade-in" onClick={() => setShowSettings(false)}>
           <div className="bg-slate-900 w-full max-w-lg rounded-t-3xl p-6 space-y-6" onClick={e => e.stopPropagation()}>
              <h2 className="text-xl font-bold">Ayarlar</h2>
              <button onClick={() => { setViewMode('archive'); setShowSettings(false); }} className="w-full p-4 bg-slate-800 rounded-xl flex items-center gap-3"><FolderOpen size={20} className="text-blue-400"/> Arşiv</button>
              <button onClick={() => { localStorage.removeItem('gemini_api_key'); window.location.reload(); }} className="w-full p-4 bg-red-500/10 text-red-400 rounded-xl font-bold">API Anahtarını Sil</button>
           </div>
        </div>
      )}
    </div>
  );
};

